--

/*!40000 ALTER TABLE `character_event` DISABLE KEYS */;
INSERT INTO `character_event` VALUES (1,1,'566','1','生于长安，出身关陇贵族李氏，为西魏八柱国之一李虎之孙','《旧唐书·高祖本纪》：高祖神尧大圣大光孝皇帝姓李氏，讳渊。其先陇西狄道人，凉武昭王暠七代孙也。……以周天和元年，生于长安。','北周天和元年',0,'2026-04-01 13:14:18.270383','2026-04-01 13:15:59.000000'),(2,1,'572','7','父亲李昞去世，袭封唐国公，成年后性格豁达宽仁，深得人心','《旧唐书·高祖本纪》：七岁袭唐国公。及长，倜傥豁达，任性真率，宽仁容众，无贵贱咸得其欢心。','北周建德元年',1,'2026-04-01 13:14:18.274022','2026-04-01 13:15:59.000000'),(3,1,'581','16','隋代周后，补任千牛备身，因是隋文帝独孤皇后外甥，格外受器重','《旧唐书·高祖本纪》：文帝受禅，补千牛备身。文帝独孤皇后，即高祖从母也，由是特见亲爱。','隋开皇元年',2,'2026-04-01 13:14:18.275305','2026-04-01 13:14:18.275305'),(4,1,'隋开皇年间','壮年','历任谯州、陇州、岐州三州刺史，有方士称其骨法异常，将来必为天子','《新唐书·高祖本纪》：历谯、陇、岐三州刺史。有史世良者，善相人，谓高祖曰：‘公骨法非常，必为人主，愿自爱，勿忘鄙言。’高祖颇以自负。','隋开皇年间',3,'2026-04-01 13:14:18.279727','2026-04-01 13:14:18.279727'),(5,1,'613','48','辽东之役时受命督运怀远镇粮草，杨玄感叛乱后调任弘化郡留守，节制关右十三郡兵马','《旧唐书·高祖本纪》：大业九年，迁卫尉少卿。辽东之役，督运于怀远镇。及杨玄感反，诏高祖驰驿镇弘化郡，兼知关右诸军事。','隋大业九年',4,'2026-04-01 13:14:18.280872','2026-04-01 13:14:18.280872'),(6,1,'615','50','任山西河东抚慰大使，平定母端儿、敬盘陀等农民起义，在山西地区势力逐步壮大','《旧唐书·高祖本纪》：十一年，炀帝幸汾阳宫，命高祖往山西、河东黜陟讨捕。师次龙门，贼帅母端儿帅众数千薄于城下。高祖从十余骑击之，所射七十发，皆应弦而倒，贼乃大溃。','隋大业十一年',5,'2026-04-01 13:14:18.281610','2026-04-01 13:14:18.281610'),(7,1,'617','52','升任太原留守，同年五月于晋阳起兵，十一月攻入长安，立代王杨侑为帝，自任大丞相、进封唐王','《新唐书·高祖本纪》：十三年，为太原留守。……五月甲子，高祖举兵反。……十一月丙辰，克京城。……壬戌，遥尊隋帝为太上皇，立代王侑为皇帝，大赦，改元义宁，高祖假黄钺、大都督内外诸军事、大丞相，进封唐王。','隋大业十三年',6,'2026-04-01 13:14:18.282196','2026-04-01 13:14:18.282196'),(8,1,'618','53','隋炀帝遇弑后，接受隋恭帝杨侑禅位，建立唐朝，定都长安，立李建成为太子，李世民为秦王，李元吉为齐王','《旧唐书·高祖本纪》：武德元年五月甲子，高祖即皇帝位于太极殿，命刑部尚书萧造兼太尉，告于南郊，大赦，改隋义宁二年为唐武德元年。','唐武德元年',7,'2026-04-01 13:14:18.282731','2026-04-01 13:14:18.282731'),(9,1,'621','56','唐军先后擒获窦建德、迫降王世充，平定河北、河南地区，基本完成全国统一','《旧唐书·高祖本纪》：（武德四年）五月己未，秦王大破窦建德之众于武牢，擒建德，河北悉平。丙寅，王世充举东都降，河南平。','唐武德四年',8,'2026-04-01 13:14:18.283409','2026-04-01 13:14:18.283409'),(10,1,'626','61','玄武门之变后，立李世民为皇太子，同年八月禅位为太上皇，迁居太安宫','《旧唐书·高祖本纪》：（武德九年）六月庚申，秦王以皇太子建成与齐王元吉同谋害己，率兵诛之。诏立秦王为皇太子，总统万机，大赦天下。八月癸亥，诏传位于皇太子。尊帝为太上皇，徙居弘义宫，改名太安宫。','唐武德九年',9,'2026-04-01 13:14:18.284356','2026-04-01 13:14:18.284356'),(11,1,'635','70','病逝于太安宫，谥号太武皇帝，庙号高祖，葬于献陵','《旧唐书·高祖本纪》：贞观九年五月庚子，高祖大渐……是日，崩于太安宫之垂拱前殿，年七十。群臣上谥曰大武皇帝，庙号高祖。十月庚寅，葬于献陵。','唐贞观九年',10,'2026-04-01 13:14:18.285042','2026-04-01 13:14:18.285042'),(12,2,'598','1','生于武功别馆，为唐高祖李渊次子，母亲为太穆皇后窦氏，出生时有异相，幼时便显示出聪睿过人的特质','《旧唐书·太宗本纪》：\"太宗文武大圣大广孝皇帝讳世民，高祖第二子也。母曰太穆顺圣皇后窦氏。隋开皇十八年十二月戊午，生于武功之别馆。时有二龙戏于馆门之外，三日而去。高祖之临岐州，太宗时年四岁。有书生自言善相，谒高祖曰：‘公贵人也，且有贵子。’见太宗，曰：‘龙凤之姿，天日之表，年将二十，必能济世安民矣。’\"','隋开皇十八年',0,'2026-04-01 13:36:14.388311','2026-04-01 13:39:27.000000'),(13,2,'615','18','隋炀帝被突厥围困于雁门，李世民应募从军，隶属屯卫将军云定兴麾下，献疑兵计吓退突厥，成功解除雁门之围','《旧唐书·太宗本纪》：\"大业末，炀帝于雁门为突厥所围，太宗应募救援，隶屯卫将军云定兴营。将行，谓定兴曰：‘必赍旗鼓以设疑兵。且始毕可汗举国之师，敢围天子，必以国家仓卒无援。我张军容，令数十里幡旗相续，夜则钲鼓相应，虏必谓救兵云集，望尘而走矣。不然，彼众我寡，悉军来战，必不能支矣。’定兴从焉，师次崞县，突厥候骑驰告始毕曰：王师大至。由是解围而遁。\"','隋大业十一年',1,'2026-04-01 13:36:14.389304','2026-04-01 13:39:27.000000'),(14,2,'617','20','力劝李渊在晋阳起兵反隋，后统兵为先锋，一路势如破竹，同年攻占隋都长安，为李唐立国奠定核心基础','《新唐书·太宗本纪》：\"高祖起太原，非其本意，而事出太宗。及取天下，破宋金刚、王世充、窦建德等，太宗功益高。\"','隋大业十三年',2,'2026-04-01 13:36:14.389995','2026-04-01 13:36:14.389995'),(15,2,'618','21','李渊称帝建立唐朝，李世民受封秦王，任尚书令、右翊卫大将军，随后数年领兵平定各地割据势力','《旧唐书·太宗本纪》：\"武德元年，为尚书令、右翊卫大将军，进封秦王。\"','唐武德元年',3,'2026-04-01 13:36:14.391166','2026-04-01 13:36:14.391166'),(16,2,'621','24','先后攻灭窦建德、王世充两大割据势力，基本统一北方，因功高被特封为天策上将，允许开天策府、置官属，同年开设文学馆，招揽四方贤才','《资治通鉴·唐纪五》：\"上以秦王世民功大，前代官皆不足以称之，特置天策上将，位在王公上。冬，十月，以世民为天策上将，领司徒、陕东道大行台尚书令，增邑二万户，仍开天策府，置官属。\"《旧唐书·太宗本纪》：\"于时海内渐平，太宗乃锐意经籍，开文学馆以待四方之士。\"','唐武德四年',4,'2026-04-01 13:36:14.397047','2026-04-01 13:36:14.397047'),(17,2,'626','29','因太子李建成、齐王李元吉联合加害，率长孙无忌、尉迟敬德等人发动玄武门之变，诛杀李建成、李元吉，被立为皇太子，同年八月接受李渊禅位，正式登基为帝','《旧唐书·太宗本纪》：\"九年，皇太子建成、齐王元吉谋害太宗。六月四日，太宗率长孙无忌、尉迟敬德等等于玄武门诛之。甲子，立为皇太子，庶政皆断决。八月癸亥，高祖传位于皇太子，太宗即位于东宫显德殿。\"','唐武德九年',5,'2026-04-01 13:36:14.398347','2026-04-01 13:36:14.398347'),(18,2,'627','30','改元贞观，重用魏征、房玄龄、杜如晦等贤臣，整顿吏治，轻徭薄赋，鼓励农桑，拉开\"贞观之治\"的序幕','《旧唐书·太宗本纪》：\"及即位，励精政道，数引魏征入卧内，访以得失。征雅有经国之才，性又抗直，无所屈挠，太宗与之言，未尝不欣然纳受。\"','唐贞观元年',6,'2026-04-01 13:36:14.399271','2026-04-01 13:36:14.399271'),(19,2,'630','33','派李靖、李勣率军攻灭东突厥，俘获颉利可汗，彻底解除北方边患，周边四夷君长共同尊奉李世民为\"天可汗\"','《旧唐书·太宗本纪》：\"四年春正月乙亥，定襄道行军总管李靖大破突厥，获隋皇后萧氏及炀帝之孙正道，送至京师。三月甲午，李靖俘颉利可汗，东突厥遂亡。四夷君长诣阙请上为天可汗，群臣及四夷皆称万岁。是后以玺书赐西北君长，皆称天可汗。\"','唐贞观四年',7,'2026-04-01 13:36:14.400309','2026-04-01 13:36:14.400309'),(20,2,'641','44','同意吐蕃赞普松赞干布的和亲请求，派江夏王李道宗护送文成公主入藏，带去中原的先进技术与文化，促进唐蕃友好交流','《旧唐书·吐蕃传》：\"贞观十五年，太宗以文成公主妻之，令礼部尚书、江夏郡王道宗主婚，持节送公主于吐蕃。弄赞率其部兵次柏海，亲迎于河源。\"','唐贞观十五年',8,'2026-04-01 13:36:14.402576','2026-04-01 13:36:14.402576'),(21,2,'643','46','太子李承乾谋反事泄被废为庶人，改立晋王李治为皇太子，同年下诏命阎立本绘制长孙无忌、尉迟敬德等二十四位功臣画像悬挂于凌烟阁，表彰开国功绩','《旧唐书·太宗本纪》：\"十七年四月庚辰朔，皇太子有罪，废为庶人。汉王元昌、吏部尚书侯君集并坐与连谋，伏诛。丙戌，立晋王治为皇太子，大赦，赐酺三日。戊申，诏图画司徒、赵国公无忌等勋臣二十四人于凌烟阁。\"','唐贞观十七年',9,'2026-04-01 13:36:14.403826','2026-04-01 13:36:14.403826'),(22,2,'645','48','以高句丽权臣渊盖苏文弑主虐民、侵扰新罗为由，亲率六军征讨高句丽，连克十余座城池，后因安市城久攻不下、粮草不济、气候转冷下令班师回朝','《旧唐书·太宗本纪》：\"十九年二月庚戌，上亲统六军发洛阳。五月丁丑，车驾渡辽。甲申，上亲率铁骑与李勣会围辽东城，因烈风发火弩，斯须城上屋及楼皆尽，麾战士令登，乃拔之。九月，唐军围安市，不克，遂班师。\"','唐贞观十九年',10,'2026-04-01 13:36:14.404537','2026-04-01 13:36:14.404537'),(23,2,'649','52','因病驾崩于翠微宫含风殿，庙号太宗，谥号文皇帝，葬于昭陵，其统治时期政治清明、社会安定、国力强盛，被后世誉为\"贞观之治\"','《旧唐书·太宗本纪》：\"二十三年四月己巳，上崩于翠微宫之含风殿，年五十二。庙号太宗，葬于昭陵。\"','唐贞观二十三年',11,'2026-04-01 13:36:14.405249','2026-04-01 13:36:14.405249'),(34,20,'618','51','唐朝建立后出任纳言，位列宰相，奉诏牵头修订隋朝律令，删除严苛条目，制定53条宽简新规作为唐初法律基础','《旧唐书·刘文静传》：高祖受禅，拜纳言……寻诏与当朝通识之士，因开皇律令而损益之，尽削大业所用烦峻之法。又制五十三条格，务在宽简，取便于时。','唐武德元年',5,'2026-04-08 10:23:23.859351','2026-04-08 10:23:23.859351'),(35,20,'568','1','出生于京兆武功，祖籍彭城，祖父刘懿曾任北周石州刺史，父亲刘韶为隋朝将领战死，刘文静自幼才智出众，有谋略气度','《旧唐书·刘文静传》：刘文静，字肇仁，自云彭城人，代居京兆之武功。祖懿，周石州刺史。父韶，隋战没，赠上仪同三司。文静少倜傥，有器干，多权略。','北周天和三年',0,'2026-04-08 10:23:23.861219','2026-04-08 10:23:23.861219'),(36,20,'隋大业年间','壮年','出任晋阳令，与晋阳宫监裴寂结为好友，察觉李渊父子有四方之志，暗中主动结交','《旧唐书·刘文静传》：大业末，为晋阳令，遇裴寂为晋阳宫监，因而结友。及高祖镇太原，文静察高祖有四方之志，深自结托。','隋朝晚期',1,'2026-04-08 10:23:23.861466','2026-04-08 10:23:23.861466'),(37,20,'617','50','因与李密有姻亲关系被隋炀帝下令关押于太原狱中，李世民入狱探视，二人共同商定晋阳起兵的核心方略','《旧唐书·刘文静传》：后文静坐与李密连婚，炀帝令系于郡狱。太宗以文静可与谋议，入禁所视之。文静大喜曰：‘天下大乱，非有汤、武、高、光之才，不能定也。’太宗曰：‘卿安知无？但恐常人不能别耳。今入禁所相看，非儿女之情相忧而已。时事如此，故来与君图举大计，请善筹其事。’','隋大业十三年',2,'2026-04-08 10:23:23.861665','2026-04-08 10:23:23.861665'),(38,20,'617','50','晋阳起兵后任大将军府军司马，奉命出使突厥，说服始毕可汗出兵2000、献马千匹相助，解除起兵的后方隐患','《旧唐书·刘文静传》：高祖开大将军府，以文静为军司马。文静劝改旗帜以彰义举，又请连突厥以益兵威，高祖并从之。因遣文静使于始毕可汗……始毕大喜，即遣将康鞘利领骑二千，随文静而至，又献马千匹。高祖大悦。','隋大业十三年',3,'2026-04-08 10:23:23.861810','2026-04-08 10:23:23.861810'),(39,20,'618','51','随李世民平定薛举之子薛仁杲，因战功恢复全部官爵，拜民部尚书、陕东道行台左仆射','《旧唐书·刘文静传》：及举死，又从太宗平举子仁杲，悉复其爵位，拜民部尚书，领陕东道行台左仆射。','唐武德元年',7,'2026-04-08 10:23:23.861970','2026-04-08 10:23:23.861970'),(40,20,'618','51','以元帅府长史身份随李世民征讨薛举，因违背李世民坚守不战的部署主动出击，在高墌城大败，被削除官职爵位','《旧唐书·刘文静传》：薛举寇泾州，以文静为元帅府长史，与司马殷开山率众拒举，遇于高墌城，文静为举所乘，军遂大败，奔还京师，坐除名。','唐武德元年',6,'2026-04-08 10:23:23.862123','2026-04-08 10:23:23.862123'),(41,20,'629','62（追赠时对应虚岁）','唐太宗李世民为刘文静平反，追复其全部官爵，允许其子刘树义承袭鲁国公爵位，许配公主','《旧唐书·刘文静传》：贞观三年，追复官爵，以子树义袭封鲁国公，许尚公主。','唐贞观三年',9,'2026-04-08 10:23:23.862322','2026-04-08 10:23:23.862322'),(42,20,'619','52','因自认功劳高于裴寂但官位远在其下，多次当众与裴寂对立、口出怨言，酒后失言称要斩杀裴寂，被失宠小妾的兄长告发谋反，李渊听信裴寂谗言将其处死，临刑前慨叹“高鸟尽，良弓藏”','《旧唐书·刘文静传》：文静自以才能干用在裴寂之右，又屡有军功，而位居其下，意甚不平……拔刀击柱曰：‘必当斩裴寂耳！’……高祖素疏忌之，裴寂又言曰：‘文静才略，实冠时人，性复粗险，忿不思难，丑言悖逆，其状已彰。当今天下未定，外有勍敌，今若赦之，必贻后患。’高祖竟听其言，遂杀文静、文起……文静临刑，抚膺叹曰：‘高鸟逝，良弓藏，故不虚也。’时年五十二。','唐武德二年',8,'2026-04-08 10:23:23.862501','2026-04-08 10:23:23.862501'),(43,20,'617','50','随起义军攻克长安，李渊立代王杨侑为帝后，刘文静被授大丞相府司马，进封鲁国公','《旧唐书·刘文静传》：寻平京城，高祖辅政，转大丞相府司马，进授光禄大夫，封鲁国公。','隋义宁元年',4,'2026-04-08 10:23:23.862677','2026-04-08 10:23:23.862677'),(44,21,'541','1','生于冯翊般若寺，紫气充庭，被尼姑智仙认为来历异于常人，带到别馆亲自抚养','《隋书·高祖本纪》：皇妣吕氏，以大统七年六月癸丑夜，生高祖于冯翊般若寺，紫气充庭。有尼来自河东，谓皇妣曰：‘此儿所从来甚异，不可于俗间处之。’尼将高祖舍于别馆，躬自抚养。','西魏大统七年',0,'2026-04-08 10:34:38.322604','2026-04-08 10:34:38.322604'),(45,21,'555','15','凭借父亲杨忠的功勋，被授予散骑常侍、车骑大将军、仪同三司，封成纪县公','《隋书·高祖本纪》：十五，以太祖勋授散骑常侍、车骑大将军、仪同三司，封成纪县公。','西魏恭帝二年',2,'2026-04-08 10:34:38.324105','2026-04-08 10:34:38.324105'),(46,21,'554','14','被京兆尹薛善征召为功曹，正式进入仕途','《隋书·高祖本纪》：年十四，京兆尹薛善辟为功曹。','西魏恭帝元年',1,'2026-04-08 10:34:38.324254','2026-04-08 10:34:38.324254'),(47,21,'557','17','北周代西魏，杨坚升任骠骑大将军、开府仪同三司；周明帝即位后，任右小宫伯，进封大兴郡公','《隋书·高祖本纪》：周明帝即位，授右小宫伯，进封大兴郡公。','北周孝闵帝元年/明帝元年',3,'2026-04-08 10:34:38.324391','2026-04-08 10:34:38.324391'),(48,21,'578','38','周武帝病逝，太子宇文赟即位为周宣帝，杨丽华被立为皇后，杨坚被拜为上柱国、大司马','《隋书·高祖本纪》：宣帝即位，以后父征拜上柱国、大司马。','北周宣政元年',7,'2026-04-08 10:34:38.324591','2026-04-08 10:34:38.324591'),(49,21,'560','20','周明帝被权臣宇文护毒杀，周武帝宇文邕即位，宇文护专权忌惮杨坚名望，多次意图加害，得大臣侯伏侯寿等人保护才免遭祸患','《隋书·高祖本纪》：宇文护执政，尤忌高祖，屡将害焉，大将军侯伏、侯寿等匡护得免。','北周武成二年/保定元年',4,'2026-04-08 10:34:38.325040','2026-04-08 10:34:38.325040'),(50,21,'568','28','父亲杨忠去世，杨坚承袭随国公爵位','《隋书·高祖本纪》：天和三年，袭爵随国公。','北周天和三年',5,'2026-04-08 10:34:38.325187','2026-04-08 10:34:38.325187'),(51,21,'573','33','周武帝为皇太子宇文赟聘杨坚长女杨丽华为太子妃，杨坚地位愈发尊崇','《隋书·高祖本纪》：建德二年，武帝娉高祖长女为皇太子妃，益加礼重。','北周建德二年',6,'2026-04-08 10:34:38.325444','2026-04-08 10:34:38.325444'),(52,21,'581','41','接受周静帝禅让登基称帝，定国号为隋，改元开皇，定都长安，立杨勇为皇太子，封杨广为晋王','《隋书·高祖本纪》：开皇元年春二月甲子，上自相府常服入宫，备礼即皇帝位于临光殿。设坛于南郊，遣使柴燎告天。是日，告庙，大赦，改元。','隋开皇元年',9,'2026-04-08 10:34:38.325583','2026-04-08 10:34:38.325583'),(53,21,'589','49','命晋王杨广率大军南下灭陈，俘虏陈后主陈叔宝，统一全国，结束西晋末年以来近三百年的分裂割据局面','《隋书·高祖本纪》：九年春正月辛未，贺若弼败陈师于蒋山，获其将萧摩诃。韩擒虎进师入建邺，获陈主叔宝。陈国平，合州三十，郡一百，县四百。','隋开皇九年',10,'2026-04-08 10:34:38.325730','2026-04-08 10:34:38.325730'),(54,21,'580','40','周宣帝病逝，静帝宇文阐年幼，杨坚在刘昉、郑译协助下矫诏辅政，任左大丞相总揽朝政，平定尉迟迥、司马消难、王谦三方叛乱，清除北周宗室反对势力，进爵随王','《隋书·高祖本纪》：大象二年五月，乙未，帝崩。时静帝幼冲，未能亲理政事。内史上大夫郑译、御正大夫刘昉以高祖皇后之父，众望所归，遂矫诏引高祖入总朝政，都督内外诸军事。','北周大象二年',8,'2026-04-08 10:34:38.329574','2026-04-08 10:34:38.329574'),(55,21,'590','50','平定江南士族豪强叛乱巩固统一，推行均田制、输籍法整顿户籍，改州郡县三级制为州县二级制简化行政，修订《开皇律》完善法制，开启“开皇之治”','《隋书·食货志》：高颎又以人间课输，虽有定分，年常征纳，除注恒多，长吏肆情，文帐出没，复无定簿，难以推校，乃为输籍定样，请遍下诸州。帝从之。自是奸无所容矣。','隋开皇十年',11,'2026-04-08 10:34:38.331094','2026-04-08 10:34:38.331094'),(56,21,'600','60','废黜皇太子杨勇，改立晋王杨广为皇太子','《隋书·高祖本纪》：开皇二十年冬十月乙丑，皇太子勇及诸子并废为庶人。十一月戊子，以晋王广为皇太子。','隋开皇二十年',12,'2026-04-08 10:34:38.335178','2026-04-08 10:34:38.335178'),(57,21,'604','64','在仁寿宫病重驾崩，庙号高祖，谥号文皇帝，葬于泰陵','《隋书·高祖本纪》：仁寿四年秋七月甲辰，上以疾甚，卧于仁寿宫，与百僚辞诀，并握手歔欷。丁未，崩于大宝殿，时年六十四。','隋仁寿四年',13,'2026-04-08 10:34:38.335319','2026-04-08 10:34:38.335319'),(58,22,'569','1','生于京兆，为隋文帝杨坚与文献皇后独孤伽罗次子，史载其姿容俊美、自幼聪慧，极受父母宠爱','《隋书·炀帝纪》：炀皇帝，讳广，一名英，小字阿𡡉，高祖第二子也。母曰文献独孤皇后。上美姿仪，少敏慧，高祖及后于诸子中特所钟爱。','北周天和四年',0,'2026-04-08 12:07:50.645263','2026-04-08 12:07:50.645263'),(59,22,'613','45','第二次征伐高句丽，战事僵持之际，礼部尚书杨玄感在黎阳起兵叛乱，杨广被迫撤军平叛','《隋书·炀帝纪》：九年春四月庚午，车驾度辽，遣宇文述等趣平壤。六月乙巳，礼部尚书杨玄感反于黎阳，逼东都。庚午，上班师。八月，宇文述等破杨玄感于阌乡，斩之，余党悉平。','隋大业九年',11,'2026-04-08 12:07:50.648015','2026-04-08 12:07:50.648015'),(60,22,'612','44','征调百万大军第一次征伐高句丽，久攻辽东不下，萨水之战大败，伤亡数十万，被迫班师','《隋书·炀帝纪》：八年春正月，大军集于涿郡，总一百一十三万三千八百，号二百万。七月壬寅，宇文述等败绩于萨水，右屯卫将军辛世雄死之，九军并陷，将帅奔还亡者二千余骑，癸卯班师。','隋大业八年',10,'2026-04-08 12:07:50.647741','2026-04-08 12:07:50.647741'),(61,22,'614','46','第三次征调全国兵力征伐高句丽，此时天下大乱，征兵多失期不至，高句丽遣使请降，杨广遂班师回朝','《隋书·炀帝纪》：十年春二月，诏复征天下兵，百道俱进。秋七月，次怀远镇，高丽困弊，遣使乞降，上大悦许之，八月己巳班师。','隋大业十年',12,'2026-04-08 12:07:50.648803','2026-04-08 12:07:50.648803'),(62,22,'618','50','宇文化及联合骁果军发动江都之变，杨广被缢杀，隋朝统治正式覆灭','《隋书·炀帝纪》：义宁二年三月，右屯卫将军宇文化及等以骁果作乱，入犯宫闱，上崩于温室，时年五十。','隋义宁二年',14,'2026-04-08 12:07:50.649560','2026-04-08 12:07:50.649560'),(63,22,'600','32','太子杨勇被废，杨广被正式册立为皇太子','《隋书·炀帝纪》：二十年，皇太子勇废，立上为皇太子。','隋开皇二十年',3,'2026-04-08 12:07:50.650102','2026-04-08 12:07:50.650102'),(64,22,'581','13','隋朝建立后受封晋王，拜柱国、并州总管，负责镇守北方边境','《隋书·炀帝纪》：开皇元年，立为晋王，拜柱国、并州总管，时年十三。','隋开皇元年',1,'2026-04-08 12:07:50.649829','2026-04-08 12:07:50.649829'),(65,22,'616','48','不顾朝臣劝阻，执意巡幸江都，此时中原农民起义蜂起，瓦岗军、窦建德等割据势力已占据大部中原，杨广遂滞留江都不归','《隋书·炀帝纪》：十二年秋七月，江都新作龙舟成，宇文述劝幸江都，帝从之。奉信郎崔民象以盗贼充斥上表谏阻，帝斩之，戊辰车驾幸江都。','隋大业十二年',13,'2026-04-08 12:07:50.649132','2026-04-08 12:07:50.649132'),(66,22,'609','41','西巡河右，攻灭吐谷浑，设置西海、河源等四郡，打通丝绸之路，在张掖会见西域二十七国使节','《隋书·炀帝纪》：五年三月己巳，车驾西巡河右。五月，大破吐谷浑，伏允遁走，其部众十余万口来降。六月丙辰，上御观风行殿，盛陈文物，奏九部乐，宴高昌王等，蛮夷陪列者三十余国。','隋大业五年',8,'2026-04-08 12:07:50.650429','2026-04-08 12:07:50.650429'),(67,22,'589','21','以行军元帅身份统领大军灭陈，诛杀陈朝佞臣，封存府库秋毫无犯，进位太尉，声名大振','《隋书·炀帝纪》：八年冬，大举伐陈，以上为行军元帅。及陈平，执陈湘州刺史施文庆等邪佞之臣斩之右阙下，以谢三吴。封府库，资财无所取，天下称贤。进位太尉。','隋开皇九年',2,'2026-04-08 12:07:50.656319','2026-04-08 12:07:50.656319'),(68,22,'604','36','隋文帝驾崩，杨广即皇帝位，随后平定汉王杨谅叛乱，诛杀废太子杨勇，巩固皇权','《隋书·炀帝纪》：四年七月，高祖崩，上即皇帝位于仁寿宫。八月，并州总管汉王谅举兵反，诏尚书左仆射杨素讨平之。丙子，杀故太子勇。','隋仁寿四年',4,'2026-04-08 12:07:50.658637','2026-04-08 12:07:50.658637'),(69,22,'606','38','始建进士科，正式确立科举取士制度，打破门阀士族对选官权的垄断，为后世科举制奠定基础','《旧唐书·薛登传》：炀帝嗣兴，又变前法，置进士等科。于是后生之徒，复相放效，因陋就寡，赴速邀时，缉缀小文，名之策学。','隋大业二年',6,'2026-04-08 12:07:50.659024','2026-04-08 12:07:50.659024'),(70,22,'605','37','下诏营建东都洛阳，征发百万民夫开凿通济渠，连通黄河与淮河水系，制造数千艘龙舟准备巡幸江南','《隋书·炀帝纪》：大业元年春正月壬辰朔，大赦，改元。三月丁未，诏尚书令杨素等营建东京。发河南诸郡男女百余万，开通济渠，自西苑引谷、洛水达于河，自板渚引河通于淮。遣黄门侍郎王弘等往江南造龙舟、楼船等数万艘。','隋大业元年',5,'2026-04-08 12:07:50.659309','2026-04-08 12:07:50.659309'),(71,22,'607','39','颁布《大业律》，改州为郡，统一度量衡依古制，北巡榆林会见突厥启民可汗，稳固北部边疆','《隋书·炀帝纪》：三年夏四月庚辰，诏改州为郡，改度量权衡并依古式。甲申，颁律令，大赦天下。八月乙酉，启民可汗来朝行宫，宴赐极厚。','隋大业三年',7,'2026-04-08 12:07:50.659616','2026-04-08 12:07:50.659616'),(72,22,'610','42','下诏开凿江南河，连通京口至余杭八百余里水运通道，完成隋唐大运河全线贯通的最后一段工程','《隋书·炀帝纪》：六年冬十二月，敕穿江南河，自京口至余杭，八百余里，广十余丈，使可通龙舟，并置驿宫、草顿，欲东巡会稽。','隋大业六年',9,'2026-04-08 12:07:50.666263','2026-04-08 12:07:50.666263'),(73,24,'581','41','杨坚称帝建隋后，拜尚书左仆射、纳言，进封渤海郡公，为当朝首相；主持修订《开皇律》、规划新都大兴城，举荐苏威、杨素等贤臣','《隋书·高颎传》：及受禅，拜尚书左仆射，兼纳言，进封渤海郡公，朝臣莫与为比，上每呼为独孤而不名也。颎有文武大略，明达世务，引荐苏威、杨素、贺若弼、韩擒虎等，皆尽其用，为一代名臣。又领新都大监，领刑律修撰，制度多出于颎。','隋开皇元年',4,'2026-04-08 12:32:59.183866','2026-04-08 12:32:59.183866'),(74,24,'541','1','出身渤海高氏，父高宾为北周重臣，自幼聪慧有器局，博览文史，善辞令','《隋书·高颎传》：颎少明敏，有器局，略涉书史，尤善词令。','西魏大统七年',0,'2026-04-08 12:32:59.184339','2026-04-08 12:32:59.184339'),(75,24,'557','17','被齐王宇文宪征辟为记室，不久升任内史上士、下大夫，正式入仕北周','《隋书·高颎传》：齐公宪引为记室，时年十七，俄迁内史上士，寻拜下大夫。','北周孝闵帝元年',1,'2026-04-08 12:32:59.184504','2026-04-08 12:32:59.184504'),(76,24,'580','40','接受辅政的杨坚征召，入相府任司录，成为杨坚核心幕僚；主动请命监军平定尉迟迥叛乱，进位柱国，迁相府司马','《隋书·高颎传》：高祖得政，素知颎强明，又习兵事，多计略，意欲引之入府，遣邗国公杨惠谕意。颎承旨欣然曰：‘愿受驱驰。纵令公事不成，颎亦不辞灭族。’于是为相府司录。及尉迟迥之反也，颎请行，为监军，破迥平之，进位柱国，改封义宁县公，迁相府司马，任寄益隆。','北周大象二年',3,'2026-04-08 12:32:59.184916','2026-04-08 12:32:59.184916'),(77,24,'577','37','随周武帝宇文邕平定北齐，因军功授开府仪同三司，进封襄阳县公，食邑千户','《隋书·高颎传》：从武帝平齐，以功拜开府，赐物千段，爵襄阳县公，邑千户。','北周建德六年',2,'2026-04-08 12:32:59.185168','2026-04-08 12:32:59.185168'),(78,24,'589','49','任伐陈大军元帅长史，实际统筹灭陈军务，平定陈朝；拒绝晋王杨广索要陈后主宠妃张丽华的请求将其处斩，由此得罪杨广；战后因功加上柱国，进爵齐国公','《隋书·高颎传》：九年，晋王广大举伐陈，以颎为元帅长史，三军谘禀，皆取断于颎。及陈平，晋王欲纳陈主宠姬张丽华。颎曰：‘武王灭殷，戮妲己。今平陈国，不宜取丽华。’乃命斩之，王甚不悦。师还，以功加授上柱国，进爵齐国公，赐物九千段，定食千乘县千五百户。','隋开皇九年',5,'2026-04-08 12:32:59.185405','2026-04-08 12:32:59.185405'),(79,24,'599','59','反对隋文帝废黜太子杨勇，得罪独孤皇后与杨广，遭构陷弹劾，先免官，不久除名为民','《隋书·高颎传》：时太子勇失爱于上，潜有废立之意，谓颎曰：‘晋王妃有神凭之，言王必有天下，若之何？’颎长跪曰：‘长幼有序，其可废乎！’上默然而止。独孤皇后知颎不可夺，阴欲去之，后因事构陷，颎竟坐免官，未几除名为民。','隋开皇十九年',6,'2026-04-08 12:32:59.185585','2026-04-08 12:32:59.185585'),(80,24,'604','64','隋炀帝杨广即位后，重新起用高颎为太常卿','《隋书·高颎传》：炀帝即位，拜为太常卿。','隋仁寿四年',7,'2026-04-08 12:32:59.186164','2026-04-08 12:32:59.186164'),(81,24,'607','67','因私下议论隋炀帝奢靡无度、大兴劳役，以及对启民可汗礼遇过厚恐留后患，被人告发，以诽谤朝政罪被诛杀，诸子悉数流放边疆','《隋书·高颎传》：帝时甚奢靡，声色滋甚，又起长城之役。颎甚病之，谓太常丞李懿曰：‘周天元以好乐而亡，殷鉴不远，安可复尔！’时帝遇启民可汗恩礼过厚，颎谓太府卿何稠曰：‘此虏颇知中国虚实，山川险易，恐为后患。’有人奏之，帝以为谤讪朝政，于是下诏诛之，诸子徙边。','隋大业三年',8,'2026-04-08 12:32:59.186399','2026-04-08 12:32:59.186399'),(82,25,'572','29','周武帝宇文邕诛杀权臣宇文护亲政，杨素因父亲杨敷守节被俘死于北齐、未获朝廷追赠，接连上表申诉，触怒武帝被判斩首，临刑抗辩获武帝赏识，得免死罪，被授车骑大将军、仪同三司，父亲也获追赠','《隋书·杨素传》：武帝亲总万机，素以其父守节陷齐，未蒙朝命，上表申理，帝不许。至于再三，帝大怒，命左右斩之。素乃大言曰：‘臣事无道天子，死其分也。’帝壮其言，由是赠敷为大将军，谥曰忠壮。拜素为车骑大将军、仪同三司，渐见礼遇。','北周建德元年',1,'2026-04-08 12:56:25.348354','2026-04-08 12:56:25.348354'),(83,25,'577','34','随军攻灭北齐，升任开府，改封成安县公，食邑一千五百户；后又随王轨在吕梁大破陈将吴明彻，击退陈将樊毅，平定淮南地区','《隋书·杨素传》：及齐平，加上开府，改封成安县公，邑千五百户，赐以粟帛、奴婢、杂畜。从王轨破陈将吴明彻于吕梁，治东楚州事。陈将樊毅筑城于泗口，素击走之，夷毅所筑。','北周建德六年',3,'2026-04-08 12:56:25.348654','2026-04-08 12:56:25.348654'),(84,25,'544','1','生于弘农华阴杨氏望族，祖父杨暄为北魏辅国将军，父亲杨敷为北周汾州刺史，自幼胸怀大志，精研诗书、兵法，善属文工书法，被家族长辈认定为逸群之才','《隋书·杨素传》：杨素，字处道，弘农华阴人也。祖暄，魏辅国将军、谏议大夫。父敷，周汾州刺史，没于齐。素少落拓，有大志，不拘小节，世人多未之知，唯从叔祖魏尚书仆射宽深异之，每谓子孙曰：‘处道当逸群绝伦，非常之器，非汝曹所逮也。’','西魏大统十年',0,'2026-04-08 12:56:25.348872','2026-04-08 12:56:25.348872'),(85,25,'575','32','随周武帝攻伐北齐，主动请求率父亲旧部为先锋，在河阴之战中立功，受封清河县子，食邑五百户','《隋书·杨素传》：及平齐之役，素请率父麾下先驱。帝从之，赐以竹策，曰：‘朕方欲大相驱策，故用此物赐卿。’从齐王宪与齐人战于河阴，以功封清河县子，邑五百户。','北周建德四年',2,'2026-04-08 12:56:25.349276','2026-04-08 12:56:25.349276'),(86,25,'580','37','北周宣帝驾崩，杨坚辅政，杨素主动结交杨坚，被任为大将军，率军平定相州总管尉迟迥叛乱，升任徐州总管，进位柱国，封清河郡公','《隋书·杨素传》：及高祖为丞相，素深自结纳，高祖甚器之，以素为汴州刺史。行至洛阳，会尉迥作乱，荥州刺史宇文胄据武牢以应迥，素不得进。高祖拜素大将军，发河内兵击胄，破之。迁徐州总管，进位柱国，封清河郡公，邑二千户。','北周大象二年',4,'2026-04-08 12:56:25.349439','2026-04-08 12:56:25.349439'),(87,25,'581','38','杨坚代周建隋，杨素获封上柱国，任御史大夫，参与修订隋朝律法《开皇律》','《隋书·杨素传》：开皇元年，加上柱国。','隋开皇元年',5,'2026-04-08 12:56:25.349767','2026-04-08 12:56:25.349767'),(88,25,'588','45','隋文帝下诏伐陈，杨素被任为行军元帅，率水师从永安顺江东下，造五牙巨舰攻破陈军长江沿线防线，威震江南','《隋书·杨素传》：及大举伐陈，以素为行军元帅，引舟师趣三硖。军至流头滩，陈将戚欣以青龙百余艘、屯兵数千人守狼尾滩，以遏军路。素亲率黄龙数千艘，衔枚而下，遣开府王长袭引步卒从南岸击欣别栅，令大将军刘仁恩率甲骑趣白沙北岸，迟明而至，击之，欣败走。','隋开皇八年',6,'2026-04-08 12:56:25.349944','2026-04-08 12:56:25.349944'),(89,25,'589','46','隋灭陈一统天下，杨素因功改封越国公，食邑万户，不久后被征召入朝任纳言，后转任内史令','《隋书·杨素传》：及陈灭，以素功进爵郢国公，邑三千户，真食长寿县千户。素言于上曰：‘里名胜母，曾子不入，逆人王谊，前封于郢，臣不愿与之同。’于是改封越国公。寻拜纳言。岁余，转内史令。','隋开皇九年',7,'2026-04-08 12:56:25.350079','2026-04-08 12:56:25.350079'),(90,25,'590','47','江南士族豪强发动大规模叛乱，杨素任行军总管率军南下平叛，历时一年平定江南各地叛乱，巩固隋朝对江南的统治，战后升任尚书右仆射，与高颎共同执掌朝政','《隋书·杨素传》：俄而江南人李棱等聚众为乱，大者数万，小者数千，共相影响，杀害长吏。以素为行军总管，帅众讨之。素用兵多权略，驭众严整，所向克捷，江南大定。岁余，转尚书右仆射，与高颎专掌朝政。','隋开皇十年',8,'2026-04-08 12:56:25.350208','2026-04-08 12:56:25.350208'),(91,25,'598','55','突厥达头可汗犯塞，杨素任灵州道行军总管出塞征讨，一改此前中原军队以战车、步骑混编的守势战术，以骑兵阵正面迎击突厥，大破达头可汗所部，突厥受重创远遁漠北','《隋书·杨素传》：素谓人曰：‘此乃自固之道，非取胜之方也。’于是悉除旧法，令诸军为骑阵。达头闻之大喜，率十余万骑而至。素奋击，大破之，达头被重创而遁，杀伤不可胜计，群虏号哭而去。','隋开皇十八年',9,'2026-04-08 12:56:25.350311','2026-04-08 12:56:25.350311'),(92,25,'600','57','杨素与晋王杨广结交，参与谋划夺储事宜，诬陷太子杨勇、蜀王杨秀，帮助杨广成功被立为太子','《隋书·杨素传》：二十年，晋王广为灵朔道行军元帅，素为长史。王卑躬以交素。及为太子，素之谋也。','隋开皇二十年',10,'2026-04-08 12:56:25.356188','2026-04-08 12:56:25.356188'),(93,25,'605','62','杨素被拜为尚书令，不久后升任太子太师、司徒，改封楚国公，位极人臣','《隋书·杨素传》：大业元年，迁尚书令，赐东京甲第一区，物二千段。寻拜太子太师，余官如故。前后赏赐，不可胜计。','隋大业元年',12,'2026-04-08 12:56:25.357837','2026-04-08 12:56:25.357837'),(94,25,'604','61','隋文帝病重，杨素与杨广密谋封锁宫禁消息，隋文帝驾崩后，协助杨广继位，又率军平定汉王杨谅叛乱，稳定杨广统治','《隋书·杨素传》：及上不豫，素与兵部尚书柳述、黄门侍郎元岩等入閤侍疾。时皇太子入居大宝殿，虑上有不讳，须豫防拟，乃手自为书，封出问素。素录出事状以报太子。及上崩，汉王谅反，以素为并州道行军总管、河北安抚大使，率众数万讨谅，大破之，谅降，余党悉平。','隋仁寿四年',11,'2026-04-08 12:56:25.358105','2026-04-08 12:56:25.358105'),(95,25,'606','63','杨素因功高震主被隋炀帝猜忌，患病后自知名位已极，不肯服药医治，不久后病逝，追赠光禄大夫、太尉公，谥号景武','《隋书·杨素传》：素虽有建立之策，及平杨谅功，然特为帝所猜忌，外示殊礼，内情甚薄。素寝疾之日，帝每令名医诊候，赐以上药。然密问医人，恒恐不死。素又自知名位已极，不肯服药，亦不将慎，每语弟约曰：‘我岂须更活耶？’其年卒，时年六十三。赠光禄大夫、太尉公，谥曰景武。','隋大业二年',13,'2026-04-08 12:56:25.362773','2026-04-08 12:56:25.362773'),(96,26,'约577年','1','生于北周将门世家，为隋左翊卫大将军宇文述长子','《隋书·宇文化及传》：宇文化及，左翊卫大将军述之子也。','北周建德六年',0,'2026-04-08 13:08:12.707374','2026-04-08 13:08:12.707374'),(97,26,'618','42','随隋炀帝驻留江都期间，被意图西归的骁果军叛军推举为主，发动江都宫变，缢杀隋炀帝，诛杀隋朝宗室、外戚及忠于炀帝的大臣数十人，立秦王杨浩为傀儡皇帝，自称大丞相，掌控朝政','《隋书·宇文化及传》：义宁二年三月一日，德戡欲宣言告众，恐以人心未一，更思谲诈以协骁果……遂共推化及为主。化及本驽怯，初闻大惧，色动流汗，久之乃定。于是入宫内，尽杀宗室外戚，奉秦王浩为帝，化及自称大丞相，总百揆。','隋大业十四年、唐武德元年',4,'2026-04-08 13:08:12.710558','2026-04-08 13:08:12.710558'),(98,26,'619','43','先后被唐军、窦建德率领的夏军攻击，逃奔聊城后被窦建德生擒，被押至河间以弑君谋逆的罪名斩首，两个儿子宇文承基、宇文承趾一同被处死','《隋书·宇文化及传》：化及大惧，奔于聊城，将投于王薄。薄知其珍宝多，诈往附之，实欲图也。窦建德攻之甚急，薄开门纳建德，遂入聊城，生擒化及……乃以轞车载化及之河间，数以杀君之罪，并二子承基、承趾皆斩之。','唐武德二年',6,'2026-04-08 13:08:12.711054','2026-04-08 13:08:12.711054'),(99,26,'618','42','率军西归关中途中，在黎阳被李密率领的瓦岗军击败，部众大量逃散，退至魏县后，毒杀傀儡皇帝杨浩，僭位称帝，国号为许，建元天寿','《隋书·宇文化及传》：化及势蹙，叹曰：“人生固当死，岂不一日为帝乎！”于是鸩杀浩，僭皇帝位于魏县，国号许，建元为天寿，署置百官。','唐武德元年',5,'2026-04-08 13:08:12.711410','2026-04-08 13:08:12.711410'),(100,26,'607','31','随隋炀帝北巡榆林期间，与弟弟宇文智及违禁与突厥互市牟利，被炀帝查获后囚禁数月，险些被斩，最终因弟媳南阳公主求情免死，被赐给父亲宇文述为家奴','《隋书·宇文化及传》：大业初，拜太仆少卿，益恃旧恩，贪冒尤甚。炀帝幸榆林，化及与弟智及违禁与突厥交市。帝大怒，囚之数月，还至青门外，欲斩之而后入城，解衣辫发讫，以主故，久之乃释，并智及并赐述为奴。','隋大业三年',2,'2026-04-08 13:08:12.710803','2026-04-08 13:08:12.710803'),(101,26,'616','40','父亲宇文述去世后，隋炀帝追念宇文述辅佐之功，重新启用宇文化及，授其右屯卫将军之职','《隋书·宇文化及传》：述薨后，帝追忆之，故起化为右屯卫将军。','隋大业十二年',3,'2026-04-08 13:08:12.711609','2026-04-08 13:08:12.711609'),(102,26,'隋开皇末年至仁寿年间','青年','以父荫入仕侍奉太子杨广，多次因收受贿赂被免官，皆因杨广庇护很快复职，累迁至太子仆','《隋书·宇文化及传》：炀帝为太子时，常领千牛，出入卧内。累迁至太子仆。数以受纳货贿，再三免官，太子昵狎之，寻复其职。','隋开皇、仁寿年间',1,'2026-04-08 13:08:12.711876','2026-04-08 13:08:12.711876'),(103,27,'579','1','生于齐州临淄房氏望族，自幼聪敏，博览经史，工于书法，善作文章','《旧唐书·房玄龄传》：“玄龄幼聪敏，博览经史，工草隶，善属文。”','北周大象元年',0,'2026-04-08 13:13:51.689214','2026-04-08 13:13:51.689214'),(104,27,'596','18','本州举进士，授羽骑尉，入秘书省校勘典籍，吏部侍郎高孝基盛赞其才，认为将来必成伟器','《旧唐书·房玄龄传》：“年十八，本州举进士，授羽骑尉。吏部侍郎高孝基素称知人，见之深相嗟挹，谓裴矩曰：‘仆阅人多矣，未见如此郎者。必成伟器，但恨不睹其耸壑凌霄耳。’”','隋开皇十八年',1,'2026-04-08 13:13:51.690451','2026-04-08 13:13:51.690451'),(105,27,'隋大业初年','壮年','补任隰城县尉，受汉王杨谅谋反案牵连被谪徙上郡，见隋末天下大乱，慨然生忧天下、匡时济世之志','《旧唐书·房玄龄传》：“后补隰城尉。会汉王谅作乱，并州总管属官坐谅死徙者九十余人，玄龄皆在其中，因徙上郡。属中原方乱，慨然有忧天下志。”','隋朝晚期',2,'2026-04-08 13:13:51.690710','2026-04-08 13:13:51.690710'),(106,27,'617','39','于渭北谒见秦王李世民，被署为渭北道行军记室参军，成为李世民核心谋臣，随其征战四方，运筹帷幄，收揽人才，起草军书奏表','《旧唐书·房玄龄传》：“会义兵入关，太宗徇地渭北，玄龄杖策谒于军门，温彦博又荐焉。太宗一见，便如旧识，署渭北道行军记室参军。玄龄既遇知己，罄竭心力，知无不为。”','隋义宁元年',3,'2026-04-08 13:13:51.690911','2026-04-08 13:13:51.690911'),(107,27,'626','48','与长孙无忌、杜如晦等人共同谋划发动玄武门之变，助李世民夺得太子之位，事定后论功居第一，授太子右庶子','《旧唐书·房玄龄传》：“隐太子将有变也，太宗令长孙无忌召玄龄及如晦，令衣道士服，潜引入阁计事。及太宗入春宫，擢拜太子右庶子，赐绢五千匹。”','唐武德九年',4,'2026-04-08 13:13:51.691081','2026-04-08 13:13:51.691081'),(108,27,'627','49','拜中书令，进爵邢国公，与杜如晦等共掌朝政，主持制定唐初律令典制，时人并称“房杜”，为贞观名相之首','《旧唐书·房玄龄传》：“贞观元年，代萧瑀为中书令。论功行赏，以玄龄及长孙无忌、杜如晦、尉迟敬德、侯君集五人为第一，进爵邢国公，赐实封千三百户。”','唐贞观元年',5,'2026-04-08 13:13:51.691236','2026-04-08 13:13:51.691236'),(109,27,'629','51','改任尚书左仆射，监修国史，总领百司政务，夙夜操劳，为政宽平，选贤任能，不以求全责备取人','《旧唐书·房玄龄传》：“（贞观）三年，拜太子少师，固让不受，摄太子詹事，兼礼部尚书。明年，代长孙无忌为尚书左仆射，改封魏国公，监修国史。既任总百司，虔恭夙夜，尽心竭节，不欲一物失所。闻人有善，若己有之。明达吏事，饰以文学，审定法令，意在宽平。”','唐贞观三年',6,'2026-04-08 13:13:51.691383','2026-04-08 13:13:51.691383'),(110,27,'642','64','进位司空，仍综理朝政，监修完成《高祖实录》《太宗实录》，获太宗厚赐','《旧唐书·房玄龄传》：“十六年，拜司空，仍综朝政，监修国史。”','唐贞观十六年',7,'2026-04-08 13:13:51.699820','2026-04-08 13:13:51.699820'),(111,27,'643','65','图形凌烟阁，位列二十四功臣第五，同年受诏主持重修《晋书》','《旧唐书·房玄龄传》：“十七年，与司徒长孙无忌等图形于凌烟阁，赞曰：‘才兼藻翰，思入机神。当官励节，奉上忘身。’”','唐贞观十七年',8,'2026-04-08 13:13:51.700172','2026-04-08 13:13:51.700172'),(112,27,'648','70','病重去世，太宗废朝三日，追赠太尉、并州都督，谥号文昭，陪葬昭陵，后配享太宗庙廷','《旧唐书·房玄龄传》：“（贞观二十二年）寻薨，年七十。废朝三日，册赠太尉、并州都督，谥曰文昭，给东园秘器，陪葬昭陵。”','唐贞观二十二年',9,'2026-04-08 13:13:51.700455','2026-04-08 13:13:51.700455'),(113,28,'621','37','李世民开设文学馆招纳天下文士，杜如晦被选为十八学士之首，常与李世民讨论经义政务至深夜，是秦府核心智囊','《旧唐书·褚亮传》：始太宗既平寇乱，留意儒学，乃于宫城西起文学馆，以待四方文士。于是，以属大行台司勋郎中杜如晦等十八人并以本官兼文学馆学士。','唐武德四年',5,'2026-04-08 13:19:40.769499','2026-04-08 13:19:40.769499'),(114,28,'618-621','34-37','随李世民先后平定薛仁杲、刘武周、王世充、窦建德等割据势力，全程参与军机谋划，临事剖断如流，深得李世民及秦府僚属信服','《旧唐书·杜如晦传》：后从征薛仁杲、刘武周、王世充、窦建德，尝参谋帷幄。时军国多事，剖断如流，深为时辈所服。','唐武德元年至武德四年',4,'2026-04-08 13:19:40.769652','2026-04-08 13:19:40.769652'),(115,28,'585','1','生于京兆杜氏望族，自幼聪悟好学，喜好研读文史，性格沉毅有气度，临事果决','《旧唐书·杜如晦传》：如晦少聪悟，好谈文史，有器局，临事善断。','隋开皇五年',0,'2026-04-08 13:19:40.770189','2026-04-08 13:19:40.770189'),(116,28,'隋大业年间','青年','参与隋朝吏部选拔，被补授滏阳县尉，因见朝政混乱、隋室将亡，不久便弃官归隐观望时局','《新唐书·杜如晦传》：大业中，预吏部选，侍郎高孝基异之，补滏阳尉，辄弃官去。','隋朝晚期',1,'2026-04-08 13:19:40.770605','2026-04-08 13:19:40.770605'),(117,28,'618','34','李渊称帝建立唐朝，杜如晦被秦王李世民召入秦王府，任兵曹参军，成为秦府核心幕僚','《旧唐书·杜如晦传》：太宗平京城，引为秦王府兵曹参军，俄迁陕州总管府长史。','唐武德元年',2,'2026-04-08 13:19:40.770803','2026-04-08 13:19:40.770803'),(118,28,'619','35','太子李建成忌惮秦府势力，奏请李渊将秦府僚属外调，杜如晦在被逐之列；房玄龄向李世民力荐杜如晦为王佐之才，李世民遂奏请将其留任府中','《旧唐书·杜如晦传》：时府中多英俊，被外迁者众，太宗患之。记室房玄龄曰：‘府僚去者虽多，盖不足惜。杜如晦聪明识达，王佐才也。若大王守藩端拱，无所用之；必欲经营四方，非此人莫可。’太宗大惊曰：‘尔不言，几失此人矣。’遂奏为府属。','唐武德二年',3,'2026-04-08 13:19:40.771000','2026-04-08 13:19:40.771000'),(119,28,'626','42','作为核心谋臣参与策划玄武门之变，协助李世民诛杀李建成、李元吉；事变后论功行赏，与房玄龄、长孙无忌等五人功居第一，拜太子左庶子，不久迁兵部尚书，封蔡国公','《旧唐书·杜如晦传》：九年，建成被诛，太宗为皇太子，擢拜太子左庶子。俄迁兵部尚书，进封蔡国公，赐实封一千三百户。','唐武德九年',6,'2026-04-08 13:19:40.771172','2026-04-08 13:19:40.771172'),(120,28,'630','46','病重不治去世，李世民悲痛万分，废朝三日，追赠司空，改封莱国公，谥号为“成”，后事恩遇远超常制','《旧唐书·杜如晦传》：四年，疾笃……寻薨，年四十六。太宗哭之甚恸，废朝三日，赠司空，徙封莱国公，谥曰成。','唐贞观四年',9,'2026-04-08 13:19:40.771567','2026-04-08 13:19:40.771567'),(121,28,'629','45','升任尚书右仆射，与左仆射房玄龄共同执掌朝政；二人配合默契，房玄龄善谋划、杜如晦善决断，时人称为“房谋杜断”，二人携手制定唐代前期台阁规模、典章制度，奠定贞观之治的制度基础','《旧唐书·杜如晦传》：三年，代长孙无忌为尚书右仆射，仍知选事，与房玄龄共掌朝政。至于台阁规模，典章文物，皆二人所定，甚获当时之誉。','唐贞观三年',7,'2026-04-08 13:19:40.771966','2026-04-08 13:19:40.771966'),(122,28,'629','45','因积劳成疾上表辞官，李世民准奏，保留其全部俸禄待遇，多次派遣名医、宦官往返探望其病情','《旧唐书·杜如晦传》：其年冬，遇疾，表请解职，许之，禄赐特依旧。太宗深忧其疾，频遣使存问，名医上药，相望于道。','唐贞观三年',8,'2026-04-08 13:19:40.772103','2026-04-08 13:19:40.772103'),(123,28,'643','已故','唐太宗命人绘制二十四功臣画像于凌烟阁，杜如晦位列第三，为初唐三大功勋名臣之一','《旧唐书·杜如晦传》：十七年，与房玄龄等图形于凌烟阁，诏曰：‘尚书右仆射、蔡国公杜如晦，识量清举，神彩凝映，德宣内外，声溢庙堂。’','唐贞观十七年',10,'2026-04-08 13:19:40.777110','2026-04-08 13:19:40.777110'),(124,29,'617','47','任马邑郡丞，察觉太原留守李渊有举兵反隋的意图，伪装成囚徒前往江都准备向隋炀帝告发，因道路阻塞滞留在长安','《旧唐书·李靖传》：大业末，累除马邑郡丞。会高祖击突厥于塞外，靖察高祖，知有四方之志，因自锁上变，将诣江都，至长安，道塞不通而止。','隋大业十三年',2,'2026-04-08 13:24:59.433885','2026-04-08 13:24:59.433885'),(125,29,'571','1','生于雍州三原官宦世家，为北周名将韩擒虎外甥，少时便有文武才略，志在立功立事','《旧唐书·李靖传》：李靖，字药师，雍州三原人也。祖崇义，后魏殷州刺史、永康公。父诠，隋赵郡守。靖姿貌瑰伟，少有文武材略，每谓所亲曰：\"大丈夫若遇主逢时，必当立功立事，以取富贵。\"其舅韩擒虎，号为名将，每与论兵，未尝不称善，抚之曰：\"可与论孙、吴之术者，惟斯人矣。\"','北周天和六年',0,'2026-04-08 13:24:59.434091','2026-04-08 13:24:59.434091'),(126,29,'605','35','入仕隋朝，历任长安县功曹、殿内直长、驾部员外郎，得到吏部尚书牛弘、左仆射杨素的高度赏识，杨素称其日后必位至宰辅','《旧唐书·李靖传》：初仕隋为长安县功曹，后历驾部员外郎。左仆射杨素、吏部尚书牛弘皆善之。素尝拊其床谓靖曰：\"卿终当坐此。\"','隋大业元年',1,'2026-04-08 13:24:59.434436','2026-04-08 13:24:59.434436'),(127,29,'617','47','李渊攻克长安后擒获李靖，本欲将其斩首，李靖出言明志，得李世民求情获赦，被召入秦王幕府担任三卫','《旧唐书·李靖传》：高祖克京城，执靖将斩之，靖大呼曰：\"公起义兵，本为天下除暴乱，不欲就大事，而以私怨斩壮士乎！\"高祖壮其言，太宗又固请，遂舍之。太宗寻召入幕府，充三卫。','隋大业十三年',3,'2026-04-08 13:24:59.434616','2026-04-08 13:24:59.434616'),(128,29,'619','49','随秦王李世民东征王世充，因战功授开府','《旧唐书·李靖传》：武德二年，从讨王世充，以功授开府。','唐武德二年',4,'2026-04-08 13:24:59.434773','2026-04-08 13:24:59.434773'),(129,29,'635','65','吐谷浑入侵凉州，唐太宗起用李靖为西海道行军大总管，统率诸军征讨吐谷浑，大败吐谷浑，吐谷浑部众杀可汗慕容伏允投降，李靖另立慕容顺为可汗后班师回朝','《旧唐书·李靖传》：九年，吐谷浑寇边，太宗顾谓侍臣曰：\"得李靖为帅，岂非善也！\"靖乃见房玄龄曰：\"靖虽年老，固堪一行。\"太宗大悦，即以靖为西海道行军大总管，统兵部尚书侯君集、刑部尚书任城王道宗、凉州都督李大亮、右卫将军李道彦、利州刺史高甑生等五总管征之。……伏允西走，烧去野草，以疲我师。……靖遂平其国。伏允子大宁王顺穷蹙，斩其国相天柱王，举国来降。伏允大惧，与千余骑遁于碛中，众稍亡散，尚余百骑，为左右所杀。','唐贞观九年',11,'2026-04-08 13:24:59.436039','2026-04-08 13:24:59.436039'),(130,29,'634','64','因足疾上表请求辞官，得到唐太宗赞许，加授特进，允许他在家休养，病重时可临时入朝参议政事，被太宗称为\"一代楷模\"','《旧唐书·李靖传》：八年，诏为畿内道大使，伺察风俗。寻以足疾上表乞骸骨，言甚恳至。太宗遣中书侍郎岑文本谓曰：\"朕观自古已来，身居富贵，能知止足者甚少。……公能识达大体，深足可嘉，朕今非直成公雅志，欲以公为一代楷模。\"乃下优诏，加授特进，听在第摄养。','唐贞观八年',10,'2026-04-08 13:24:59.436476','2026-04-08 13:24:59.436476'),(131,29,'643','73','唐太宗命人在凌烟阁绘制二十四功臣像，李靖位列第八','《旧唐书·李靖传》：十七年，诏图画靖与赵郡王孝恭等二十四人于凌烟阁，诏曰：\"仪刑宇内，功冠当时，宜简良工，图写其状，庶念功之怀，无谢于前载；旌贤之义，永贻于后昆。\"','唐贞观十七年',12,'2026-04-08 13:24:59.437053','2026-04-08 13:24:59.437053'),(132,29,'649','79','李靖病重，唐太宗亲自前往探望，同年七月李靖病逝，册赠司徒、并州都督，谥号景武，陪葬昭陵','《旧唐书·李靖传》：二十三年，靖病亟，太宗幸其第视之，流涕谓之曰：\"公乃朕生平故人，于国有劳，今疾若此，为公忧之。\"其年七月薨，年七十九。册赠司徒、并州都督，给班剑四十人、羽葆鼓吹，陪葬昭陵，谥曰景武。','唐贞观二十三年',13,'2026-04-08 13:24:59.437232','2026-04-08 13:24:59.437232'),(133,29,'621','51','上陈攻灭萧铣的十条策略，任行军总管兼李孝恭的行军长史，统兵平定割据江陵的萧铣政权，战后被授上柱国，封永康县公，又奉命招抚岭南地区，得九十六州，六十余万户','《旧唐书·李靖传》：武德四年，靖又陈十策以图萧铣，高祖从之，授靖行军总管，兼摄孝恭行军长史，三军之任，一以委靖。……铣遣使请降，靖即入据其城，号令严肃，军无私焉。……于是度岭至桂州，遣人分道招抚，其大首领冯盎、李光度、宁真长等皆遣子弟来谒，靖承制授其官爵。凡所怀辑九十六州，户六十余万。','唐武德四年',5,'2026-04-08 13:24:59.437639','2026-04-08 13:24:59.437639'),(134,29,'630','60','亲率三千精骑夜袭定襄，大破突厥，随后又率军大破颉利可汗主力，擒获颉利可汗，灭亡东突厥，解除了唐朝北方的边患，因功进封代国公','《旧唐书·李靖传》：四年，靖进击定襄，破之，获隋齐王暕之子杨正道及炀帝萧后，送于京师，可汗仅以身遁。……遂督军疾进，师至阴山，遇其斥候千余帐，皆俘以随军。……靖军逼其牙帐十五里，虏始觉。颉利畏威先走，部众因而溃散。靖斩万余级，俘男女十余万，杀其妻隋义成公主。颉利乘千里马将走投吐谷浑，西道行军总管张宝相擒之以献。俄而突利可汗来奔，遂复定襄、常安之地，斥土界自阴山北至于大漠。','唐贞观四年',9,'2026-04-08 13:24:59.441027','2026-04-08 13:24:59.441027'),(135,29,'625','55','突厥入侵太原，李靖任行军总管，率江淮兵一万北上抵御突厥，诸军皆败，唯独李靖所部保全，战后权检校安州大都督','《旧唐书·李靖传》：八年，突厥寇太原，以靖为行军总管，统江淮兵一万，与张瑾屯大谷。时诸军不利，靖众独全。寻权检校安州大都督。','唐武德八年',7,'2026-04-08 13:24:59.443256','2026-04-08 13:24:59.443256'),(136,29,'629','59','唐太宗任命李靖为代州道行军总管，统率十几万大军分道出击东突厥','《旧唐书·李靖传》：贞观三年，转兵部尚书。突厥诸部离叛，朝廷将图进取，以靖为代州道行军总管，率骁骑三千，自马邑出其不意，直趋恶阳岭以逼之。','唐贞观三年',8,'2026-04-08 13:24:59.443437','2026-04-08 13:24:59.443437'),(137,29,'623','53','辅公祏在江东反唐，李靖任副元帅辅佐李孝恭出兵征讨，次年平定辅公祏叛乱，江南悉定，朝廷授其东南道行台兵部尚书','《旧唐书·李靖传》：六年，辅公祏于丹阳反，诏孝恭为元帅，靖为副以讨之。……公祏大惧，先遣伪将冯惠亮、陈当世领舟师三万屯博望山，……靖率轻兵先至丹阳，公祏大惧，拥兵数万不敢战，弃城而走，擒获于武康，江南悉平。','唐武德六年',6,'2026-04-08 13:24:59.443725','2026-04-08 13:24:59.443725'),(138,30,'619','26','窦建德攻陷黎阳，李勣被俘，被迫接受窦建德任命，次年寻机逃回长安','《旧唐书·李勣传》：二年，窦建德陷黎阳，获勣，复以为兵部尚书，使守黎阳。三年，勣自拔归京师。','唐武德二年',3,'2026-04-08 13:28:43.912350','2026-04-08 13:28:43.912350'),(139,30,'594','1','生于曹州离狐，本名徐世勣，字懋功，后迁居滑州卫南，家族豪富，父子皆乐善好施，周济贫民','《旧唐书·李勣传》：李勣，曹州离狐人也。隋末徙居滑州之卫南。本姓徐氏，名世勣，永徽中，以犯太宗讳，单名勣焉。家多僮仆，积粟数千钟，与其父盖皆好惠施，拯济贫乏，不问亲疏。','隋开皇十四年',0,'2026-04-08 13:28:43.912536','2026-04-08 13:28:43.912536'),(140,30,'隋大业年间','17','投奔瓦岗军首领翟让，劝说翟让劫掠汴水官船商旅物资，使瓦岗军兵势迅速壮大','《旧唐书·李勣传》：隋大业末，翟让为盗，勣年十七，往从之。说让曰：“宋、郑两郡，地管御河，商旅往还，船乘不绝，就彼邀截，足以自相资助。”让然之，于是劫公私船取物，兵众大振。','隋朝晚期',1,'2026-04-08 13:28:43.912978','2026-04-08 13:28:43.912978'),(141,30,'643','50','图形于凌烟阁，为二十四功臣之一，同年转任太子詹事，辅佐太子李治','《旧唐书·李勣传》：十七年，高宗为皇太子，转勣太子詹事兼左卫率，加位特进，同中书门下三品。……又图其形于凌烟阁，太宗亲为作赞。','唐贞观十七年',8,'2026-04-08 13:28:43.913302','2026-04-08 13:28:43.913302'),(142,30,'618','25','李密败降唐后，李勣将所统领的瓦岗旧境土地人口悉数通过李密上交唐廷，不私占功劳，被唐高祖李渊誉为纯臣，授黎阳总管、上柱国，封曹国公，赐姓李氏，附宗正属籍','《旧唐书·李勣传》：高祖闻而大悦曰：“徐世勣感德推功，实纯臣也。”诏授黎阳总管、上柱国，封莱国公。寻加右武候大将军，改封曹国公，赐姓李氏，赐良田五十顷，甲第一区。','唐武德元年',2,'2026-04-08 13:28:43.913563','2026-04-08 13:28:43.913563'),(143,30,'621','28','跟随秦王李世民平定王世充、窦建德割据势力，论功为下将，与太宗同服金甲告捷太庙，迁左监门大将军','《旧唐书·李勣传》：从太宗平窦建德，降王世充，振旅而还。论功行赏，太宗为上将，勣为下将，与太宗俱服金甲，乘戎辂，告捷于太庙。','唐武德四年',4,'2026-04-08 13:28:43.913736','2026-04-08 13:28:43.913736'),(144,30,'626','33','唐太宗李世民即位后，拜李勣为并州都督，赐实封九百户，命其镇守北方边境','《旧唐书·李勣传》：太宗即位，拜并州都督，赐实封九百户。','唐武德九年',5,'2026-04-08 13:28:43.913891','2026-04-08 13:28:43.913891'),(145,30,'630','37','任通汉道行军总管，与李靖等联军大破东突厥，俘获颉利可汗，平定北方边患','《旧唐书·李勣传》：贞观三年，为通汉道行军总管，至云中，与突厥颉利可汗兵会，大战于白道。……勣遂引兵逾碛，颉利闻之，走度碛，其大酋长率其部落并降于勣，虏五万余口而还。','唐贞观四年',6,'2026-04-08 13:28:43.914001','2026-04-08 13:28:43.914001'),(146,30,'641','48','在并州镇守十六年，令行禁止，突厥畏服，被太宗誉为远胜长城的贤将，同年被征入朝任兵部尚书，随即率军在诺真水大破薛延陀入侵军队','《旧唐书·李勣传》：勣在并州凡十六年，令行禁止，号为称职。太宗谓侍臣曰：“朕今委任李世勣于并州，遂使突厥畏威遁走，塞垣安静，岂不胜远筑长城耶？”','唐贞观十五年',7,'2026-04-08 13:28:43.914143','2026-04-08 13:28:43.914143'),(147,30,'645','52','随唐太宗征伐高句丽，连克盖牟、辽东、白岩等城，在驻跸山大破高句丽十五万援军','《旧唐书·李勣传》：授勣辽东道行军大总管，攻破盖牟、辽东、白崖等数城，又从太宗摧殄延寿、惠真十五万众于驻跸山，师还，加勋位。','唐贞观十九年',9,'2026-04-08 13:28:43.914392','2026-04-08 13:28:43.914392'),(148,30,'649','56','唐太宗临终前将其贬为叠州都督，嘱咐太子李治即位后召回施恩，高宗即位当月即召李勣回朝，拜洛州刺史、同中书门下平章事，参掌机密','《旧唐书·李勣传》：太宗寝疾，谓高宗曰：“汝于李勣无恩，我今将责出之。我死后，汝当授以仆射，即荷汝恩，必致其死力。”乃出为叠州都督。高宗即位，其月，召拜洛州刺史，寻加开府仪同三司，令同中书门下，参掌机密。','唐贞观二十三年',10,'2026-04-08 13:28:43.918547','2026-04-08 13:28:43.918547'),(149,30,'653','60','册拜司空，高宗再次命人为其图形凌烟阁，亲为作赞','《旧唐书·李勣传》：四年，册拜司空。初，贞观中，太宗以勋庸特著，尝图其形于凌烟阁，至是，帝又命写形焉，仍亲为之序。','唐永徽四年',11,'2026-04-08 13:28:43.918851','2026-04-08 13:28:43.918851'),(150,30,'655','62','在高宗废王立武事件中，以“此陛下家事，何必更问外人”的表态坚定高宗立武则天为后的决心，深得高宗夫妇信任','《资治通鉴·卷一百九十九》：上一日退朝，召勣入内殿，谓之曰：“朕欲立武昭仪为后，遂良固执以为不可。遂良既顾命大臣，事当且已乎？”对曰：“此陛下家事，何必更问外人！”上意遂决。','唐永徽六年',12,'2026-04-08 13:28:43.918974','2026-04-08 13:28:43.918974'),(151,30,'668','75','任辽东道行军大总管，率军攻克平壤，灭亡高句丽，设立安东都护府管辖其旧地，回朝后因功进封太子太师','《旧唐书·李勣传》：贼虏其王高藏及男建、男产，裂其诸城，并为州县，振旅而旋。……二年，加太子太师，增食实封通前一千一百户。','唐总章元年',13,'2026-04-08 13:28:43.924234','2026-04-08 13:28:43.924234'),(152,30,'669','76','病逝，高宗为之辍朝七日，追赠太尉、扬州大都督，谥号贞武，陪葬昭陵，坟墓仿照卫青、霍去病旧例，起冢象阴山、铁山、乌德鞬山，以表彰其开边功绩','《旧唐书·李勣传》：其年薨，年七十六。高宗闻之悲泣，辍朝七日，赠太尉、扬州大都督，谥曰贞武，给东园秘器，陪葬昭陵。……所筑坟一准卫、霍故事，象阴山、铁山及乌德鞬山，以旌破突厥、薛延陀之功。','唐总章二年',14,'2026-04-08 13:28:43.926444','2026-04-08 13:28:43.926444'),(153,31,'622年','壮年','随李世民征讨刘黑闼叛军，作战勇猛，击破刘黑闼部，平定河北地区','《旧唐书·秦叔宝传》：\"又从破刘黑闼，赏物千段。\"','唐武德五年',10,'2026-04-08 14:38:54.525218','2026-04-08 14:38:54.525218'),(154,31,'约571年','1','出生于齐州历城（今山东济南），自幼勇武过人，有气节','《旧唐书·秦叔宝传》：\"秦叔宝，名琼，齐州历城人也。\"','北齐武平二年',0,'2026-04-08 14:38:54.536237','2026-04-08 14:38:54.536237'),(155,31,'626年','约56岁','参与玄武门之变，协助李世民诛杀太子李建成、齐王李元吉，事后被任命为左武卫大将军，赐实封七百户','《旧唐书·秦叔宝传》：\"六月四日，从诛建成、元吉，事宁，拜左武卫大将军，食实封七百户。\"','唐武德九年',11,'2026-04-08 14:38:54.537235','2026-04-08 14:38:54.537235'),(156,31,'隋大业年间','青年','投身隋军，在隋将来护儿麾下任职，因勇武有志节得到来护儿器重，秦琼母亲去世时，来护儿破例遣使吊唁','《旧唐书·秦叔宝传》：\"大业中，为隋将来护儿帐内。叔宝丧母，护儿遣使吊之，军吏怪曰：‘士卒死亡及遭丧者多矣，将军未尝降问，独吊叔宝何也？’答曰：‘此人勇悍，加有志节，必当自取富贵，岂得以卑贱处之。’\"','隋朝晚期',1,'2026-04-08 14:38:54.538128','2026-04-08 14:38:54.538128'),(157,31,'614年','壮年','随齐郡通守张须陀攻打叛军卢明月，秦琼与罗士信率千余人偷袭敌营，纵火焚毁三十余座营寨，配合主力大破卢明月十万部众，自此勇武闻名天下','《旧唐书·秦叔宝传》：\"从须陀击贼帅卢明月于下邳，贼众十余万，须陀所部才万人，力势不敌，去贼六七里立栅，相持十余日，粮尽将退，谓诸将士曰：‘贼见兵却，必轻来追我，其众既出，营内即虚，若以千人袭营，可有大利，此诚危险，谁能去者？’人皆莫对，唯叔宝与罗士信请行。\"','隋大业十年',2,'2026-04-08 14:38:54.538560','2026-04-08 14:38:54.538560'),(158,31,'620年','壮年','随李世民征讨割据并州的刘武周、宋金刚势力，在美良川之战中大败尉迟敬德部，立下首功，战后获唐高祖李渊赏赐金瓶、黄金、绸缎，受封秦王右三统军','《旧唐书·秦叔宝传》：\"又从征于美良川，破尉迟敬德，功最居多。高祖遣使赐以金瓶，劳之曰：‘卿不顾妻子，远来投我，又立功效，朕肉可为卿用者，当割以赐卿，况子女玉帛乎？卿当勉之。’寻授秦王右三统军。\"','唐武德三年',8,'2026-04-08 14:38:54.538848','2026-04-08 14:38:54.538848'),(159,31,'618年9月','壮年','李密被王世充击败后降唐，秦琼被俘，王世充深知其勇武，任命其为龙骧大将军','《旧唐书·秦叔宝传》：\"后密败，又为王世充所得，署龙骧大将军。\"','唐武德元年',6,'2026-04-08 14:38:54.539135','2026-04-08 14:38:54.539135'),(160,31,'619年','壮年','不满王世充奸诈多诈，与程咬金等将领在两军对阵时主动投奔李唐，被唐高祖李渊分配至秦王李世民麾下任职，受任马军总管','《旧唐书·秦叔宝传》：\"叔宝薄世充之多诈，因其出抗官军，至于九曲，与程咬金、吴黑闼、牛进达等数十骑西驰百许步，下马拜世充曰：‘虽蒙殊礼，不能仰事，请从此辞。’世充不敢逼，于是来降。高祖令事秦府，太宗素闻其勇，厚加礼遇，从镇长春宫，拜马军总管。\"','唐武德二年',7,'2026-04-08 14:38:54.539538','2026-04-08 14:38:54.539538'),(161,31,'贞观年间','晚年','因早年历次作战身受重伤，常年患病，很少再领兵出征，闲居调养身体','《旧唐书·秦叔宝传》：\"其后每多疾病，因谓人曰：‘吾少长戎马，所经二百余阵，屡中重疮，计吾前后出血亦数斛矣，安得不病乎？’\"','唐初贞观时期',12,'2026-04-08 14:38:54.539981','2026-04-08 14:38:54.539981'),(162,31,'618年','壮年','瓦岗军与宇文化及部在黎阳童山激战，李密中箭坠马，左右奔散，追兵将至，秦琼只身护卫李密突围，之后收拢残兵击退宇文化及部','《旧唐书·秦叔宝传》：\"密与化及大战于黎阳童山，为流矢所中，堕马闷绝，左右奔散，追兵且至，唯叔宝独捍卫之，密遂获免，叔宝又收兵与之力战，化及乃退。\"','唐武德元年',5,'2026-04-08 14:38:54.540275','2026-04-08 14:38:54.540275'),(163,31,'617年','壮年','裴仁基献虎牢关投降瓦岗李密，秦琼随之加入瓦岗军，被李密任命为帐内骠骑，统领八千精锐内军','《旧唐书·秦叔宝传》：\"会仁基以武牢降于李密，密得叔宝大喜，以为帐内骠骑，待之甚厚。\"','隋大业十三年',4,'2026-04-08 14:38:54.550221','2026-04-08 14:38:54.550221'),(164,31,'621年','壮年','随李世民先后征讨王世充、窦建德割据势力，在虎牢关之战中率数十精锐率先突入窦建德大阵，动摇敌军阵型，为唐军全歼窦建德部十余万人立下大功，战后受封翼国公，获大量赏赐','《旧唐书·秦叔宝传》：\"又从破王世充，每为前锋，太宗平窦建德，降王世充，屡立殊勋，进封翼国公，赐物千段、金百斤。\"','唐武德四年',9,'2026-04-08 14:38:54.551170','2026-04-08 14:38:54.551170'),(165,31,'638年','约68岁','病逝，唐太宗李世民追赠其为徐州都督，陪葬昭陵，特令在其墓前立石人石马以表彰其战功；贞观十七年，被列入凌烟阁二十四功臣，位列第十六','《旧唐书·秦叔宝传》：\"十二年卒，赠徐州都督，陪葬昭陵。太宗特令所司就其茔内立石人马，以旌战阵之功焉。十三年，改封胡国公。十七年，与长孙无忌等图形于凌烟阁。\"','唐贞观十二年',13,'2026-04-08 14:38:54.552634','2026-04-08 14:38:54.552634'),(166,31,'616年','壮年','随张须陀攻打瓦岗军，张须陀战死，秦琼率余部归附隋将裴仁基','《旧唐书·秦叔宝传》：\"后从须陀击李密于荥阳，军败，须陀死之，叔宝以余众附裴仁基。\"','隋大业十二年',3,'2026-04-08 14:38:54.553190','2026-04-08 14:38:54.553190'),(167,32,'617','33','刘武周起兵反隋，将其招揽为偏将，随宋金刚南下攻唐，接连攻克晋州、浍州等地，屡败唐军','《旧唐书·尉迟敬德传》：\"刘武周起，以为偏将，与宋金刚南侵，陷晋、浍二州。\"','隋大业十三年',2,'2026-04-08 14:42:34.249698','2026-04-08 14:42:34.249698'),(168,32,'620','36','李世民击败宋金刚后，尉迟恭率部归降，获李世民信任，不久后在榆窠狩猎时遇王世充部突袭，横刺王世充骁将单雄信坠马，护卫李世民成功突围','《旧唐书·尉迟敬德传》：\"俄而寻相叛，诸将疑敬德必叛，囚于军中。太宗曰：‘敬德若怀翻背之计，岂在寻相之后耶？’遽命释之，引入卧内，赐以金宝。是日，从猎于榆窠，遇王世充领步骑数万来战。世充骁将单雄信领骑直趋太宗，敬德跃马大呼，横刺雄信坠马。贼徒稍却，敬德翼太宗以出贼围。\"','唐武德三年',3,'2026-04-08 14:42:34.249854','2026-04-08 14:42:34.249854'),(169,32,'621','37','跟随李世民先后平定窦建德、王世充、刘黑闼、徐圆朗等割据势力，累立战功，升任秦王府左二副护军，成为李世民核心亲信','《旧唐书·尉迟敬德传》：\"又从讨窦建德、王世充、刘黑闼，破徐圆朗，累有战功，授秦王府左二副护军。\"','唐武德四年',4,'2026-04-08 14:42:34.249997','2026-04-08 14:42:34.249997'),(170,32,'640','56','唐太宗提出将女儿嫁给他，尉迟恭以不忘结发妻子、富不易妻为由坚决推辞，获太宗赞许','《旧唐书·尉迟敬德传》：\"太宗尝谓敬德曰：‘朕将嫁女与卿，称意不？’敬德顿首谢曰：‘臣妇虽鄙陋，亦不失夫妻情。臣每闻说古人语，富不易妻，仁也。臣窃慕之，愿停圣恩。’叩头固让，太宗嘉之而止。\"','唐贞观十四年',7,'2026-04-08 14:42:34.250258','2026-04-08 14:42:34.250258'),(171,32,'643','59','上表请求辞官养老，授开府仪同三司，仅需每月初一、十五入朝，同年被列入凌烟阁二十四功臣，位列第七','《旧唐书·尉迟敬德传》：\"十七年，抗表乞骸骨，授开府仪同三司，令朝朔望。又与长孙无忌等二十四人图形于凌烟阁，敬德第七。\"','唐贞观十七年',8,'2026-04-08 14:42:34.251716','2026-04-08 14:42:34.251716'),(172,32,'隋大业年间','青年','入高阳官军参与平叛，因作战骁勇屡获升迁，官至朝散大夫','《旧唐书·尉迟敬德传》：\"大业末，从军于高阳，讨捕群盗，以武勇称，累授朝散大夫。\"','隋朝晚期',1,'2026-04-08 14:42:34.251984','2026-04-08 14:42:34.251984'),(173,32,'632','48','在庆善宫侍宴时因不满朝臣班次居于己上，当众发怒，殴打前来劝解的任城王李道宗，致其一眼几乎失明，遭到唐太宗严词警告，此后逐渐收敛言行','《旧唐书·尉迟敬德传》：\"尝侍宴庆善宫，时有班在其上者，敬德怒曰：‘汝有何功，合坐我上？’任城王道宗次其下，因解喻之。敬德勃然，拳殴道宗目，几至眇。太宗不怿而罢，谓敬德曰：‘朕览汉史，见高祖功臣获全者少，意常尤之。及居大位以来，常欲保全功臣，令子孙无绝。然卿居官辄犯宪法，方知韩、彭夷戮，非汉祖之愆。国家大事，唯赏与罚，非分之恩，不可数行，勉自修饬，无贻后悔也。’\"','唐贞观六年',6,'2026-04-08 14:42:34.252023','2026-04-08 14:42:34.252023'),(174,32,'585','1','生于朔州善阳（今山西朔州），字敬德，出身鲜卑尉迟氏，自幼习武，勇武过人','《旧唐书·尉迟敬德传》：\"尉迟敬德名恭，以字行，朔州善阳人。\"','隋开皇五年',0,'2026-04-08 14:42:34.252144','2026-04-08 14:42:34.252144'),(175,32,'645','61','随唐太宗亲征高句丽，担任左一马军总管，得胜还朝后闭门谢客，沉迷丹药炼制，自奉清乐，不与外人交往长达十六年','《旧唐书·尉迟敬德传》：\"太宗将伐高丽，令以本官行太常卿，为左一马军总管，从破高丽于驻跸山。军还，依旧致仕。敬德末年笃信仙方，飞炼金石，服食云母粉，穿筑池台，崇饰罗绮，尝奏清商乐以自奉养，不与外人交通，凡十六年。\"','唐贞观十九年',9,'2026-04-08 14:42:34.252484','2026-04-08 14:42:34.252484'),(176,32,'626','42','主导参与玄武门之变，射杀齐王李元吉，持太子李建成、李元吉首级示众瓦解东宫兵马攻势，随后入宫护卫唐高祖李渊，请其下手敕令诸军受秦王节制，事后论功第一，封右武候大将军、吴国公','《旧唐书·尉迟敬德传》：\"六月四日，建成既死，元吉走马东奔，左右射之坠马。太宗所乘马又逸于林下，坠不能兴。元吉遽来夺弓，垂欲相扼，敬德跃马叱之，奔逐射杀之。敬德持建成、元吉首以示之，宫府兵遂散。太宗命敬德侍卫高祖，敬德擐甲持矛，直至高祖所。高祖意乃安。论功为第一，拜右武候大将军，赐爵吴国公，食实封一千三百户。\"','唐武德九年',5,'2026-04-08 14:42:34.254026','2026-04-08 14:42:34.254026'),(177,32,'658','74','在家中去世，唐高宗为其废朝三日，追赠司徒、并州都督，谥号忠武，陪葬昭陵','《旧唐书·尉迟敬德传》：\"显庆三年，其年薨，年七十四。高宗为之举哀，废朝三日，令京官五品以上及朝集使赴宅哭，册赠司徒、并州都督，谥曰忠武，赐东园秘器，陪葬于昭陵。\"','唐显庆三年',10,'2026-04-08 14:42:34.255266','2026-04-08 14:42:34.255266'),(178,33,'隋大业末年','青年','隋末农民起义爆发，天下大乱，程咬金聚集数百乡勇，护卫本地乡里免遭乱兵匪寇劫掠','《旧唐书·程知节传》：\"大业末，聚徒数百，共保乡里，以备他盗。\"','隋朝晚期',1,'2026-04-08 14:58:46.833134','2026-04-08 14:58:46.833134'),(179,33,'624','36','太子李建成为削弱李世民势力，向唐高祖进谗将程咬金外放为康州刺史，程咬金拒不赴任，劝说李世民尽快采取行动自保','《旧唐书·程知节传》：\"武德七年，建成忌之，构之于高祖，除康州刺史。知节白太宗曰：‘大王手臂今并翦除，身必不久。知节以死不去，愿速自全。’\"','唐武德七年',6,'2026-04-08 14:58:46.833357','2026-04-08 14:58:46.833357'),(180,33,'589','1','本名程咬金，后改名程知节，字义贞，生于济州东阿官宦世家，年少时即骁勇过人，擅长使用马槊','《旧唐书·程知节传》：\"程知节，本名咬金，济州东阿人也。少骁勇，善用马槊。\"','隋开皇九年',0,'2026-04-08 14:58:46.833546','2026-04-08 14:58:46.833546'),(181,33,'617','29','率部归附瓦岗军领袖李密，受任内军骠骑，统领李密麾下八千精锐内军的其中一部，深得李密信任','《旧唐书·程知节传》：\"后依李密，署为内军骠骑。时密于军中简勇士尤异者八千人，隶四骠骑，分为左右以自卫，号为内军。自云：‘此八千人可当百万。’知节既领其一，甚被恩遇。\"','隋义宁元年',2,'2026-04-08 14:58:46.833993','2026-04-08 14:58:46.833993'),(182,33,'618','30','王世充与李密决战于偃师，程咬金为救中箭坠马的裴行俨，身受重创仍突破敌阵将其救回；后李密兵败，程咬金被王世充俘获，王世充对其十分优待','《旧唐书·程知节传》：\"及王世充出城决战，知节领内马军，与密同营在北邙山上。世充遣骑击行俨，行俨中流矢坠于地，知节驰马救之，杀数人，世充军披靡，乃抱行俨重骑而还。为世充骑所逐，刺槊洞过，知节回身捩折其槊，兼斩获追者，于是与行俨俱免。及密败，世充得之，接遇甚厚。\"','唐武德元年',3,'2026-04-08 14:58:46.834233','2026-04-08 14:58:46.834233'),(183,33,'621','33','跟随李世民先后平定宋金刚、窦建德、王世充等割据势力，每战皆率先冲锋陷阵，以军功受封宿国公','《旧唐书·程知节传》：\"从破宋金刚，擒窦建德，降王世充，每阵先登，以功封宿国公。\"','唐武德四年',5,'2026-04-08 14:58:46.834426','2026-04-08 14:58:46.834426'),(184,33,'655','67','升任左卫大将军','《旧唐书·程知节传》：\"永徽六年，迁左卫大将军。\"','唐永徽六年',10,'2026-04-08 14:58:46.835303','2026-04-08 14:58:46.835303'),(185,33,'658','70','被朝廷重新起用为岐州刺史，程咬金以年老为由上疏请求致仕，获得批准','《旧唐书·程知节传》：\"未几，授岐州刺史。表请乞骸骨，许之。\"','唐显庆三年',12,'2026-04-08 14:58:46.835509','2026-04-08 14:58:46.835509'),(186,33,'665','77','于长安家中去世，朝廷追赠其为骠骑大将军、益州大都督，陪葬昭陵，谥号为‘襄’','《旧唐书·程知节传》：\"麟德二年卒，赠骠骑大将军、益州大都督，陪葬昭陵。谥曰襄。\"','唐麟德二年',13,'2026-04-08 14:58:46.835607','2026-04-08 14:58:46.835607'),(187,33,'657','69','被任命为葱山道行军大总管，领兵征讨西突厥阿史那贺鲁；大军行至怛笃城时，副大总管王文度矫旨收军，又杀降取财，程咬金未加劝阻，班师回朝后因此被免官','《旧唐书·程知节传》：\"显庆二年，授葱山道行军大总管以讨贺鲁。师次怛笃城，有胡人数千家开门出降，知节屠城而去，贺鲁遂即远遁。军还，坐免官。\"','唐显庆二年',11,'2026-04-08 14:58:46.835414','2026-04-08 14:58:46.835414'),(188,33,'643','55','唐太宗下诏将二十四位开国功臣画像悬于凌烟阁，程咬金位列第十九；同年转任左屯卫大将军，负责镇守玄武门','《旧唐书·程知节传》：\"十七年，累转左屯卫大将军，检校北门屯兵，加镇军大将军。\"《旧唐书·太宗纪》：\"十七年二月，诏图画司徒、赵国公无忌等勋臣二十四人于凌烟阁，程知节预焉。\"','唐贞观十七年',9,'2026-04-08 14:58:46.840266','2026-04-08 14:58:46.840266'),(189,33,'619','31','不满王世充为人猜忌狡诈、难成大事，与秦叔宝等将领在九曲对阵时率部临阵投唐，被分配至秦王李世民麾下效力','《旧唐书·程知节传》：\"知节谓秦叔宝曰：‘世充器度浅狭，而多妄语，好为咒誓，乃巫师老妪耳，岂是拨乱主乎？’及世充拒王师于九曲，知节领兵在其阵，与叔宝等马上揖世充曰：‘荷公接待，极欲报恩。公性猜贰，傍多扇惑，非仆托身之所，今谨奉辞。’于是跃马与左右数十人归国，世充惧，不敢追之。高祖使事秦府，太宗素闻其勇，厚加礼遇。\"','唐武德二年',4,'2026-04-08 14:58:46.847637','2026-04-08 14:58:46.847637'),(190,33,'626','38','参与玄武门之变，跟随李世民诛杀太子李建成、齐王李元吉，政变成功后升任右武卫大将军，获赐实封七百户','《旧唐书·程知节传》：\"六月四日，从太宗讨建成、元吉。事定，拜太子右卫率，迁右武卫大将军，赐实封七百户。\"','唐武德九年',7,'2026-04-08 14:58:46.850509','2026-04-08 14:58:46.850509'),(191,33,'633','45','累迁泸州都督，获赐实封加至一千户','《旧唐书·程知节传》：\"贞观中，累迁泸州都督，赐实封一千户。\"','唐贞观七年',8,'2026-04-08 14:58:46.850368','2026-04-08 14:58:46.850368'),(192,34,'658','45','作为程名振的副将经略辽东，在贵端城大破高句丽军队，斩首三千级','《新唐书》：显庆三年，诏副程名振经略辽东，破高丽于贵端城，斩首三千级。','唐显庆三年',4,'2026-04-08 15:02:31.917617','2026-04-08 15:02:31.917617'),(193,34,'659','46','先后在横山、石城击败高句丽军队，生擒高句丽神箭手；随后在黑山击破契丹部众，生擒契丹王阿卜固押赴东都，因功升任左武卫将军，封河东县男','《新唐书》：明年，与梁建方、契苾何力遇高丽大将温沙多门，战横山，仁贵独驰入，所射皆应弦仆。又战石城，有善射者，杀官军十余人，仁贵怒，单骑突击，贼弓矢俱废，遂生擒之。俄与辛文陵破契丹于黑山，执其王阿卜固献东都。拜左武卫将军，封河东县男。','唐显庆四年',5,'2026-04-08 15:02:31.917801','2026-04-08 15:02:31.917801'),(194,34,'614','1','生于绛州龙门普通农户之家，少时家境贫寒，以耕种为业，熟习骑射，勇武过人','《旧唐书》：薛仁贵，绛州龙门人。少贫贱，以田为业。','隋大业十年',0,'2026-04-08 15:02:31.918472','2026-04-08 15:02:31.918472'),(195,34,'645','32','东征高句丽的安市城之战中，身着白衣冲锋陷阵，所向披靡，被唐太宗一眼识别，战后破格提拔为游击将军、云泉府果毅，获赐财物奴婢，唐太宗称\"不喜得辽东，喜得卿也\"，班师后升任右领军中郎将，负责玄武门宿卫','《旧唐书》：仁贵自恃骁勇，欲立奇功，乃异其服色，著白衣，握戟，腰鞬张弓，大呼先入，所向无前，贼尽披靡却走。太宗遥望见之，遣驰问先锋白衣者为谁，特引见，赐马两匹、绢四十匹，擢授游击将军、云泉府果毅。及军还，太宗谓曰：\"朕旧将并老，不堪受阃外之寄，每欲抽擢骁雄，莫如卿者。朕不喜得辽东，喜得卿也。\"寻迁右领军郎将，依旧北门长上。','唐贞观十九年',2,'2026-04-08 15:02:31.918609','2026-04-08 15:02:31.918609'),(196,34,'644','31','听从妻子柳氏规劝，放弃迁葬先人祖坟的计划，到将军张士贵帐下应募从军，加入东征高句丽的唐军序列','《新唐书》：妻柳曰：\"夫有高世之材，要须遇时乃发。今天子自征辽东，求猛将，此难得之时，君盍图功名以自显？富贵还乡，葬未晚。\"仁贵乃往见将军张士贵应募。','唐贞观十八年',1,'2026-04-08 15:02:31.918724','2026-04-08 15:02:31.918724'),(197,34,'654','41','唐高宗巡幸万年宫时遭遇山洪，宿卫士卒四散逃命，薛仁贵冒死登上宫门横梁大声示警，高宗及时撤离躲过一劫，获赐御马一匹','《旧唐书》：永徽五年，高宗幸万年宫，甲夜，山水猥至，冲突玄武门，宿卫者散走。仁贵曰：\"安有天子有急，辄敢惧死？\"遂登门桄叫呼以惊宫内。高宗遽出乘高，俄而水入寝殿，上使谓仁贵曰：\"赖得卿呼，方免沦溺，始知有忠臣也。\"于是赐御马一匹。','唐永徽五年',3,'2026-04-08 15:02:31.918832','2026-04-08 15:02:31.918832'),(198,34,'661','48','作为郑仁泰的副将征讨铁勒九姓叛乱，阵前连发三箭射杀敌军三名骁勇骑士，敌军震慑投降，铁勒九姓自此衰弱，边患平息，军中传唱\"将军三箭定天山，战士长歌入汉关\"','《旧唐书》：时九姓有众十余万，令骁健数十人逆来挑战，仁贵发三矢，射杀三人，自余一时下马请降。军中歌曰：\"将军三箭定天山，战士长歌入汉关。\"九姓自此衰弱，不复更为边患。','唐龙朔元年',6,'2026-04-08 15:02:31.919682','2026-04-08 15:02:31.919682'),(199,34,'668','55','随李勣征讨高句丽，率两千人攻克扶余城，扶余川四十余城望风归降，随后与诸军合围平壤，高句丽灭亡。战后授右威卫大将军，封平阳郡公，检校安东都护，镇守平壤，抚辑高句丽遗民','《旧唐书》：仁贵乘胜领二千人进攻扶余城，诸将咸言兵少，仁贵曰：\"在主将善用耳，不在多也。\"遂先锋而行，贼众来拒，逆击大破之，杀获万余人，遂拔扶余城。扶余川四十余城，乘风震慑，一时送款。高丽既降，授仁贵右威卫大将军，封平阳郡公，仍检校安东都护。','唐总章元年',7,'2026-04-08 15:02:31.919846','2026-04-08 15:02:31.919846'),(200,34,'676','63','高句丽余众叛乱，薛仁贵被起用为鸡林道总管，不久因事获罪被流放象州，后遇朝廷大赦得以返回中原','《新唐书》：未几，高丽余众叛，起为鸡林道总管。复坐事贬象州，会赦还。','唐上元三年',9,'2026-04-08 15:02:31.920235','2026-04-08 15:02:31.920235'),(201,34,'682','69','唐高宗念其功绩，重新起用为右领军卫将军、检校代州都督，率军在云州迎击突厥阿史德元珍部，突厥士卒听闻薛仁贵为将，望风而逃，唐军乘势追击，斩首万级，俘获生口两万、牛羊无数','《旧唐书》：开耀元年，起授瓜州长史，寻拜右领军卫将军，检校代州都督。又率兵击突厥元珍等于云州，突厥闻薛仁贵复起为将，素惮其名，皆奔散，不敢当之。','唐永淳元年',10,'2026-04-08 15:02:31.920550','2026-04-08 15:02:31.920550'),(202,34,'683','70','病逝，朝廷追赠左骁卫大将军、幽州都督，由官府提供灵舆，护送其灵柩返回故乡安葬','《旧唐书》：永淳二年卒，年七十，赠左骁卫大将军、幽州都督，官给舆，护丧还乡里。','唐永淳二年',11,'2026-04-08 15:02:31.924709','2026-04-08 15:02:31.924709'),(203,34,'670','57','任逻娑道行军大总管征讨吐蕃，因副将郭待封违抗节度，粮草辎重被吐蕃劫掠，唐军在大非川战败，薛仁贵被削职为民','《旧唐书》：咸亨元年，吐蕃入寇，又以仁贵为逻娑道行军大总管，率将军阿史那道真、郭待封等以击之。待封尝为鄯城镇守，耻在仁贵之下，多违节度。军至大非川，吐蕃四十余万来拒战，官军大败，仁贵遂与吐蕃大将论钦陵约和。仁贵坐除名。','唐咸亨元年',8,'2026-04-08 15:02:31.926634','2026-04-08 15:02:31.926634'),(204,35,'697','1','生于华州郑县（今陕西渭南华州区），出身官宦世家，父亲郭敬之曾任五州刺史','《旧唐书·郭子仪传》：郭子仪，字子仪，华州郑人也。父敬之，历绥、渭、桂、寿、泗五州刺史，以子仪贵，赠太保，追封祁国公。','武周神功元年',0,'2026-04-08 15:09:36.532226','2026-04-08 15:09:36.532226'),(205,35,'721','25','参加武举考试取得高等成绩，补授左卫长史，正式开启军旅仕途','《旧唐书·郭子仪传》：始以武举高等补左卫长史，累历诸军使。','唐开元九年',1,'2026-04-08 15:09:36.532441','2026-04-08 15:09:36.532441'),(206,35,'756','60','唐肃宗在灵武即位，与李光弼率五万大军赴灵武勤王，被授为兵部尚书、同中书门下平章事，仍领朔方节度使，为平定安史之乱的核心统帅','《旧唐书·郭子仪传》：肃宗即位，以贼据两京，方谋收复，诏子仪班师。八月，子仪与李光弼率步骑五万至自河北。时朝廷初立，兵众寡弱，虽得牧马，军容缺然。及子仪、光弼全师赴行在，军声遂振，兴复之势，民有望焉。拜子仪兵部尚书、同中书门下平章事，余如故。','唐至德元载',4,'2026-04-08 15:09:36.532685','2026-04-08 15:09:36.532685'),(207,35,'758','62','进位中书令，与李光弼等九位节度使率十万大军围攻相州的安庆绪叛军','《旧唐书·郭子仪传》：乾元元年七月，破贼于河上，擒伪将安守忠以献，遂朝于京师。进位中书令，寻又与九节度围安庆绪于相州。','唐乾元元年',6,'2026-04-08 15:09:36.532853','2026-04-08 15:09:36.532853'),(208,35,'749','53','出任横塞军使，兼安北都护府副都护，不久改任永清军使，升任左卫大将军','《旧唐书·郭子仪传》：天宝八载，于木剌山置横塞军及安北都护府，命子仪领其使，拜左卫大将军。十三载，移横塞军及安北都护府于永清栅北筑城，仍改横塞为天德军，子仪为之使，兼九原太守、朔方节度右兵马使。','唐天宝八载',2,'2026-04-08 15:09:36.533002','2026-04-08 15:09:36.533002'),(209,35,'755','59','安史之乱爆发，受诏任朔方节度使，率部东讨叛军，收复静边军，斩杀叛将周万顷，击败叛将高秀岩','《旧唐书·郭子仪传》：十四载，安禄山反，十一月，以子仪为卫尉卿，兼灵武郡太守，充朔方节度使，诏子仪以本军东讨。遂举兵出单于府，收静边军，斩贼将周万顷，传首阙下。贼将高秀岩寇振武军，子仪击败之，又收云中、马邑，开东陉关。','唐天宝十四载',3,'2026-04-08 15:09:36.533133','2026-04-08 15:09:36.533133'),(210,35,'757','61','随天下兵马大元帅李俶（即唐代宗）率蕃汉大军收复西京长安、东都洛阳，安史之乱取得阶段性胜利，因功加封司徒、代国公','《旧唐书·郭子仪传》：二载，入关中，与贼将安守忠战于清渠，官军败绩，子仪收保武功，待罪于朝，乞降官阶，乃授左仆射，余如故。未几，从元帅广平王率蕃汉之师十五万进收长安。京师平，留子仪经营东都。十月，子仪破贼于陕州西新店，贼走，遂复东都。以功加司徒，封代国公，食邑一千户。','唐至德二载',5,'2026-04-08 15:09:36.533628','2026-04-08 15:09:36.533628'),(211,35,'759','63','相州之战官军溃败，监军鱼朝恩将战败责任嫁祸郭子仪，郭子仪被召回京师，解除兵权，闲居在家','《旧唐书·郭子仪传》：明年三月，官军败于邺下，子仪以朔方军保河阳，断浮桥。有诏留守东都。俄为鱼朝恩所构，召还京师，以李光弼代为朔方节度使、兵马副元帅，子仪乃留京师。','唐乾元二年',7,'2026-04-08 15:09:36.533779','2026-04-08 15:09:36.533779'),(212,35,'762','66','太原、绛州发生兵变，朝廷起用郭子仪为汾阳郡王，出镇绛州，斩杀兵变首恶数十人，平定乱局，不久又被宦官程元振谗言，再次罢职','《旧唐书·郭子仪传》：宝应元年二月，河中、太原军乱，杀其帅，朝廷忧其与贼合，乃起子仪为朔方、河中、北庭、潞仪泽沁等州节度行营兼兴平、定国副元帅，充本管观察处置使，进封汾阳郡王，出镇绛州。子仪至绛，擒其杀帅者四十余人斩之，诸镇帖然。时程元振用事，忌子仪功高任重，数行谮毁，子仪惧，表请解副元帅、节度使，许之。','唐宝应元年',8,'2026-04-08 15:09:36.533895','2026-04-08 15:09:36.533895'),(213,35,'763','67','吐蕃攻入长安，唐代宗出逃陕州，郭子仪被重新起用为关内副元帅，收拢散兵数千人，用疑兵计逼退吐蕃，收复长安，迎代宗回京','《旧唐书·郭子仪传》：广德元年十月，吐蕃寇泾州，寇奉天、武功，京师震骇。代宗幸陕，子仪闲废日久，部曲离散，至是承召，麾下得二十骑而行。至商州，收合亡散及六军逃卒至数千人，军势稍振。吐蕃既立广武王承宏，欲掠城中士女、百工，整众归国。子仪使数百骑于蓝田城西南面击鼓，多张旗帜，夜则燃火以疑之。吐蕃惶骇，悉众遁去，京师收复。十二月，车驾还京，子仪率城内百官及诸军，于浐东奉迎。','唐广德元年',9,'2026-04-08 15:09:36.533985','2026-04-08 15:09:36.533985'),(214,35,'765','69','仆固怀恩引吐蕃、回纥等数十万大军入寇关中，郭子仪单骑赴回纥大营，以旧情谊说服回纥倒戈，与唐军联手大败吐蕃，解除边患','《旧唐书·郭子仪传》：永泰元年九月，仆固怀恩诱吐蕃、回纥、党项、羌、浑、奴剌等凡三十余万众，南犯京师。子仪自河中赴，屯泾阳。虏骑合围，子仪率甲骑二千出没于左右前后，回纥知为令公，疑其尚存。子仪乃免胄赴回纥营，见其大酋曰：‘诸君同艰难久矣，何忽亡忠谊而至是耶？’回纥皆舍兵下马齐拜曰：‘果吾父也。’子仪因说回纥共击吐蕃，吐蕃夜遁，遂大败之，斩首五万，生擒万人，获其所掠士女四千人，驼马牛羊数百里不绝。','唐永泰元年',10,'2026-04-08 15:09:36.538369','2026-04-08 15:09:36.538369'),(215,35,'779','83','唐代宗驾崩，唐德宗即位，郭子仪被尊为‘尚父’，进位太尉、中书令，所领诸使、副元帅职务全部被罢免，不再掌兵权','《旧唐书·郭子仪传》：大历十四年五月，代宗崩，遗诏子仪摄冢宰。德宗即位，诏还朝，摄冢宰，充山陵使，赐号‘尚父’，进位太尉、中书令，增实封通前二千户，给粮千五百人，马二百匹，所领诸使副元帅并罢。','唐大历十四年',11,'2026-04-08 15:09:36.539597','2026-04-08 15:09:36.539597'),(216,35,'781','85','病逝，享年八十五岁，唐德宗废朝五日悼念，追赠太师，谥号忠武，配享代宗庙廷','《旧唐书·郭子仪传》：建中二年夏，子仪病甚，德宗遣舒王谊至省问。六月薨，时年八十五。德宗闻之震悼，废朝五日，赠太师，谥曰忠武，配飨代宗庙庭。','唐建中二年',12,'2026-04-08 15:09:36.539790','2026-04-08 15:09:36.539790'),(217,36,'708','1','出身营州柳城契丹贵族，父亲李楷洛为唐朝朔方节度副使，封蓟国公，李光弼自幼沉稳坚毅，善骑射，喜读《汉书》','《旧唐书·李光弼传》：李光弼，营州柳城人也。其先，契丹之酋长。父楷洛，开元初左羽林将军同正、朔方节度副使，封蓟国公，以骁果闻。','唐中宗景龙二年',0,'2026-04-08 15:25:06.394839','2026-04-08 15:25:06.394839'),(218,36,'746','39','得朔方节度使王忠嗣赏识，提拔为兵马使，王忠嗣曾断言李光弼日后必会接替自己执掌兵权','《旧唐书·李光弼传》：节度使王忠嗣遇之甚厚，常云：‘光弼必居我位。’','唐玄宗天宝五载',2,'2026-04-08 15:25:06.396383','2026-04-08 15:25:06.396383'),(219,36,'761','54','受宦官鱼朝恩逼迫，被迫出师收复洛阳，于邙山被史思明击败，上表请罪后不久复职，出镇临淮','《旧唐书·李光弼传》：上元二年，鱼朝恩屡言贼可灭之状，朝旨令光弼速收东都。光弼不得已，出师战于邙山，官军败绩，光弼走保闻喜，上表请罪，诏释之，寻复拜太尉，兼侍中、河南副元帅，出镇临淮。','唐肃宗上元二年',9,'2026-04-08 15:25:06.396613','2026-04-08 15:25:06.396613'),(220,36,'开元年间','青年','少年入仕，补左卫亲府左郎将，多次升迁至安北都护府都虞候，治军严整，颇受同僚敬畏','《新唐书·李光弼传》：光弼严毅沉果，有大略，幼不嬉弄，善骑射，能读《班固汉书》。少补左卫郎，累迁左清道率兼安北都护府、朔方都虞候。','唐玄宗开元年间',1,'2026-04-08 15:25:06.396936','2026-04-08 15:25:06.396936'),(221,36,'755','48','安史之乱爆发，经郭子仪举荐，被唐玄宗任命为河东节度副使，奉命率军东讨叛军','《旧唐书·李光弼传》：及安禄山反，封常清、高仙芝败绩于东京，玄宗求良将于郭子仪，子仪荐光弼堪当阃寄。','唐玄宗天宝十四载',4,'2026-04-08 15:25:06.397265','2026-04-08 15:25:06.397265'),(222,36,'749','42','升任河西节度副使，封蓟郡公，因治军严明、屡立战功，在军中威望极高','《新唐书·李光弼传》：天宝八载，充节度副使，封蓟郡公。','唐玄宗天宝八载',3,'2026-04-08 15:25:06.397375','2026-04-08 15:25:06.397375'),(223,36,'757','50','以不足一万兵力坚守太原，对抗史思明等部十万叛军，歼敌七万余人，取得太原保卫战大捷，以功升任司空、兵部尚书，封魏国公','《旧唐书·李光弼传》：至德二载，贼将史思明、蔡希德、高秀岩、牛廷玠等四伪帅率众十余万来攻太原，光弼麾下精兵尽赴朔方，麾下士卒不满万人，光弼亲率士卒奋战，大破贼军，斩首七万余级，军资器械不可胜数。以功迁司空，兼兵部尚书，进封魏国公。','唐肃宗至德二载',6,'2026-04-08 15:25:06.397517','2026-04-08 15:25:06.397517'),(224,36,'756','49','率军收复常山郡，于嘉山大破史思明部，斩杀俘获叛军数万人，收复河北十余郡县','《旧唐书·李光弼传》：光弼以景城、河间兵五千入常山，俘斩贼兵数千，史思明闻常山不守，解饶阳之围来救，光弼大破之，斩首万余级，生擒四千，河北十余郡皆斩贼守将以降。','唐肃宗至德元载',5,'2026-04-08 15:25:06.397650','2026-04-08 15:25:06.397650'),(225,36,'760','53','加授太尉、中书令，进封临淮郡王，率军攻克怀州，生擒叛将安太清','《旧唐书·李光弼传》：上元元年，加光弼太尉、兼中书令，进封临淮郡王。光弼遂收怀州，生擒安太清送京师。','唐肃宗上元元年',8,'2026-04-08 15:25:06.397773','2026-04-08 15:25:06.397773'),(226,36,'762','55','出镇徐州，击破史朝义残部，又平定浙东袁晁起义，获赐铁券，图形凌烟阁','《新唐书·李光弼传》：宝应元年，出镇徐州，败史朝义兵，又平袁晁之乱，加食邑实封二千户，与郭子仪等八人图形凌烟阁。','唐代宗宝应元年',10,'2026-04-08 15:25:06.398077','2026-04-08 15:25:06.398077'),(227,36,'763','56','吐蕃攻入长安，代宗下诏征李光弼勤王，他因惧怕宦官程元振、鱼朝恩构陷，迁延不至，声名受损','《旧唐书·李光弼传》：广德初，吐蕃入寇京畿，代宗诏征天下兵，光弼与程元振不协，迁延不至。','唐代宗广德元年',11,'2026-04-08 15:25:06.404093','2026-04-08 15:25:06.404093'),(228,36,'759','52','接替郭子仪任朔方节度使、天下兵马副元帅，于河阳之战中多次击破史思明叛军，稳定河南战局','《新唐书·李光弼传》：乾元二年，代郭子仪为朔方节度使、天下兵马副元帅，会贼将史思明杀安庆绪，悉众来攻，光弼守河阳，斩俘万计，贼势大挫。','唐肃宗乾元二年',7,'2026-04-08 15:25:06.404342','2026-04-08 15:25:06.404342'),(229,36,'764','57','在徐州病逝，追赠太保，谥号“武穆”，陪葬建陵','《旧唐书·李光弼传》：广德二年七月，薨于徐州，时年五十七。废朝三日，赠太保，谥曰武穆，陪葬建陵。','唐代宗广德二年',12,'2026-04-08 15:25:06.404238','2026-04-08 15:25:06.404238'),(230,37,'741年','44','得安西节度使夫蒙灵詧赏识重用，累迁至安西副都护、四镇都知兵马使，成为安西都护府核心军事长官','《旧唐书·高仙芝传》：开元末，为安西副都护、四镇都知兵马使。','唐开元二十九年',2,'2026-04-08 15:31:42.982801','2026-04-08 15:31:42.982801'),(231,37,'747年','50','回师后因平小勃律之功，被唐玄宗征召入朝，取代夫蒙灵詧出任安西四镇节度使，加御史中丞','《新唐书·高仙芝传》：会监军边令诚以闻，诏征仙芝赴阙，拜鸿胪卿，摄御史中丞，代灵詧为安西四镇节度使。','唐天宝六年',4,'2026-04-08 15:31:42.983083','2026-04-08 15:31:42.983083'),(232,37,'750年','53','先后击破朅师国、石国，俘虏石国国王，因掠夺大量珍宝、屠戮当地民众引发西域诸国不满，石国王子逃奔大食求救，为怛罗斯之战埋下隐患','《旧唐书·高仙芝传》：九载，将兵讨石国，平之，获其国王以归。仙芝性贪，获石国大块瑟瑟十馀石、真金五六馲驼、名马宝玉称是。《新唐书·高仙芝传》：其王子走大食，乞兵攻仙芝于怛逻斯城。','唐天宝九年',5,'2026-04-08 15:31:42.983301','2026-04-08 15:31:42.983301'),(233,37,'751年','54','率蕃汉三万大军深入葱岭以西进攻大食，在怛罗斯城与大食军遭遇激战五日，因附属葛逻禄部叛逃夹击，唐军大败，仅率数千人退回安西','《资治通鉴·卷二百一十六》：高仙芝之虏石国王也，石国王子逃诣诸胡，具告仙芝欺诱贪暴之状。诸胡皆怒，潜引大食欲共攻四镇。仙芝闻之，将蕃、汉三万众击大食，深入七百馀里，至怛逻斯城，与大食遇。相持五日，葛罗禄部众叛，与大食夹攻唐军，仙芝大败，士卒死亡略尽，所馀才数千人。','唐天宝十年',6,'2026-04-08 15:31:42.983463','2026-04-08 15:31:42.983463'),(234,37,'开元年间','20余','少年随父至安西军中历练，因善骑射、骁勇有谋，以军功授游击将军，后拜将军，与父亲品级相同','《旧唐书·高仙芝传》：仙芝美姿容，善骑射，勇决骁果。少随父至安西，以父有功授游击将军。年二十余即拜将军，与父同班秩。','唐玄宗开元年间',1,'2026-04-08 15:31:42.983633','2026-04-08 15:31:42.983633'),(235,37,'747年','50','率步骑一万远征依附吐蕃的小勃律国，翻越葱岭奇袭连云堡，俘虏小勃律国王及吐蕃公主，平定小勃律，拂菻、大食等七十二国闻讯震恐归降唐朝','《旧唐书·高仙芝传》：天宝六载，仙芝率步骑一万以伐之。……遂平其国，虏小勃律王及吐蕃公主而还。……是时，拂菻、大食诸胡七十二国皆震慑降附。','唐天宝六年',3,'2026-04-08 15:31:42.983773','2026-04-08 15:31:42.983773'),(236,37,'752年','55','被召回长安任职，拜开府仪同三司，后任右羽林大将军，天宝十四年晋封密云郡公','《旧唐书·高仙芝传》：十载，入朝，拜开府仪同三司，……以仙芝为右羽林大将军。十四载，封密云郡公。','唐天宝十一年',7,'2026-04-08 15:31:42.984116','2026-04-08 15:31:42.984116'),(237,37,'755年','58','安禄山发动安史之乱，唐玄宗任命高仙芝为讨贼副元帅，率临时募集的军队出潼关，屯守陕郡抵御叛军','《旧唐书·高仙芝传》：十四载，安禄山反，……以仙芝为副元帅，领飞骑、彍骑及朔方等兵，又出禁中钱召募关辅市人，号十一万，号曰‘天武军’。十二月，屯于陕州。','唐天宝十四年',8,'2026-04-08 15:31:42.984231','2026-04-08 15:31:42.984231'),(238,37,'756年1月','59','因监军边令诚索贿不成，向唐玄宗诬告其弃守陕地、克扣军粮，玄宗不察真伪，派边令诚至潼关将高仙芝与封常清一同斩首','《旧唐书·高仙芝传》：边令诚又诬奏仙芝、常清逗留桡败，……宣敕斩仙芝。仙芝曰：‘我退，罪也，死不敢辞。然以我为盗颉资粮，诬也。’……遂下斩之。','唐天宝十四年十二月',9,'2026-04-08 15:31:42.984366','2026-04-08 15:31:42.984366'),(239,37,'约698年','1','出生于高句丽贵族后裔家庭，父亲高舍鸡为唐朝安西都护府资深将领','《旧唐书·高仙芝传》：高仙芝，本高句丽人也。父舍鸡，初从河西军，累劳至四镇十将、诸卫将军。','武周圣历元年',0,'2026-04-08 15:31:42.985110','2026-04-08 15:31:42.985110'),(240,38,'752','45','安西节度使王正见病逝，接任安西副大都护、摄御史中丞，持节充安西四镇节度等副大使、知节度事，成为安西唐军最高统帅','《旧唐书·封常清传》：十一载，正见死，乃以常清为安西副大都护，摄御史中丞，持节充安西四镇节度、经略、支度、营田副大使，知节度事。','唐天宝十一载',5,'2026-04-08 15:39:18.997655','2026-04-08 15:39:18.997655'),(241,38,'747','40','随高仙芝远征小勃律，攻破连云堡，平定小勃律国，切断吐蕃西进通道，因功升任朝散大夫，主管四镇仓库、屯田、甲仗等事务，高仙芝出征时常以其为留后主持军政','《旧唐书·封常清传》：天宝六年，从仙芝破小勃律。十二月，仙芝代夫蒙灵詧为安西节度使，便奏常清为庆王府录事参军，充节度判官，赐紫金鱼袋。寻加朝散大夫，专知四镇仓库、屯田、甲仗、支度、营田事。仙芝每出征讨，常令常清知留后事。','唐天宝六载',3,'2026-04-08 15:39:18.998452','2026-04-08 15:39:18.998452'),(242,38,'741','34','时年三十余，孤贫无依，见四镇都知兵马使高仙芝出行仪仗威严，连续数十日投牒请求充当侍从，起初因貌丑脚跛被拒，最终被收入高仙芝麾下为侍从','《旧唐书·封常清传》：外祖死，常清孤贫，年三十馀，属夫蒙灵詧为四镇节度使，将军高仙芝为都知兵马使，颇有材能，每出军，奏傔从三十馀人，衣服鲜明。常清慨然发愤，投牒请预一傔。常清细瘦目类脚短而跛，仙芝见其貌寝，不纳。常清自尔候仙芝出入，晨夕不离其门，凡数十日，仙芝不得已，补为傔。','唐开元二十九年',1,'2026-04-08 15:39:18.998614','2026-04-08 15:39:18.998614'),(243,38,'748','41','任安西留后期间严明法度，杖杀骄横无礼的高仙芝乳母之子郑德诠，又连斩两名犯事大将，全军震惧，军纪整肃','《旧唐书·封常清传》：仙芝乳母子郑德诠已为郎将，威望动三军，德诠见常清出其门，素易之，走马突常清而去。常清至使院，命人密召德诠，杖六十，面仆地，曳出。及见常清，遂无一言，常清亦不之谢。又有二大将犯令，又斩之，军中莫不股栗。','唐天宝七载',4,'2026-04-08 15:39:18.999056','2026-04-08 15:39:18.999056'),(244,38,'约708','1','生于蒲州猗氏，幼时因外祖获罪被流放安西，跟随外祖在胡城南门生活，自幼跟随外祖读书，广览文史典籍','《旧唐书·封常清传》：封常清，蒲州猗氏人也。外祖犯罪流安西效力，守胡城南门，颇读书，每坐常清于城门楼上，教其读书，多所历览。','唐景龙二年',0,'2026-04-08 15:39:18.999185','2026-04-08 15:39:18.999185'),(245,38,'742','35','跟随高仙芝率两千骑兵平定达奚部叛乱，私下撰写的捷报精准契合高仙芝的作战谋划，因此崭露头角，被授任叠州地下戍主，后升任节度判官','《旧唐书·封常清传》：会达奚部落背叛，自黑山北向，西趣碎叶，敕灵詧邀击之。灵詧使仙芝以二千骑自副城向北，至绫岭下，遇贼，击之，达奚行远，人马疲，擒杀略尽。常清于幕中潜作捷书，具言次舍井泉，遇贼形势，克获谋略，事颇精审。仙芝所欲言，无不周悉，仙芝大骇异之。遂知名，以功授叠州地下戍主，便以为判官。','唐天宝元年',2,'2026-04-08 15:39:18.999281','2026-04-08 15:39:18.999281'),(246,38,'753','46','率军远征大勃律国，采用段秀实建议识破敌军诱敌之计，大破伏兵，迫降大勃律而还，因功升任御史大夫','《旧唐书·封常清传》：十二年，东征大勃律，至菩萨劳城，前锋屡捷，常清乘胜逐之。斥候府果毅段秀实谏曰：\'虏兵羸而屡北，诱我也，请搜左右山林。\'常清从之，果获伏兵，遂大破之，受降而还。其年，加御史大夫，仍与一子五品官，赐第一区，亡父母皆赠封爵。','唐天宝十二载',6,'2026-04-08 15:39:18.999372','2026-04-08 15:39:18.999372'),(247,38,'755年11月','48','入朝觐见唐玄宗，恰逢安史之乱爆发，主动请缨前往东都洛阳募兵抵御叛军，被任命为范阳、平卢节度使，旬日之内募兵六万，整备防务抵御叛军','《旧唐书·封常清传》：十四载，入朝，十一月，谒玄宗于华清宫。时禄山反，玄宗以常清为范阳节度，俾令募兵以讨之。常清乘驿赴东京召募，旬日得兵六万，皆佣保市井之流。乃斫断河阳桥，于东京为固守之备。','唐天宝十四载',8,'2026-04-08 15:39:18.999495','2026-04-08 15:39:18.999495'),(248,38,'754','47','入朝奏事，兼任北庭都护、伊西节度使，统管安西、北庭两大都护府，成为唐王朝西域地区最高军政长官','《旧唐书·封常清传》：十三载，入朝，摄御史大夫，封常清权知北庭都护，持节充伊西节度等使。','唐天宝十三载',7,'2026-04-08 15:39:18.999815','2026-04-08 15:39:18.999815'),(249,38,'755年12月','48','所募新军缺乏训练，不敌安禄山叛军精锐，先后在武牢、葵园、上东门连败，洛阳陷落，率残部向西撤退至陕郡与高仙芝会合','《旧唐书·封常清传》：十二月，禄山渡河，陷陈留，入罂子谷，凶威转炽。先锋至葵园，常清使骁骑与柘羯逆战，杀贼数十百人。贼大军继至，常清退入上东门，又战不利，贼鼓噪于四城门入，杀掠人吏。常清又战于都亭驿，不胜。退守宣仁门，又败。乃从苑西坏墙西走。','唐天宝十四载',9,'2026-04-08 15:39:18.999940','2026-04-08 15:39:18.999940'),(250,38,'756年1月','49','与高仙芝商议后放弃无险可守的陕郡，退守潼关整备防务，被监军边令诚诬陷克扣军粮、临阵脱逃，与高仙芝一同被唐玄宗下令处斩，临刑前仍上表劝谏玄宗切勿轻视叛军，从容赴死，时人皆以为冤','《旧唐书·封常清传》：常清既败，至陕郡，遇高仙芝，具以贼势告之：\'贼锋不可当，潼关无兵，若贼豕突入关，则京师危矣。陕不可守，不如退而据潼关，挫其锋势。\'仙芝然之，乃督士卒徐退。俄而敕使边令诚至，宣敕斩常清。常清将死，表请玄宗勿轻贼，言毕饮刃而死，时人莫不冤之。','唐天宝十五载/至德元载',10,'2026-04-08 15:39:19.003348','2026-04-08 15:39:19.003348'),(251,39,'747年','44','王忠嗣被李林甫诬告下狱，哥舒翰入朝为其申辩，言辞恳切声泪俱下，使王忠嗣得以免死贬官，本人也受玄宗赏识，接任陇右节度使','《旧唐书》：及忠嗣为李林甫所构，追赴京师，因大狱，敕令推问。翰叩头随之，言词慷慨，声泪俱下，言忠嗣之冤。玄宗感寤，始宽忠嗣之罪，贬为汉阳太守。其年，以翰代忠嗣为陇右节度支度营田副大使，知节度事。','唐天宝六载',2,'2026-04-08 15:44:33.288087','2026-04-08 15:44:33.288087'),(252,39,'748年','45','率军于青海修筑神威军，击败来犯吐蕃，又在青海中龙驹岛修筑应龙城，自此吐蕃不敢再进犯青海区域','《旧唐书》：七载，筑神威军于青海上，吐蕃至，攻破之。又筑城于青海中龙驹岛，有白龙见，遂名为应龙城，吐蕃屏迹不敢近青海。','唐天宝七载',3,'2026-04-08 15:44:33.288207','2026-04-08 15:44:33.288207'),(253,39,'约704年','1','出身突骑施哥舒部落，父祖皆为唐廷官员，家世豪富，自幼任侠仗义，喜好饮酒赌博','《旧唐书》：哥舒翰，突骑施首领哥舒部落之裔也。蕃人多以部落称姓，因以为氏。祖沮，左清道率。父道元，安西副都护，世居安西。翰家富于财，倜傥任侠，好然诺，纵蒲酒。','武周长安四年',0,'2026-04-08 15:44:33.288355','2026-04-08 15:44:33.288355'),(254,39,'742年左右','40岁左右','遭父丧后客居长安，因遭长安县尉轻慢，愤而前往河西从军，先事节度使王倕，后归入陇右节度使王忠嗣麾下任衙将','《旧唐书》：年四十，遭父丧，三年客居京师，为长安尉不礼，慨然发愤折节，仗剑之河西。初事节度使王倕，倕攻新城，使翰经略，三军无不震慑。后节度使王忠嗣补为衙将。','唐天宝初年',1,'2026-04-08 15:44:33.288516','2026-04-08 15:44:33.288516'),(255,39,'755年','52','入朝途中突发风疾，返回长安居家养病；同年安史之乱爆发，封常清、高仙芝战败被杀后，玄宗起用哥舒翰为兵马副元帅，率二十万大军驻守潼关抵御叛军','《旧唐书》：十四载，翰入朝，道得风疾，遂废疾于家。及安禄山反，封常清、高仙芝相次败绩，玄宗诛之，因召翰入朝，拜皇太子先锋兵马元帅，领蕃、汉兵二十万，守潼关。','唐天宝十四载',6,'2026-04-08 15:44:33.288798','2026-04-08 15:44:33.288798'),(256,39,'757年','54','安禄山之子安庆绪兵败撤出洛阳前，将哥舒翰等三十余名被俘唐将全部杀害','《旧唐书》：安庆绪之败，渡河走，翰与程千里、卢奕等凡三十余人，并为贼所害。','唐至德二载',8,'2026-04-08 15:44:33.288901','2026-04-08 15:44:33.288901'),(257,39,'753年','50','率军攻占吐蕃洪济、大莫门等城，收复黄河九曲故地，设置多座军城，因功进封凉国公，不久再加封西平郡王，兼河西节度使','《旧唐书》：十二载，翰又击吐蕃，收洪济、大莫门等城，收九曲故地，置神策、宛秀、保宁等军于九曲。其年，进封凉国公，食实封三百户，加河西节度使，寻封西平郡王。','唐天宝十二载',5,'2026-04-08 15:44:33.289262','2026-04-08 15:44:33.289262'),(258,39,'749年','46','奉玄宗诏令率十万大军攻打吐蕃石堡城，付出惨重伤亡后攻克该城，俘虏吐蕃守军四百余人，因功加特进、摄御史大夫','《旧唐书》：天宝八载，上以石堡城为吐蕃所据，侵扰河右，敕翰领河东、朔方群牧等十万众以攻之。不旬日而拔之。上录其功，拜特进、鸿胪员外卿，与一子五品官，加摄御史大夫。','唐天宝八载',4,'2026-04-08 15:44:33.288671','2026-04-08 15:44:33.288671'),(259,39,'756年','53','唐玄宗在杨国忠撺掇下多次遣使催促出战，哥舒翰被迫领兵出关，在灵宝西原被叛军将领崔乾祐击败，二十万大军几乎全军覆没，本人被部将劫持投降安禄山','《旧唐书》：杨国忠恐翰图己，言于玄宗，促翰出战。翰不得已，引师出关。六月八日，与贼交绥，为贼所败，翰急走入关，得入者仅八千余人。九日，贼将崔乾祐进攻潼关，翰为帐下火拔归仁执以降贼。','唐天宝十五载/至德元载',7,'2026-04-08 15:44:33.289421','2026-04-08 15:44:33.289421'),(260,40,'740','40','隐居山东徂徕山，与孔巢父、韩准、裴政、张叔明、陶沔交游，终日酣饮纵歌，时人称为“竹溪六逸”','《旧唐书·李白传》：少与鲁中诸生孔巢父、韩沔、裴政、张叔明、陶沔等隐于徂徕山，酣歌纵酒，时号‘竹溪六逸’。','唐开元二十八年',3,'2026-04-08 15:47:12.436535','2026-04-08 15:47:12.436535'),(261,40,'701','1','出生于西域碎叶城，为凉武昭王李暠（唐兴圣皇帝）后裔，其家族隋末因故迁居西域','《新唐书·李白传》：李白，字太白，兴圣皇帝九世孙。其先隋末以罪徙西域。','武周长安元年',0,'2026-04-08 15:47:12.436650','2026-04-08 15:47:12.436650'),(262,40,'718','18','隐居蜀中大匡山苦读，修习纵横术与剑术，行侠仗义，轻财好施，游历蜀地周边州郡','《新唐书·李白传》：喜纵横术，击剑，为任侠，轻财重施。','唐开元六年',2,'2026-04-08 15:47:12.436743','2026-04-08 15:47:12.436743'),(263,40,'705','5','随家族自西域迁回中原，定居绵州昌隆县（今四川江油），开始启蒙求学','《新唐书·李白传》：神龙初，遁还，客巴西。','唐神龙元年',1,'2026-04-08 15:47:12.436825','2026-04-08 15:47:12.436825'),(264,40,'757','57','永王李璘被朝廷认定谋反，兵败后李白受牵连系狱浔阳，得郭子仪以官爵相赎，免死改判流放夜郎','《新唐书·李白传》：璘起兵，逃还彭泽，璘败，当诛。初，白游并州，见郭子仪，奇之。子仪尝犯法，白为救免。至是子仪请解官以赎，有诏长流夜郎。','唐至德二载',7,'2026-04-08 15:47:12.436923','2026-04-08 15:47:12.436923'),(265,40,'742','42','经贺知章、玉真公主举荐，被唐玄宗召入长安，召见金銮殿，获玄宗亲为调羹的礼遇，诏授供奉翰林，为宫廷撰写乐章文书','《新唐书·李白传》：往见贺知章，知章见其文，叹曰：‘子，谪仙人也！’言于玄宗，召见金銮殿，论当世事，奏颂一篇。帝赐食，亲为调羹，有诏供奉翰林。','唐天宝元年',4,'2026-04-08 15:47:12.437014','2026-04-08 15:47:12.437014'),(266,40,'762','62','投奔当涂县令、族叔李阳冰，同年病卒于当涂，传世诗作近千首','《旧唐书·李白传》：后遇赦得还，竟以饮酒过度，醉死于宣城。《新唐书·李白传》：代宗立，以左拾遗召，而白已卒，年六十余。','唐宝应元年',9,'2026-04-08 15:47:12.437093','2026-04-08 15:47:12.437093'),(267,40,'759','59','朝廷因旱灾颁布大赦令，流放途中行至白帝城的李白遇赦，顺江而下返回江夏','《新唐书·李白传》：会赦，还寻阳。','唐乾元二年',8,'2026-04-08 15:47:12.437242','2026-04-08 15:47:12.437242'),(268,40,'756','56','安史之乱爆发后避居江南，受邀加入永王李璘幕府，参与平叛事务','《旧唐书·李白传》：禄山之乱，玄宗幸蜀，在途以永王璘为江淮兵马都督、扬州节度大使，白在宣州谒见，遂辟为从事。','唐至德元载',6,'2026-04-08 15:47:12.437348','2026-04-08 15:47:12.437348'),(269,40,'744','44','因醉酒令高力士脱靴，遭权贵谗毁，自知不为朝堂所容，恳求还山，玄宗赐金放还；同年在洛阳与杜甫、高适相识，三人同游梁宋，怀古论诗','《新唐书·李白传》：白尝侍帝，醉，使高力士脱靴。力士素贵，耻之，擿其诗以激杨贵妃，帝欲官白，妃辄沮止。白自知不为亲近所容，益骜放不自修，恳求还山，帝赐金放还。《旧唐书·杜甫传》：甫尝从李白、高适过汴州，酒酣登吹台，慷慨怀古，人莫测也。','唐天宝三载',5,'2026-04-08 15:47:12.439539','2026-04-08 15:47:12.439539'),(270,41,'751','40','进献《三大礼赋》，获唐玄宗赏识，命其待制集贤院，取得参列选序的入仕资格','《旧唐书·杜甫传》：天宝末，献《三大礼赋》，玄宗奇之，召试文章，待制集贤院。','唐天宝十载',5,'2026-04-08 15:54:45.943996','2026-04-08 15:54:45.943996'),(271,41,'759','48','关中地区爆发严重饥荒，民生凋敝，杜甫弃华州司功参军之职，携家眷辗转秦州、同谷等地，年底入蜀抵达成都','《新唐书·杜甫传》：关辅饥，辄弃官去，客秦州，负薪采橡栗自给。流落剑南，结庐成都西郭。','唐乾元二年',9,'2026-04-08 15:54:45.944124','2026-04-08 15:54:45.944124'),(272,41,'744','33','在洛阳与被赐金放还的李白相遇，随后二人同高适结伴漫游梁宋，登临怀古，饮酒酬唱，结下深厚友谊','《新唐书·杜甫传》：尝从白及高适过汴州，酒酣登吹台，慷慨怀古，人莫测也。','唐天宝三载',3,'2026-04-08 15:54:45.944228','2026-04-08 15:54:45.944228'),(273,41,'712','1','生于河南巩县，出身京兆杜氏分支，祖父为初唐著名诗人杜审言，家学渊源深厚','《旧唐书·杜甫传》：杜甫，字子美，本襄阳人，后徙河南巩县。曾祖依艺，位终巩令。祖审言，位终膳部员外郎，自有传。父闲，终奉天令。','唐先天元年',0,'2026-04-08 15:54:45.944355','2026-04-08 15:54:45.944355'),(274,41,'736','25','赴洛阳参加进士科考试落第，随后漫游齐赵，度过一段裘马轻狂的快意生活，创作《望岳》等名篇','《新唐书·杜甫传》：举进士不中第，客齐赵间，豪放旷达，时人莫之许也。','唐开元二十四年',2,'2026-04-08 15:54:45.944479','2026-04-08 15:54:45.944479'),(275,41,'757','46','冒死逃离长安奔赴凤翔肃宗行在，被授为右拾遗；不久因上疏为战败的宰相房琯求情触怒肃宗，被贬为华州司功参军','《旧唐书·杜甫传》：甫自京师宵遁赴河西，谒肃宗于彭原郡，拜右拾遗。房琯布衣时与甫善，时琯为宰相，请自帅师讨贼，帝许之。其年十月，琯兵败于陈涛斜。明年春，琯罢相。甫上疏言琯有才，不宜罢免。肃宗怒，贬琯为刺史，出甫为华州司功参军。','唐至德二载',8,'2026-04-08 15:54:45.944613','2026-04-08 15:54:45.944613'),(276,41,'756','45','叛军攻陷长安，杜甫在奔赴肃宗行在途中被叛军俘获，押解至长安，软禁期间目睹叛军暴行，创作《春望》《哀江头》等忧国名篇','《新唐书·杜甫传》：安禄山乱，天子入蜀，甫避走三川。肃宗立，自鄜州羸服欲奔行在，为贼所得。','唐至德元载',7,'2026-04-08 15:54:45.944728','2026-04-08 15:54:45.944728'),(277,41,'731','20','开启漫游生涯，先游历吴越多地，饱览江南山川风物，积累大量创作素材','《新唐书·杜甫传》：甫少贫不自振，客吴越、齐赵间。','唐开元十九年',1,'2026-04-08 15:54:45.944840','2026-04-08 15:54:45.944840'),(278,41,'747','36','参加玄宗下诏征集贤才的制举考试，因宰相李林甫操纵“野无遗贤”闹剧，所有应试者全部落第，杜甫仕途严重受挫','《资治通鉴·卷二百一十五》：上欲广求天下之士，命通一艺以上皆诣京师。李林甫恐草野之士对策斥言其奸恶，建言：‘举人多卑贱愚聩，恐有俚言污浊圣听。’乃令郡县长官精加试练，灼然超绝者，具名送省，委尚书覆试，御史中丞监之，取名实相副者闻奏。既而至者皆试以诗、赋、论，遂无一人及第者，林甫乃上表贺野无遗贤。','唐天宝六载',4,'2026-04-08 15:54:45.944969','2026-04-08 15:54:45.944969'),(279,41,'760','49','在亲友资助下于成都浣花溪畔建成草堂，结束长期辗转流离的生活，在此居住近四年，创作《蜀相》《茅屋为秋风所破歌》等大量名篇','《旧唐书·杜甫传》：甫于成都浣花里种竹植树，结庐枕江，纵酒啸咏，与田夫野老相狎荡，无拘检。','唐上元元年',10,'2026-04-08 15:54:45.945085','2026-04-08 15:54:45.945085'),(280,41,'755','44','被授予右卫率府兵曹参军一职，掌管兵器门禁、官员宿卫等事务；同年安史之乱爆发，杜甫携家眷逃往鄜州避难','《旧唐书·杜甫传》：授京兆府兵曹参军。十五载，禄山陷京师，肃宗征兵灵武。','唐天宝十四载',6,'2026-04-08 15:54:45.949743','2026-04-08 15:54:45.949743'),(281,41,'764','53','好友严武出任剑南节度使，表荐杜甫为节度参谋、检校工部员外郎，赐绯鱼袋，后世因此称其为“杜工部”','《旧唐书·杜甫传》：上元二年冬，黄门侍郎、郑国公严武镇成都，奏为节度参谋、检校尚书工部员外郎，赐绯鱼袋。','唐广德二年',11,'2026-04-08 15:54:45.951776','2026-04-08 15:54:45.951776'),(282,41,'765','54','严武病逝，杜甫在成都失去依靠，携家眷乘舟沿江东下，辗转漂泊渝州、忠州、夔州等地，在夔州居住期间创作颇丰，存诗达四百余首','《新唐书·杜甫传》：武卒，甫无所依，乃游东蜀依高适。既至而适卒。是岁，崔宁杀郭英乂，杨子琳攻西川，蜀中大乱，甫以其家避乱荆、楚，扁舟下峡。','唐永泰元年',12,'2026-04-08 15:54:45.951911','2026-04-08 15:54:45.951911'),(283,41,'770','59','漂泊湘水流域时遭遇洪水，被困耒阳数日，后在由潭州前往岳阳的湘江舟中病逝，终年五十九岁','《旧唐书·杜甫传》：甫尝游岳庙，为暴水所阻，旬日不得食。耒阳聂令知之，自棹舟迎甫而还。永泰二年，啖牛肉白酒，一夕而卒于耒阳，时年五十九。','唐大历五年',13,'2026-04-08 15:54:45.952013','2026-04-08 15:54:45.952013'),(284,42,'563','15','随父参与北周与北齐的邙山之战，提前预判周军败局，令左右换装撤离，不久周军果然大败，军事天赋显露，被父亲看重','《隋书·史万岁传》：年十五，值周、齐战于邙山，万岁时从父入军，旗鼓正相望，万岁令左右趣治装急去。俄而周师大败，其父由是奇之。','北周保定三年',1,'2026-04-08 16:01:14.752699','2026-04-08 16:01:14.752699'),(285,42,'577','29','北周攻灭北齐，父亲史静战死，史万岁以忠臣之子身份被授开府仪同三司，袭爵太平县公','《隋书·史万岁传》：武帝平齐，其父静战没，万岁以忠臣子，拜开府仪同三司，袭爵太平县公。','北周建德六年',2,'2026-04-08 16:01:14.752948','2026-04-08 16:01:14.752948'),(286,42,'549','1','生于京兆杜陵史氏，父亲史静为北周沧州刺史，史万岁自幼习武，擅长骑射，熟读兵书，精通占卜候气之术','《隋书·史万岁传》：史万岁，京兆杜陵人也。父静，周沧州刺史。万岁少英武，善骑射，骁捷若飞。好读兵书，兼精占候。','西魏大统十五年',0,'2026-04-08 16:01:14.753091','2026-04-08 16:01:14.753091'),(287,42,'580','32','随梁士彦征讨尉迟迥叛乱，阵前射落雁阵第三只雁震慑三军，邺城之战中单骑冲阵杀敌数十人扭转战局，平叛后因功升上大将军','《隋书·史万岁传》：尉迟迥之乱也，万岁从梁士彦击之。军次冯翊，见群雁飞来，万岁谓士彦曰：‘请射行中第三者。’既射之，应弦而落，三军莫不悦服。及与迥军相遇，每战先登。邺城之阵，官军稍却，万岁谓左右曰：‘事急矣，吾当破之。’于是驰马奋击，杀数十人，众亦齐力，官军乃振。及迥平，以功拜上大将军。','北周大象二年',3,'2026-04-08 16:01:14.753258','2026-04-08 16:01:14.753258'),(288,42,'583','35','受尔朱绩谋反案牵连，被除去官籍，发配敦煌为戍卒，期间常单骑深入突厥境内掠夺羊马，名震突厥','《隋书·史万岁传》：尔朱绩以谋反伏诛，万岁颇相关涉，坐除名，配敦煌为戍卒。','隋开皇三年',4,'2026-04-08 16:01:14.753677','2026-04-08 16:01:14.753677'),(289,42,'589','41','参与隋灭陈之战，因战功加授上开府','《隋书·史万岁传》：平陈之役，又以功加上开府。','隋开皇九年',6,'2026-04-08 16:01:14.753855','2026-04-08 16:01:14.753855'),(290,42,'583','35','主动投效秦州总管窦荣定参与对突厥作战，阵前单挑斩杀突厥骁将，突厥大惊撤军请和，战后被授上仪同，领车骑将军','《隋书·史万岁传》：其后突厥犯塞，上令窦荣定率众讨之。万岁诣辕门请自效。荣定素闻其名，见而大悦。因遣人谓突厥曰：‘士卒何罪过，令杀之，但当各遣一壮士决胜负耳。’突厥许诺，因遣一骑挑战。荣定遣万岁出应之，万岁驰斩其首而还。突厥大惊，不敢复战，遂引军而去。由是拜上仪同，领车骑将军。','隋开皇三年',5,'2026-04-08 16:01:14.754051','2026-04-08 16:01:14.754051'),(291,42,'590','42','以行军总管身份随杨素平定江南高智慧叛乱，率部二千翻山越海，前后七百余战转战千里，以竹筒传信通报战况，平息东南叛乱后还朝拜左领军将军','《隋书·史万岁传》：及高智慧等作乱江南，以行军总管从杨素击之。万岁率众二千，自东阳别道而进，逾岭越海，攻陷溪洞不可胜数。前后七百余战，转斗千余里，寂无声问者十旬，远近皆以万岁为没。万岁以水陆阻绝，信使不通，乃置书竹筒中，浮之于水。汲者得之，以言于素。素大悦，上其事。高祖嗟叹，赐其家钱十万，还拜左领军将军。','隋开皇十年',7,'2026-04-08 16:01:14.754118','2026-04-08 16:01:14.754118'),(292,42,'597','49','任行军总管征讨南宁州爨翫叛乱，转战千余里破三十余部，俘虏二万余人，受爨翫贿赂将其放走，次年爨翫复反，史万岁受贿事发被除名为民','《隋书·史万岁传》：先是，南宁夷爨玩来降，拜昆州刺史，既而复叛。遂以万岁为行军总管，率众击之。入自蜻蛉川，经弄冻，次小勃弄、大勃弄，至于南中。贼前后屯据要害，万岁皆击破之。渡西二河，入渠滥川，行千余里，破其三十余部，虏获男女二万余口。玩阴有二心，不欲诣阙，因赂万岁以金宝，万岁于是舍玩而还。明年，爨玩复反，蜀王秀奏万岁受赂纵贼，致生边患，上令穷治其事，事皆验，罪当死，左仆射高颎等求情，于是除名为民。','隋开皇十七年',8,'2026-04-08 16:01:14.754281','2026-04-08 16:01:14.754281'),(293,42,'599','51','恢复官爵，被任命为河州刺史，兼任行军总管防备突厥入侵','《隋书·史万岁传》：岁余，复官爵。寻拜河州刺史，复领行军总管以备胡。','隋开皇十九年',9,'2026-04-08 16:01:14.754337','2026-04-08 16:01:14.754337'),(294,42,'600','52','率部出塞迎击突厥达头可汗，在大斤山大破突厥，追击数百里歼敌数千，杨素隐瞒其战功，史万岁在朝堂为将士请功时言语冲撞隋文帝，被当场暴杀于朝堂','《隋书·史万岁传》：开皇末，突厥达头可汗犯塞，万岁率部出塞，至大斤山，与虏相遇，达头闻其名惧而引去，万岁驰追百余里，击大破之，斩数千级，逐北入碛数百里而还。杨素害其功，隐其战功，又谮其谒见废太子杨勇，上怒，召万岁，万岁言将士有功被抑，词气愤厉，上大怒，令左右暴杀之。','隋开皇二十年',10,'2026-04-08 16:01:14.761137','2026-04-08 16:01:14.761137'),(295,43,'538','1','生于河南东垣将门之家，为北周骠骑大将军韩雄之子，原名韩擒豹，因勇武过人后改名韩擒虎','《隋书·韩擒虎传》：韩擒字子通，河南东垣人也，后家新安。父雄，周骠骑大将军、洛虞等八州刺史。','西魏大统四年',0,'2026-04-08 16:05:12.122496','2026-04-08 16:05:12.122496'),(296,43,'548','11','因容貌魁岸、胆略出众，被西魏丞相宇文泰赏识，特许其与自己的子侄一同交游','《隋书·韩擒虎传》：擒少慷慨，以胆略见称，容貌魁岸，有雄杰之表。周太祖见而异之，令与诸子游集。','西魏大统十四年',1,'2026-04-08 16:05:12.122601','2026-04-08 16:05:12.122601'),(297,43,'577','40','随军参与灭北齐之战，成功劝降北齐金墉城守将独孤永业，因功授永州刺史','《隋书·韩擒虎传》：及平齐之役，擒说下齐独孤永业于金墉，拜永州刺史。','北周建德六年',3,'2026-04-08 16:05:12.122687','2026-04-08 16:05:12.122687'),(298,43,'563','26','父亲韩雄去世，袭爵新义郡公，此后多次随军征战，屡立军功，历任都督、新安太守等职','《隋书·韩擒虎传》：父雄卒，袭爵新义郡公，稍迁都督、新安太守。','北周保定三年',2,'2026-04-08 16:05:12.122811','2026-04-08 16:05:12.122811'),(299,43,'581','44','隋文帝杨坚受禅建隋，因韩擒虎文武兼备、声名素著，任命其为庐州总管，委以平陈重任','《隋书·韩擒虎传》：高祖受禅，阴有并江南之志，以擒有文武才用，夙著声名，于是拜为庐州总管，委以平陈之任，甚为敌人所惮。','隋开皇元年',4,'2026-04-08 16:05:12.122919','2026-04-08 16:05:12.122919'),(300,43,'589','52','隋大举伐陈，任先锋率五百人夜渡采石，半日攻克姑孰，随后直入建康朱雀门，率先俘虏陈后主陈叔宝，平定南陈','《隋书·韩擒虎传》：开皇九年，大举伐陈，以擒为先锋。擒率五百人宵济，袭采石，守者皆醉，擒遂取之。进攻姑熟，半日而拔，次于新林。……陈人大骇，其将樊巡、鲁世真、田瑞等相继降之。……及平陈，擒坐于朱雀门，执陈主叔宝。','隋开皇九年',5,'2026-04-08 16:05:12.122990','2026-04-08 16:05:12.122990'),(301,43,'589','52','回朝后与贺若弼争功，隋文帝称二人俱为平陈上勋，进位上柱国，赐物八千段，后因有司弹劾其放纵士卒淫污陈宫，未加封爵食邑','《隋书·韩擒虎传》：及至京师，与贺若弼争功于上前。上曰：\"二将俱合上勋。\"于是进位上柱国，赐物八千段。有司劾擒放纵士卒，淫污陈宫，坐此不加爵邑。','隋开皇九年',6,'2026-04-08 16:05:12.123089','2026-04-08 16:05:12.123089'),(302,43,'591','54','突厥使者入朝，隋文帝向使者指认韩擒虎为“执陈国天子者”，韩擒虎厉色相对，突厥使者惶恐不敢仰视','《隋书·韩擒虎传》：其后突厥来朝，上谓曰：\"汝闻江南有陈国天子乎？\"对曰：\"闻之。\"上命左右引突厥诣擒前，曰：\"此是执得陈国天子者。\"擒厉然顾之，突厥惶恐，不敢仰视。','隋开皇十一年',7,'2026-04-08 16:05:12.123713','2026-04-08 16:05:12.123713'),(303,43,'592','55','病重去世，享年五十五岁，生前留下“生为上柱国，死作阎罗王”的典故，后世民间将其奉为阎罗王之一','《隋书·韩擒虎传》：无何，其邻母见擒门下仪卫甚盛，有同王者，母异而问之。其中人曰：\"我来迎王。\"忽然不见。又有人疾笃，忽惊走至擒家曰：\"我欲谒王。\"左右问曰：\"何王也？\"答曰：\"阎罗王。\"擒子弟欲挞之，擒止之曰：\"生为上柱国，死作阎罗王，斯亦足矣。\"因寝疾，数日竟卒，时年五十五。','隋开皇十二年',8,'2026-04-08 16:05:12.123874','2026-04-08 16:05:12.123874'),(304,44,'578','35','周武帝去世，周宣帝宇文赟即位，此前贺若弼曾与大臣乌丸轨私下议论太子宇文赟无帝王之才，宣帝即位后诛杀乌丸轨，贺若弼因坚决否认曾发表相关言论，逃过一死','《隋书·贺若弼传》：“武帝尝问弼曰：‘太子居位何如？’对曰：‘皇太子德声未闻，未见其阙。’帝默然。弼既退，乌丸轨责弼曰：‘平生言论，无所不道，今者对至尊，何得乃尔翻覆？’弼曰：‘此公之过也。太子，国之储副，岂易所言。发言有差，便至灭族。本谓公密陈臧否，何得遂至昌言。’轨默然。后轨竟被诛，弼亦免祸。”','北周宣政元年',2,'2026-04-08 16:14:30.836091','2026-04-08 16:14:30.836091'),(305,44,'544','1','贺若弼出生，为北周将领贺若敦之子，河南洛阳鲜卑人，少时胸有大志，骁勇善骑射，博览群书，在北周境内颇有声名','《隋书·贺若弼传》：“贺若弼，字辅伯，河南洛阳人也。父敦，以武烈知名，仕周为金州总管，宇文护忌而害之。弼少慷慨有大志，骁勇便弓马，解属文，博涉书记，有重名于当世。”','西魏大统十年',0,'2026-04-08 16:14:30.836202','2026-04-08 16:14:30.836202'),(306,44,'565','22','父亲贺若敦因口出怨言被权臣宇文护逼令自尽，临刑前用锥刺贺若弼舌头出血，告诫他要慎言，不可重蹈自己因言获罪的覆辙，同时嘱托他完成自己平定江南的遗愿','《隋书·贺若弼传》：“敦临刑，呼弼谓之曰：‘吾必欲平江南，然此心不果，汝当成吾志。且吾以舌死，汝不可不思。’因引锥刺弼舌出血，诫以慎口。”','北周保定五年',1,'2026-04-08 16:14:30.836671','2026-04-08 16:14:30.836671'),(307,44,'579','36','跟随行军元帅韦孝宽攻打南陈淮南地区，屡献奇策，攻克数十座城池，因功拜寿州刺史，改封襄邑县公','《隋书·贺若弼传》：“及韦孝宽之南伐也，弼为行军总管，攻陈淮南地，频献奇策，所向披靡，拜寿州刺史，改封襄邑县公。”','北周大象元年',3,'2026-04-08 16:14:30.836878','2026-04-08 16:14:30.836878'),(308,44,'581','38','杨坚受禅建立隋朝，素有平江南之志，经宰相高颎举荐，任命贺若弼为吴州总管，镇守广陵，委以平陈重任，贺若弼开始积极筹备伐陈军务','《隋书·贺若弼传》：“高祖受禅，阴有并江南之志，访可任者。高颎曰：‘朝臣之内，文武才干，无若贺若弼者。’高祖曰：‘公得之矣。’于是拜弼为吴州总管，委以平陈之事，弼忻然以为己任。”','隋开皇元年',4,'2026-04-08 16:14:30.837217','2026-04-08 16:14:30.837217'),(309,44,'589','46','隋大举伐陈，贺若弼率部从广陵偷渡长江，攻克京口，继而在蒋山与陈军主力死战，大破陈军，生擒陈朝骠骑将军萧摩诃，为平陈立下首功；战后因提前出兵与韩擒虎争功，在文帝面前互斥对方过失，不久进位上柱国，封宋国公','《隋书·贺若弼传》：“开皇九年，大举伐陈，以弼为行军总管。……弼以大军济江，陈人弗之觉也。袭陈南徐州，拔之，执其刺史黄恪。……于是弼自北道邀其走路，陈将鲁广达、周智安、任蛮奴、田瑞、樊毅、孔范、萧摩诃等以劲兵拒战。……弼督厉将士，殊死战，遂大破之。麾下执摩诃以送弼，……弼以功加位上柱国，进爵宋国公，食邑三千户。”','隋开皇九年',6,'2026-04-08 16:14:30.837327','2026-04-08 16:14:30.837327'),(310,44,'587','44','贺若弼向隋文帝进献平陈十策，得到文帝高度赞许，获赐宝刀，平陈筹备工作基本完成','《隋书·贺若弼传》：“弼献取陈十策，上称善，赐以宝刀。”','隋开皇七年',5,'2026-04-08 16:14:30.837414','2026-04-08 16:14:30.837414'),(311,44,'604','61','隋文帝驾崩，隋炀帝杨广即位，贺若弼因过往狂傲言行，更加被炀帝疏远猜忌，未获任何任用','《隋书·贺若弼传》：“炀帝即位，尤被疏忌。”','隋仁寿四年',8,'2026-04-08 16:14:30.837802','2026-04-08 16:14:30.837802'),(312,44,'607','64','贺若弼随炀帝北巡榆林，炀帝设可容纳数千人的大帐接待突厥启民可汗，贺若弼与高颎、宇文弼等人私下议论炀帝此举太过奢侈，被人告发，炀帝以诽谤朝政之罪将其诛杀，其妻女没为官奴，家族子弟流放边境','《隋书·贺若弼传》：“大业三年，从驾北巡，至榆林。帝时为大帐，其下可坐数千人，召突厥启民可汗飨之。弼以为大侈，与高颎、宇文弼等私议得失，为人所奏，竟坐诛，时年六十四。妻子为官奴婢，群从徙边。”','隋大业三年',9,'2026-04-08 16:14:30.837898','2026-04-08 16:14:30.837898'),(313,44,'592','49','贺若弼自恃平陈功高，不满官位在高颎、杨素之下，常口出怨言，被免官下狱，文帝念其功劳免其死罪，贬为庶民，一年后恢复其爵位，但不再授予实职','《隋书·贺若弼传》：“弼自谓功名出朝臣之右，每以宰相自许。既而杨素为右仆射，弼仍为将军，甚不平，形于言色，由是免官，弼怨望愈甚。后数年，下弼狱……公卿奏弼怨望，罪当死。上惜其功，于是除名为民。岁余，复其爵位。上亦忌之，不复任使。”','隋开皇十二年',7,'2026-04-08 16:14:30.837979','2026-04-08 16:14:30.837979'),(314,45,'约581年','1','生于工匠家庭，自幼跟随长辈学习土木营造技艺，在桥梁建造领域积累了丰富的实践经验','正史无李春出生相关记载，据其主持修建安济桥的时间推定生于隋开皇初年','隋开皇元年',0,'2026-04-08 16:28:34.468783','2026-04-08 16:28:34.468783'),(315,45,'隋大业年间','壮年','主持建造赵郡洨河安济桥（后世称赵州桥），首创敞肩式石拱桥建造工艺，既提升了桥梁泄洪能力，又减轻了桥体自重，该桥留存至今已有1400余年历史','《全唐文·卷三百二十九·安济桥铭》：赵郡洨河石桥，隋匠李春之迹也，制造奇特，人不知其所以为。','隋朝晚期',1,'2026-04-08 16:28:34.469056','2026-04-08 16:28:34.469056'),(316,45,'唐初','晚年','其主持建造的安济桥历经隋末战乱、洨河洪水冲击仍完好无损，投入民用通行，李春本人继续从事营造相关工作，其造桥技艺为后世工匠所传承','正史无李春晚年活动相关记载，据赵州桥历代修葺、使用的相关史料推定','唐武德至贞观年间',2,'2026-04-08 16:28:34.469251','2026-04-08 16:28:34.469251'),(317,46,'约545年','1','出生于渤海郡（今山东惠民一带），自幼展现出突出的绘画天赋','《历代名画记·卷八》：「展子虔，渤海人也。」','东魏武定三年',0,'2026-04-08 16:52:17.667726','2026-04-08 16:52:17.667726'),(318,46,'隋大业年间','老年','创作青绿山水名作《游春图》，以青绿勾填法描绘山川人物，打破此前山水仅作为人物背景的格局，开创了独立山水画的创作范式','《宣和画谱·卷一》：「展子虔善画台阁，写江山远近之势尤工，故咫尺有千里之趣。今御府所藏二十有一：……游春图一。」','隋大业年间',4,'2026-04-08 16:52:17.668531','2026-04-08 16:52:17.668531'),(319,46,'北齐河清至天统年间','青年','入仕北齐，以擅画人物、车马、楼阁、山水闻名于北方，画技被时人推崇','《历代名画记·卷八》：「（展子虔）历北齐、周、隋。」','北齐中期',1,'2026-04-08 16:52:17.668849','2026-04-08 16:52:17.668849'),(320,46,'北周建德六年（577年）后','壮年','北周灭北齐后入仕北周，绘画名气传播至关中地区，士人多以收藏其画作为荣','《后画录》：「展子虔，尤善台阁、人马、山川，咫尺千里，触物留情，备皆妙绝。」','北周晚期',2,'2026-04-08 16:52:17.669014','2026-04-08 16:52:17.669014'),(321,46,'约618年','约74岁','于隋末唐初去世，其青绿山水技法深刻影响了唐代李思训、李昭道父子的山水画创作，被后世尊为「青绿山水鼻祖」、「唐画之祖」','《画鉴》：「展子虔画山水，大抵唐李将军父子多宗之，世人谓展子虔画为唐画之祖。」','隋大业十四年/唐武德元年',5,'2026-04-08 16:52:17.669310','2026-04-08 16:52:17.669310'),(322,46,'隋开皇年间','壮年至老年','入隋后被授为朝散大夫、帐内都督，奉诏为长安、洛阳多地寺院绘制壁画，所作壁画与董伯仁齐名，并称「董展」','《历代名画记·卷八》：「在隋为朝散大夫帐内都督，与董伯仁同自河北入隋，一曰董展。」','隋开皇年间',3,'2026-04-08 16:52:17.669621','2026-04-08 16:52:17.669621'),(323,47,'690','67','正式废黜唐睿宗李旦，登基称帝，改国号为周，改名为武曌，成为中国历史上唯一的正统女皇帝','《旧唐书·则天皇后本纪》：“天授元年九月九日，革唐命，改国号为周。改元为天授，大赦天下，赐酺七日。乙酉，加尊号曰圣神皇帝，降皇帝为皇嗣，赐姓武氏。”','武周天授元年',10,'2026-04-08 16:55:46.042183','2026-04-08 16:55:46.042183'),(324,47,'649','26','唐太宗李世民驾崩，武则天依后宫嫔妃例，入长安感业寺为尼','《旧唐书·则天皇后本纪》：“及太宗崩，遂为尼，居感业寺。”','唐贞观二十三年',2,'2026-04-08 16:55:46.042352','2026-04-08 16:55:46.042352'),(325,47,'624','1','生于利州（一说长安），父为唐开国功臣武士彟，母为弘农杨氏','《新唐书·则天皇后本纪》：“则天顺圣皇后武氏讳曌，并州文水人也。父士彟，隋大业末为鹰扬府队正。高祖行军于汾、晋，每休止其家。义旗初起，从平京城。贞观中，累迁工部尚书、荆州都督，封应国公。”','唐武德七年',0,'2026-04-08 16:55:46.042469','2026-04-08 16:55:46.042469'),(326,47,'637','14','唐太宗闻其貌美有才，召入后宫，封为才人，赐号“武媚”','《旧唐书·则天皇后本纪》：“初，则天年十四时，太宗闻其美容止，召入宫，立为才人。”','唐贞观十一年',1,'2026-04-08 16:55:46.042588','2026-04-08 16:55:46.042588'),(327,47,'655','32','唐高宗废王皇后、萧淑妃为庶人，正式册立武则天为皇后','《旧唐书·高宗本纪》：“永徽六年冬十月己酉，废皇后王氏为庶人，立昭仪武氏为皇后，大赦天下。”','唐永徽六年',4,'2026-04-08 16:55:46.042716','2026-04-08 16:55:46.042716'),(328,47,'660','37','唐高宗患风眩症无法处理政务，命武则天协理朝政，武氏开始全面参与国事，权柄渐重','《旧唐书·则天皇后本纪》：“显庆五年，高宗苦风眩，百司奏事，或使皇后决之。后性明敏，涉猎文史，处事皆称旨，由是始委以政事，权与人主侔矣。”','唐显庆五年',5,'2026-04-08 16:55:46.042819','2026-04-08 16:55:46.042819'),(329,47,'684','61','废中宗李显为庐陵王，改立豫王李旦为睿宗，幽禁李旦于别宫，改元光宅，改东都洛阳为神都，为称帝做准备','《旧唐书·则天皇后本纪》：“嗣圣元年春正月，废皇帝为庐陵王，幽于别所。立豫王轮为皇帝，令居于别殿。大赦天下，改元文明。九月，大赦天下，改元为光宅，改东都为神都。”','唐嗣圣元年/光宅元年',9,'2026-04-08 16:55:46.042936','2026-04-08 16:55:46.042936'),(330,47,'664','41','唐高宗与宰相上官仪密谋废后，事泄后武则天诛杀上官仪，此后高宗每临朝，武后垂帘听政，时人并称“二圣”','《新唐书·则天皇后本纪》：“麟德元年，后诬宰相上官仪谋逆，杀之，朝士坐与仪交游谪死者甚众。自是上每视事，后垂帘于后，政无大小皆与闻之，天下大权，悉归中宫，天子拱手而已。”','唐麟德元年',6,'2026-04-08 16:55:46.043245','2026-04-08 16:55:46.043245'),(331,47,'674','51','唐高宗改称天皇，武则天改称天后，正式确立“二圣”共治格局','《旧唐书·高宗本纪》：“咸亨五年八月壬辰，皇帝称天皇，皇后称天后，改元上元，大赦天下。”','唐上元元年',7,'2026-04-08 16:55:46.043335','2026-04-08 16:55:46.043335'),(332,47,'651','28','唐高宗李治入感业寺进香时与武则天重逢，将其重召入宫，不久拜为昭仪','《新唐书·则天皇后本纪》：“高宗幸感业寺，见而悦之，复召入宫。未几，拜昭仪，进号宸妃。”','唐永徽二年',3,'2026-04-08 16:55:46.044007','2026-04-08 16:55:46.044007'),(333,47,'705','82','宰相张柬之等发动神龙政变，诛杀张易之、张昌宗兄弟，武则天被迫传位太子李显，复唐国号；同年十一月，武则天于上阳宫驾崩，遗诏去帝号，称“则天大圣皇后”，与高宗合葬乾陵','《旧唐书·则天皇后本纪》：“神龙元年春正月，上传皇帝位于皇太子，徙居上阳宫。戊申，皇帝上尊号曰则天大圣皇帝。冬十一月壬寅，则天崩于上阳宫之仙居殿，年八十三，谥曰则天大圣皇后。”','武周神龙元年/唐神龙元年',11,'2026-04-08 16:55:46.048325','2026-04-08 16:55:46.048325'),(334,47,'683','60','唐高宗驾崩，太子李显继位为中宗，尊武则天为皇太后，临朝称制总揽朝政','《旧唐书·则天皇后本纪》：“弘道元年十二月，大帝崩，皇太子显即位，尊天后为皇太后。既将篡夺，是日自临朝称制。”','唐弘道元年',8,'2026-04-08 16:55:46.050275','2026-04-08 16:55:46.050275'),(335,48,'685','1','生于东都洛阳，为唐睿宗李旦第三子，母为窦德妃','《旧唐书·玄宗本纪》：玄宗至道大圣大明孝皇帝讳隆基，睿宗第三子也。母曰昭成顺圣皇后窦氏。垂拱元年秋八月戊寅，生于东都。','唐垂拱元年',0,'2026-04-08 17:02:39.334771','2026-04-08 17:02:39.334771'),(336,48,'708','24','出任潞州别驾，暗中结交豪杰、笼络禁军势力，积蓄政治资本','《旧唐书·玄宗本纪》：景龙二年四月，兼潞州别驾。有德政，州境肃然。','唐景龙二年',2,'2026-04-08 17:02:39.334876','2026-04-08 17:02:39.334876'),(337,48,'693','9','生母窦德妃被武则天诬陷杀害，李隆基被降封临淄王，出阁就藩','《旧唐书·玄宗本纪》：长寿二年腊月丁卯，降封临淄王，出阁。《新唐书·后妃传》：长寿二年，为户婢团儿诬谮与肃明皇后厌蛊咒诅，正月二日，朝则天皇后于嘉豫殿，既退而同时遇害。','武周长寿二年',1,'2026-04-08 17:02:39.334989','2026-04-08 17:02:39.334989'),(338,48,'710','26','联合太平公主发动唐隆政变，诛杀韦后、安乐公主及其党羽，拥立睿宗李旦复位，被册立为皇太子','《旧唐书·玄宗本纪》：景龙四年，中宗暴崩，韦后临朝称制。上乃与太平公主谋之，庚子夜率部入宫平乱，比晓内外皆定。睿宗即位，乃立为皇太子。','唐景云元年',3,'2026-04-08 17:02:39.335094','2026-04-08 17:02:39.335094'),(339,48,'712','28','睿宗李旦禅位，李隆基正式登基为帝，此时太平公主仍掌控核心朝政大权','《旧唐书·睿宗本纪》：先天元年八月庚子，传位于皇太子，自称太上皇帝，三品已上除授及大刑狱并自决之，皇帝决三品已下除授及徒罪。','唐先天元年',4,'2026-04-08 17:02:39.335326','2026-04-08 17:02:39.335326'),(340,48,'725','41','封禅泰山，此时唐朝国力鼎盛、万邦来朝，史称开元盛世','《旧唐书·玄宗本纪》：十三年冬十月东封泰山，十一月祀昊天上帝于岱宗，御帐殿受朝贺，大赦天下，赐酺七日。是时海内富安，行者虽万里不持寸兵。','唐开元十三年',6,'2026-04-08 17:02:39.335779','2026-04-08 17:02:39.335779'),(341,48,'713','29','发动先天政变，赐死太平公主，尽诛其党羽，正式掌握全部皇权，改元开元，开启开元之治','《旧唐书·玄宗本纪》：太平公主与宰臣窦怀贞等谋逆，上率亲信定计诛之，公主逃入山寺，三日乃出，赐死于家。十二月庚寅朔，大赦天下，改元为开元。','唐开元元年',5,'2026-04-08 17:02:39.335921','2026-04-08 17:02:39.335921'),(342,48,'736','52','名相张九龄被罢相，李林甫接任中书令，朝政逐渐转向昏暗','《旧唐书·张九龄传》：二十四年，迁尚书右丞相，罢知政事。后宰执每荐引公卿，上必问：‘风度得如九龄否？’','唐开元二十四年',7,'2026-04-08 17:02:39.336066','2026-04-08 17:02:39.336066'),(343,48,'737','53','听信武惠妃谗言，赐死太子李瑛、鄂王李瑶、光王李琚；同年武惠妃去世，后召寿王妃杨玉环入宫','《新唐书·玄宗诸子传》：帝意决，乃诏：‘太子瑛、鄂王瑶、光王琚同恶均罪，并废为庶人。’寻赐死城东驿。《旧唐书·杨贵妃传》：或奏玄琰女姿色冠代，宜蒙召见。时妃衣道士服，号曰太真，既进见，玄宗大悦。','唐开元二十五年',8,'2026-04-08 17:02:39.336236','2026-04-08 17:02:39.336236'),(344,48,'742','58','改元天宝，后续重用杨国忠等佞臣，朝政日益腐败，边镇节度使势力不断坐大','《旧唐书·玄宗本纪》：天宝元年春正月丁未朔，大赦天下，改元，常赦不原咸赦除之。','唐天宝元年',9,'2026-04-08 17:02:39.336362','2026-04-08 17:02:39.336362'),(345,48,'755','71','范阳节度使安禄山以讨伐杨国忠为名起兵叛乱，安史之乱爆发，河北诸地迅速沦陷','《旧唐书·安禄山传》：十四载十一月，反于范阳，矫称奉恩命以兵讨逆贼杨国忠。以诸蕃马步十五万，夜半行，平明食，日六十里。','唐天宝十四载',10,'2026-04-08 17:02:39.339879','2026-04-08 17:02:39.339879'),(346,48,'756','72','潼关失守后出逃长安，行至马嵬坡时六军哗变，杨国忠被诛杀，杨贵妃被赐死；同年太子李亨在灵武即位，遥尊其为太上皇','《旧唐书·玄宗本纪》：丙申，至马嵬驿，诸卫顿军不进，杨国忠为兵士所诛，乃赐贵妃自尽。是月，皇太子即皇帝位于灵武，奉尊上为太上皇。','唐天宝十五载/至德元载',11,'2026-04-08 17:02:39.341820','2026-04-08 17:02:39.341820'),(347,48,'762','78','在长安太极宫神龙殿病逝，谥号至道大圣大明孝皇帝，庙号玄宗，葬于泰陵','《旧唐书·玄宗本纪》：宝应元年四月甲寅，崩于神龙殿，年七十八。群臣上谥曰至道大圣大明孝皇帝，庙号玄宗。广德元年三月辛酉，葬于泰陵。','唐宝应元年',12,'2026-04-08 17:02:39.341999','2026-04-08 17:02:39.341999'),(348,49,'628','1','生于长安东宫丽正殿，为唐太宗李世民第九子，生母为文德皇后长孙氏','《旧唐书·高宗本纪》：太宗第九子也。母曰文德顺圣皇后长孙氏。以贞观二年六月，生于东宫之丽正殿。','唐贞观二年',0,'2026-04-08 17:38:23.076876','2026-04-08 17:38:23.076876'),(349,49,'649','22','唐太宗李世民驾崩，李治于长安太极殿即皇帝位','《旧唐书·高宗本纪》：二十三年五月己巳，太宗崩。壬申，即皇帝位于太极殿，时年二十二。','唐贞观二十三年',3,'2026-04-08 17:38:23.077030','2026-04-08 17:38:23.077030'),(350,49,'643','16','太子李承乾谋反被废，魏王李泰获罪被黜，经长孙无忌、房玄龄等重臣拥立，被册立为皇太子','《新唐书·高宗本纪》：十七年，太子承乾废，魏王泰坐罪夺嫡，太宗与长孙无忌、房玄龄、李勣等定策，立晋王为皇太子。','唐贞观十七年',2,'2026-04-08 17:38:23.077194','2026-04-08 17:38:23.077194'),(351,49,'655','28','力排众议废王皇后为庶人，册立武昭仪（武则天）为皇后，打击关陇贵族集团势力','《旧唐书·高宗本纪》：六年冬十月己酉，废皇后王氏为庶人，立昭仪武氏为皇后，大赦天下。','唐永徽六年',7,'2026-04-08 17:38:23.077392','2026-04-08 17:38:23.077392'),(352,49,'631','4','受封晋王，遥领并州都督一职','《旧唐书·高宗本纪》：五年，封晋王。七年，遥授并州都督。','唐贞观五年',1,'2026-04-08 17:38:23.077538','2026-04-08 17:38:23.077538'),(353,49,'永徽年间','23-28','延续太宗时期施政纲领，重用长孙无忌、褚遂良等贤臣，吏治清明、民生安定，史称“永徽之治”','《资治通鉴·唐纪十五》：永徽之政，百姓阜安，有贞观之遗风。','唐永徽年间',5,'2026-04-08 17:38:23.077667','2026-04-08 17:38:23.077667'),(354,49,'665','38','率文武百官、宗亲命妇及突厥、于阗、波斯、天竺等国使节赴泰山封禅，为唐朝首次由帝后共同参与的封禅大典','《旧唐书·高宗本纪》：麟德二年冬十月丁卯，将封泰山，发自东都。三年春正月戊辰朔，车驾至泰山顿。庚午，祀昊天上帝于封祀坛，以高祖、太宗配享。','唐麟德二年',10,'2026-04-08 17:38:23.078488','2026-04-08 17:38:23.078488'),(355,49,'652','25','册立陈王李忠为皇太子，诏命编纂《唐律疏议》并颁行天下，这是中国现存最早最完整的成文封建法典','《旧唐书·刑法志》：永徽三年，诏广召解律人条义疏奏闻，勒成三十卷，十月甲辰，颁行天下。','唐永徽三年',6,'2026-04-08 17:38:23.077803','2026-04-08 17:38:23.077803'),(356,49,'650','23','改元永徽，册立王妃王氏为皇后，大赦天下','《新唐书·高宗本纪》：永徽元年正月辛丑，改元。丙午，立妃王氏为皇后。','唐永徽元年',4,'2026-04-08 17:38:23.078790','2026-04-08 17:38:23.078790'),(357,49,'657','30','派苏定方率军攻灭西突厥，擒获沙钵罗可汗阿史那贺鲁，唐朝势力范围拓展至中亚地区','《新唐书·突厥传》：显庆二年，苏定方击贺鲁，破之，擒贺鲁，西突厥亡，分其地置濛池、昆陵二都护府。','唐显庆二年',8,'2026-04-08 17:38:23.079041','2026-04-08 17:38:23.079041'),(358,49,'660','33','罹患风眩症，头重目眩难以处理政务，开始令武皇后协助裁决朝政，武后权力逐渐与皇帝比肩','《旧唐书·则天皇后本纪》：显庆五年，高宗风眩头重，目不能视，百司奏事，上或使皇后决之。后性明敏，涉猎文史，处事皆称旨。由是始委以政事，权与人主侔矣。','唐显庆五年',9,'2026-04-08 17:38:23.085808','2026-04-08 17:38:23.085808'),(359,49,'683','56','在洛阳贞观殿驾崩，庙号高宗，谥号天皇大帝，与武皇后合葬于乾陵','《旧唐书·高宗本纪》：弘道元年十二月丁巳，诏改永淳二年为弘道元年。是夕，上崩于东都贞观殿，时年五十六。谥曰天皇大帝，庙号高宗。文明元年八月庚寅，葬于乾陵。','唐弘道元年',13,'2026-04-08 17:38:23.088759','2026-04-08 17:38:23.088759'),(360,49,'668','41','派李勣率军攻灭高句丽，攻克平壤，生擒高句丽王高藏，设置安东都护府管辖高句丽旧地，唐朝疆域达到极盛','《旧唐书·高宗本纪》：总章元年九月癸巳，司空、英国公勣破高丽，拔平壤城，擒其王高藏及其大臣男建等以归。其地皆降，分置都督府及州四十二，县一百，置安东都护府以统之。','唐总章元年',11,'2026-04-08 17:38:23.088999','2026-04-08 17:38:23.088999'),(361,49,'674','47','李治自称“天皇”，武皇后称“天后”，二人并称“二圣”，共同临朝理政','《新唐书·则天皇后本纪》：上元元年，高宗号天皇，皇后亦号天后，天下谓之“二圣”。','唐上元元年',12,'2026-04-08 17:38:23.089230','2026-04-08 17:38:23.089230'),(362,50,'665','1','生于东都洛阳，为唐高宗李治与武则天幼女，自幼极受双亲宠爱','《旧唐书·外戚传》：\"太平公主者，高宗少女也。以则天所生，特承恩宠。\"','唐麟德二年',0,'2026-04-09 10:52:30.608161','2026-04-09 10:52:30.608161'),(363,50,'678','14','吐蕃遣使请求迎娶太平公主，高宗与武则天不愿爱女远嫁，遂修建太平观令其正式出居，以此回绝吐蕃和亲请求','《旧唐书·外戚传》：\"时吐蕃上表请尚主，则天不欲令嫁外蕃，乃立太平观，以主为观主，如方士薰戒，以拒和亲事。\"','唐仪凤三年',2,'2026-04-09 10:52:30.612427','2026-04-09 10:52:30.612427'),(364,50,'681','17','下嫁城阳公主之子薛绍，婚礼于万年县廨举办，规模极为盛大，沿途燎炬烤焦路边槐树','《资治通鉴·唐纪十八》：\"秋，七月，公主适薛氏，自兴安门南至宣阳坊西，燎炬相属，夹路槐木多死。\"','唐永隆二年',3,'2026-04-09 10:52:30.615426','2026-04-09 10:52:30.615426'),(365,50,'671','7','外祖母荣国夫人杨氏去世，为给外祖母祈福出家为女道士，道号\"太平\"','《新唐书·诸帝公主传》：\"荣国夫人死，后丐主为道士，以幸冥福。\"','唐咸亨二年',1,'2026-04-09 10:52:30.615896','2026-04-09 10:52:30.615896'),(366,50,'688','24','薛绍长兄薛𫖮参与李唐宗室谋反，薛绍受到连坐，被武则天杖责后饿死狱中，太平公主守寡','《新唐书·诸帝公主传》：\"会𫖮参与琅邪王冲反，绍坐与连谋，杖一百，饿死于狱。\"','唐垂拱四年',4,'2026-04-09 10:52:30.616301','2026-04-09 10:52:30.616301'),(367,50,'697','33','联合武氏诸王告发酷吏来俊臣谋反罪证，来俊臣被武则天下令处死，武周酷吏政治告一段落','《资治通鉴·唐纪二十二》：\"太平公主及武氏诸王共发其罪，下狱，有司处以极刑。\"','周万岁通天二年',6,'2026-04-09 10:52:30.617159','2026-04-09 10:52:30.617159'),(368,50,'690','26','武则天改唐为周称帝前，将太平公主改嫁武氏族人武攸暨，为促成婚事毒杀武攸暨原配妻子，此后太平公主开始参与朝政决策','《旧唐书·外戚传》：\"绍死，则天私杀攸暨之妻以配主焉。\"','周天授元年',5,'2026-04-09 10:52:30.617584','2026-04-09 10:52:30.617584'),(369,50,'713','49','与已登基为帝的李隆基权争激化，图谋废黜李隆基，事泄后李隆基发动先天政变，太平公主逃入山寺三日后出，被赐死于家中，家产被抄没，财货堆积可匹敌皇家府库','《资治通鉴·唐纪二十六》：\"太平公主逃入山寺，三日乃出，赐死于家，公主诸子及党与死者数十人。籍其家，财货山积，珍奇宝物，侔于御府。\"','唐先天二年',9,'2026-04-09 10:52:30.627002','2026-04-09 10:52:30.627002'),(370,50,'705','41','联合宰相张柬之等人发动神龙政变，诛杀武则天宠臣张昌宗、张易之兄弟，拥立中宗李显复位，因功晋封镇国太平公主，实封五千户，获开府置官属特权','《资治通鉴·唐纪二十四》：\"太平公主预诛二张功，进号镇国太平公主，食实封五千户。\"','唐神龙元年',7,'2026-04-09 10:52:30.626416','2026-04-09 10:52:30.626416'),(371,50,'710','46','中宗被韦后、安乐公主毒杀后，联合临淄王李隆基发动唐隆政变，诛杀韦后集团，拥立睿宗李旦复位，实封累加至万户，权势达到顶峰，朝廷大政多受其干预，宰相等重臣多出其门下','《旧唐书·外戚传》：\"进封万户，加实封通前一万户。军国大政，事必参决，如不朝谒，则宰臣就第议其可否。\"','唐景龙四年',8,'2026-04-09 10:52:30.626129','2026-04-09 10:52:30.626129'),(372,51,'705','42','神龙政变爆发，武则天退位，唐中宗李显复位，婉儿被拜为昭容，专门掌管草拟皇帝诏令，深受信任，母亲郑氏被封为沛国夫人','《旧唐书·后妃传上》：中宗即位，又令专掌制命，深被信任。寻拜为昭容，封其母郑氏为沛国夫人。','唐中宗神龙元年',3,'2026-04-09 11:01:27.621721','2026-04-09 11:01:27.621721'),(373,51,'664','1','出生于官宦世家，祖父上官仪为西台侍郎，因起草废黜武则天的诏书获罪，父上官庭芝与祖父一同被诛，婉儿尚在襁褓中，随母亲郑氏被没入掖庭为奴','《旧唐书·后妃传上》：中宗上官昭容，名婉儿，西台侍郎仪之孙也。父庭芝，与仪同被诛，婉儿时在襁褓，随母配入掖庭。','唐高宗麟德元年',0,'2026-04-09 11:01:27.622521','2026-04-09 11:01:27.622521'),(374,51,'677','14','被武则天召见，当场考核文辞，婉儿挥笔立就、文意通顺词藻华美，武则天惊叹其才，免除其奴婢身份，命其掌管宫中诏命','《新唐书·后妃传上》：年十四，武后召见，有所制作，若素构。','唐高宗仪凤二年',1,'2026-04-09 11:01:27.622668','2026-04-09 11:01:27.622668'),(375,51,'696','33','因忤逆武则天旨意论罪当诛，武则天怜惜其才学不忍处死，仅处以黥面之刑，此后对其更为重用，命其参决百官奏表，政务多有参与','《旧唐书·后妃传上》：则天时，婉儿忤旨当诛，则天惜其才不杀，但黥其面而已。自圣历已后，百司表奏，多令参决。','武周万岁通天元年',2,'2026-04-09 11:01:27.622799','2026-04-09 11:01:27.622799'),(376,51,'708','45','劝说中宗扩建昭文馆，增设学士员额，征召大臣名儒入馆，多次主持宫廷赐宴赋诗活动，常代中宗、韦后及长宁、安乐二公主作诗，作品辞藻华丽，时人争相传诵','《新唐书·后妃传上》：婉儿劝帝侈大书馆，增学士员，引大臣名儒充选。数赐宴赋诗，君臣赓和，婉儿常代帝及后、长宁安乐二主，众篇并作，而采丽益新。','唐中宗景龙二年',5,'2026-04-09 11:01:27.622928','2026-04-09 11:01:27.622928'),(377,51,'707','44','节愍太子李重俊不满韦后、武三思专权，发动兵变诛杀武三思父子，随后叩肃章门索要上官婉儿，婉儿称太子意在依次索要皇后、皇帝，激怒中宗与韦后登玄武楼避乱，太子最终兵败被杀','《旧唐书·后妃传上》：时婉儿既与武三思淫乱，每下制敕，多因事推尊武氏而排抑皇家。节愍太子深恶之，及举兵，至肃章门，扣阁索婉儿。婉儿大言曰：‘观其此意，即当次索皇后以及大家。’帝与后遂怒，以婉儿自随，登玄武门楼以避兵锋，俄而事定。','唐中宗景龙元年',4,'2026-04-09 11:01:27.623298','2026-04-09 11:01:27.623298'),(378,51,'713','身故后','唐玄宗李隆基感念其才学，下令收集上官婉儿的全部诗文，编为《上官昭容集》二十卷，诏令宰相张说为文集作序','《新唐书·后妃传上》：玄宗开元初，哀次其文，诏张说为之序。','唐玄宗开元初年',7,'2026-04-09 11:01:27.623748','2026-04-09 11:01:27.623748'),(379,51,'710','47','李隆基发动唐隆政变诛杀韦后、安乐公主一党，上官婉儿率宫人持烛迎接禁军，出示此前与太平公主合拟的中宗遗诏以证明自己效忠李唐，仍被李隆基下令斩于旗下','《资治通鉴·唐纪二十五》：及隆基入宫，昭容执烛帅宫人迎之，以制草示刘幽求。幽求为之言，隆基不许，斩于旗下。','唐睿宗景云元年',6,'2026-04-09 11:01:27.623436','2026-04-09 11:01:27.623436'),(380,52,'790','1','生于河南福昌（今河南宜阳）昌谷，为唐高祖李渊叔父郑王李亮后裔，父李晋肃曾任地方属官，家道已中落','《新唐书·文艺传下》：李贺，字长吉，系出郑王后。父晋肃，边上从事。','唐德宗贞元六年',0,'2026-04-09 11:12:52.006336','2026-04-09 11:12:52.006336'),(381,52,'796','7','天资聪慧，七岁即可独立创作诗文，文坛名宿韩愈、皇甫湜听闻其名后上门探访，李贺当场作《高轩过》，文笔老练如宿构，自此名动京师','《新唐书·文艺传下》：贺七岁能辞章，韩愈、皇甫湜始闻未信，过其家，使贺赋诗，援笔辄就如素构，自目曰《高轩过》，二人大惊，自是有名。','唐德宗贞元十二年',1,'2026-04-09 11:12:52.006596','2026-04-09 11:12:52.006596'),(382,52,'811','22','凭借宗室后裔身份获得举荐，任从九品上阶奉礼郎，负责朝廷祭祀、朝会等活动的礼仪安排，任职期间居长安，目睹官场黑暗，创作了诸多抒发怀才不遇、批判现实的诗作','《旧唐书·文苑传下》：李贺，字长吉，宗室郑王之后。父晋肃，边上从事。后为奉礼郎。','唐宪宗元和六年',3,'2026-04-09 11:12:52.007217','2026-04-09 11:12:52.007217'),(383,52,'810','21','赴长安准备参加进士科考试，遭妒忌其才者诽谤，称其父名“晋肃”的“晋”与“进士”的“进”同音，需避家讳不得应试，韩愈作《讳辩》为其据理力争仍未能破除舆论限制，李贺最终放弃应试','《新唐书·文艺传下》：以父名晋肃不肯举进士，愈为作《讳辩》，然卒亦不就举。','唐宪宗元和五年',2,'2026-04-09 11:12:52.007418','2026-04-09 11:12:52.007418'),(384,52,'813','24','因官职低微难以施展抱负，加之自幼体弱多病，任职三年后辞去奉礼郎职务，返回昌谷故居休养，期间曾游历潞州等地，创作了大量咏怀、记游、反映民生疾苦的作品','《新唐书·文艺传下》：贺为人纤瘦，通眉，长指爪，能疾书。每旦日出，骑弱马，从小奚奴，背古锦囊，遇所得，书投囊中。未始先立题然后为诗，如它人牵合程课者。及暮归，足成之。非大醉、吊丧日率如此。母见所书多，即怒曰：‘是儿要呕出心乃已耳。’','唐宪宗元和八年',4,'2026-04-09 11:12:52.007679','2026-04-09 11:12:52.007679'),(385,52,'816','27','病情加重，在昌谷故居去世，年仅二十七岁，其诗作风格奇谲瑰丽，后世称其为“诗鬼”，与李白、李商隐并称“唐代三李”','《新唐书·文艺传下》：辞尚奇诡，所得皆惊迈，绝去翰墨畦径，当时无能效者。乐府数十篇，云韶诸工皆合之弦管。卒年二十七。','唐宪宗元和十一年',5,'2026-04-09 11:12:52.008388','2026-04-09 11:12:52.008388'),(386,53,'797','26','登吏部取士科，授太子校书郎，正式进入仕途','《新唐书》：\"久之，登吏部取士科，授太子校书。\"','唐德宗贞元十三年',2,'2026-04-09 11:15:07.655731','2026-04-09 11:15:07.655731'),(387,53,'793','22','进士及第，同年登博学宏辞科，与柳宗元同榜，才名初显','《旧唐书》：\"贞元九年，擢进士第，又登宏辞科。\"','唐德宗贞元九年',1,'2026-04-09 11:15:07.655898','2026-04-09 11:15:07.655898'),(388,53,'800','29','被淮南节度使杜佑辟为掌书记，随府居扬州，执掌文书事务，深受器重','《旧唐书》：\"淮南节度使杜佑表为掌书记，待之甚厚。\"','唐德宗贞元十六年',3,'2026-04-09 11:15:07.656083','2026-04-09 11:15:07.656083'),(389,53,'772','1','生于苏州嘉兴，祖籍中山，家族世代以儒学传家，自幼受家学熏陶，聪慧好学','《旧唐书》：\"刘禹锡，字梦得，彭城人。祖云，父溆，仕历州县令佐，世以儒学称。\"','唐代宗大历七年',0,'2026-04-09 11:15:07.656248','2026-04-09 11:15:07.656248'),(390,53,'802','31','调任京兆府渭南县主簿，不久擢升监察御史，与韩愈、柳宗元同署为官，交游密切','《新唐书》：\"调渭南主簿，擢监察御史，与韩愈、柳宗元善，交游最密。\"','唐德宗贞元十八年',4,'2026-04-09 11:15:07.656378','2026-04-09 11:15:07.656378'),(391,53,'元和年间（806-814）','35-43','居朗州司马贬所十年，依当地民歌体例创作《竹枝词》等作品，诗文多讽喻时事，抒发谪居愤懑，其创作的俚辞在武陵夷地广为流传','《旧唐书》：\"禹锡在朗州十年，唯以文章吟咏，陶冶情性。蛮俗好巫，每淫祠鼓舞，必歌俚辞。禹锡或从事于其间，乃依骚人之作，为新辞以教巫祝。故武陵溪洞间夷歌，率多禹锡之辞也。\"','唐宪宗元和年间',6,'2026-04-09 11:15:07.657163','2026-04-09 11:15:07.657163'),(392,53,'805','34','参与王叔文主导的永贞革新，任屯田员外郎、判度支盐铁案，推行罢宫市、免进奉等革新措施；革新失败后，先贬连州刺史，途中再贬朗州司马','《旧唐书》：\"及王叔文用事，引禹锡及柳宗元入禁中，与之图议，言无不从。转屯田员外郎、判度支盐铁案。叔文败，坐贬连州刺史，在道，贬朗州司马。\"','唐顺宗永贞元年',5,'2026-04-09 11:15:07.657386','2026-04-09 11:15:07.657386'),(393,53,'815','44','与柳宗元等同被召回京，因作《戏赠看花诸君子》涉讥刺权贵，执政不悦，初贬播州刺史，经裴度以其母年高求情，改授连州刺史','《旧唐书》：\"元和十年，自武陵召还，宰相复欲置之郎署。时禹锡作《游玄都观咏看花君子诗》，语涉讥刺，执政不悦，复出为播州刺史。诏下，御史中丞裴度奏曰：‘禹锡有母年高，今为郡蛮方，西南绝域，往复万里，如何与母偕行。如母子异方，便为永诀。臣恐伤陛下孝理之风。伏请屈法，稍移近处。’……乃改授连州刺史。\"','唐宪宗元和十年',7,'2026-04-09 11:15:07.657621','2026-04-09 11:15:07.657621'),(394,53,'832','61','出任苏州刺史，任上革除弊政，安抚民生，因政绩优异获朝廷赐紫金鱼袋','《新唐书》：\"太和中，累迁礼部郎中、集贤直学士，出为苏州刺史，以政绩闻，赐金紫服。\"','唐文宗太和六年',10,'2026-04-09 11:15:07.658869','2026-04-09 11:15:07.658869'),(395,53,'836','65','授太子宾客，分司东都洛阳，世称“刘宾客”，期间与白居易、裴度等交游唱和，多作闲适抒怀诗作，与白居易并称“刘白”','《旧唐书》：\"开成初，复为太子宾客分司，俄授同州刺史。辞疾不拜，寻改检校礼部尚书、太子宾客分司。\"','唐文宗开成元年',11,'2026-04-09 11:15:07.659032','2026-04-09 11:15:07.659032'),(396,53,'842','71','七月病逝于洛阳，朝廷追赠户部尚书','《旧唐书》：\"会昌二年七月卒，时年七十一，赠户部尚书。\"','唐武宗会昌二年',12,'2026-04-09 11:15:07.663098','2026-04-09 11:15:07.663098'),(397,53,'821','50','自连州刺史调任夔州刺史，期间续写《竹枝词》数十篇，在巴楚一带民间广为传唱','《新唐书》：\"去连州，徙夔州，作《竹枝辞》数十篇，于是武陵、巴楚间民多歌之。\"','唐穆宗长庆元年',8,'2026-04-09 11:15:07.664887','2026-04-09 11:15:07.664887'),(398,53,'826','55','自和州刺史任上被召回洛阳，拜主客郎中，重游玄都观，作《再游玄都观》，以“前度刘郎今又来”句明不屈之志','《旧唐书》：\"宝历二年，自和州刺史征还，拜主客郎中。禹锡衔前事未已，复作《游玄都观诗序》曰：‘予贞元二十一年为尚书屯田员外郎，时此观中未有花木。是岁出牧连州，寻贬朗州司马。居十年，召还京师，人人皆言有道士手植红桃满观，如烁晨霞，遂有诗以志一时之事。旋又出牧，于今十有四年，得为主客郎中。重游兹观，荡然无复一树，唯兔葵燕麦动摇于春风，因再题二十八字，以俟后游。’其前篇有‘玄都观里桃千树，总是刘郎去后栽’之句，后篇有‘种桃道士今何在，前度刘郎今又来’之句。\"','唐敬宗宝历二年',9,'2026-04-09 11:15:07.665015','2026-04-09 11:15:07.665015'),(399,54,'838','26','入泾原节度使王茂元幕府，娶王茂元之女为妻，因令狐楚属牛党、王茂元属李党，被牛党人士视为背恩，仕途开始受到排挤','《新唐书·李商隐传》：王茂元镇河阳，爱其才，表掌书记，以女妻之，得侍御史。茂元善李德裕，而令狐氏父子素善李宗闵，商隐遂为绹所恶，共排笮之。','唐开成三年',4,'2026-04-09 11:17:15.279265','2026-04-09 11:17:15.279265'),(400,54,'821','9','父李嗣卒于浙东任上，随母奉丧归乡，家境贫寒，以抄书谋生，苦读力学','《新唐书·李商隐传》：商隐少孤贫，刻意为文。','唐长庆元年',1,'2026-04-09 11:17:15.280342','2026-04-09 11:17:15.280342'),(401,54,'813','1','出生于郑州荥阳，为李唐宗室远支，父李嗣时任浙东幕僚','《新唐书·李商隐传》：李商隐，字义山，怀州河内人，或言英国公世勣之裔孙。','唐元和八年',0,'2026-04-09 11:17:15.280468','2026-04-09 11:17:15.280468'),(402,54,'829','17','以所作文章谒见天平军节度使令狐楚，受令狐楚赏识，被辟为巡官，令狐楚亲授其骈文写作技法，令其与令狐绹等子弟交游','《旧唐书·李商隐传》：令狐楚镇河阳，以所业文干之，年才及弱冠，楚以其少俊，深礼之，令与诸子游。楚镇天平、汴州，从为巡官，岁给资装，令随计上都。','唐大和三年',2,'2026-04-09 11:17:15.280783','2026-04-09 11:17:15.280783'),(403,54,'839','27','通过吏部铨选，授秘书省校书郎，不久调任弘农县尉，因宽赦死囚触怒上司，愤而辞官，后新观察使姚合到任，挽留其复职','《新唐书·李商隐传》：调弘农尉，以活狱忤观察使孙简，将罢去，会姚合代简，谕使还官。','唐开成四年',5,'2026-04-09 11:17:15.280946','2026-04-09 11:17:15.280946'),(404,54,'848','36','被桂管观察使郑亚辟为观察判官，随赴桂林任职，次年郑亚因李党身份被贬，李商隐随之罢职，辗转返回长安','《新唐书·李商隐传》：会给事中郑亚廉察桂州，请为观察判官、检校水部员外郎。亚坐德裕党，亦贬循州刺史，商隐随亚在岭表累岁。','唐大中二年',8,'2026-04-09 11:17:15.281048','2026-04-09 11:17:15.281048'),(405,54,'837','25','在令狐绹的推荐下，登进士第','《旧唐书·李商隐传》：开成二年，方登进士第。','唐开成二年',3,'2026-04-09 11:17:15.281319','2026-04-09 11:17:15.281319'),(406,54,'846','34','唐武宗驾崩，唐宣宗即位，牛党全面掌权，李德裕被贬，李商隐因属李党阵营，长期不受任用，仕途陷入困顿','《新唐书·李商隐传》：宣宗大中初，白敏中执政，令狐绹在内署，共排李德裕逐之，绹恶其忘家恩，放利偷合，故共排摈，久不调。','唐会昌六年',7,'2026-04-09 11:17:15.281463','2026-04-09 11:17:15.281463'),(407,54,'842','30','通过书判拔萃科考试，授秘书省正字','《旧唐书·李商隐传》：会昌二年，又以书判拔萃。','唐会昌二年',6,'2026-04-09 11:17:15.281702','2026-04-09 11:17:15.281702'),(408,54,'851','39','妻子王氏病逝，同年应东川节度使柳仲郢征召，任节度判官、检校工部郎中，在梓州任职共五年','《新唐书·李商隐传》：柳仲郢镇东蜀，辟为节度判官、检校工部郎中。','唐大中五年',9,'2026-04-09 11:17:15.281870','2026-04-09 11:17:15.281870'),(409,54,'858','46','随柳仲郢还朝后不久罢职，返回郑州荥阳故居，同年病逝，其诗构思新奇，风格秾丽，与杜牧并称“小李杜”，与温庭筠并称“温李”','《旧唐书·李商隐传》：商隐废罢，还郑州，未几病卒，时年四十五。商隐能为古文，不喜偶对，博学强记，下笔不能自休，尤善为诔奠之辞。与太原温庭筠、南郡段成式齐名，时号‘三十六’。','唐大中十二年',10,'2026-04-09 11:17:15.286452','2026-04-09 11:17:15.286452'),(410,55,'825','23','作《阿房宫赋》，辞采瑰玮，借古讽今直指时政弊端，文章问世后广为传诵，文名震动京师','《新唐书·杜牧传》：牧少敏悟，工为文，作《阿房宫赋》，辞藻奇丽，当世传诵之。','唐宝历元年',1,'2026-04-09 11:18:52.818417','2026-04-09 11:18:52.818417'),(411,55,'803','1','生于京兆万年（今陕西西安），出身关中望族京兆杜氏，祖父杜佑为当朝宰相，著有《通典》，家学渊源深厚','《旧唐书·杜牧传》：杜牧，字牧之，京兆万年人，宰臣佑之孙。','唐贞元十九年',0,'2026-04-09 11:18:52.818686','2026-04-09 11:18:52.818686'),(412,55,'833','31','被淮南节度使牛僧孺辟为节度府掌书记，居扬州期间留心军政要务，后续作《罪言》《战论》《守论》等文，系统剖析藩镇割据、边患频发的症结','《新唐书·杜牧传》：牛僧孺节度淮南，表掌书记，牧慷慨论天下事，作《罪言》《战论》诸篇，指切时弊，皆中肯綮。','唐大和七年',3,'2026-04-09 11:18:52.818841','2026-04-09 11:18:52.818841'),(413,55,'835','33','入朝任监察御史，察觉朝中政治形势凶险，随即称病请求分司东都洛阳，成功避过甘露之变的大规模政治清洗','《旧唐书·杜牧传》：大和九年，入为监察御史，移疾分司东都，时李训、郑注构乱，朝士多罹其祸，牧以居外获免。','唐大和九年',4,'2026-04-09 11:18:52.818993','2026-04-09 11:18:52.818993'),(414,55,'828','26','考中进士第，同年又登贤良方正直言极谏科，授弘文馆校书郎、试左武卫兵曹参军，正式踏入仕途','《旧唐书·杜牧传》：太和二年，擢进士第，又举贤良方正制科，释褐弘文馆校书郎、试左武卫兵曹参军。','唐大和二年',2,'2026-04-09 11:18:52.819047','2026-04-09 11:18:52.819047'),(415,55,'839','37','迁左补阙、史馆修撰，后转任膳部、比部员外郎，参与国史修撰工作','《新唐书·杜牧传》：开成中，累迁左补阙、史馆修撰，改膳部、比部员外郎。','唐开成四年',5,'2026-04-09 11:18:52.819148','2026-04-09 11:18:52.819148'),(416,55,'842','40','受牛李党争牵连外放为黄州刺史，后历任池州、睦州刺史，在任期间整饬吏治、减免苛捐杂税，治绩斐然，颇受百姓爱戴','《旧唐书·杜牧传》：会昌二年，出为黄州刺史，转池州、睦州刺史，所至有政声。','唐会昌二年',6,'2026-04-09 11:18:52.819233','2026-04-09 11:18:52.819233'),(417,55,'848','46','奉诏入朝任司勋员外郎、史馆修撰，后转吏部员外郎，期间整理祖父杜佑遗留的《通典》相关文稿','《新唐书·杜牧传》：大中初，擢司勋员外郎、史馆修撰，迁吏部员外郎。','唐大中二年',7,'2026-04-09 11:18:52.819309','2026-04-09 11:18:52.819309'),(418,55,'852','50','入朝升任考功郎中、知制诰，旋迁中书舍人，同年冬病逝，临终前自撰墓志铭，焚毁部分不满意的诗文，留存作品后世辑为《樊川文集》，其诗后世称誉甚高，与杜甫并称“大小杜”，号为“小杜”','《新唐书·杜牧传》：迁中书舍人，卒，年五十，牧于诗格高韵远，世称“小杜”，以别杜甫云。','唐大中六年',9,'2026-04-09 11:18:52.819438','2026-04-09 11:18:52.819438'),(419,55,'850','48','以家贫、弟杜顗病重无人照料为由上疏求任湖州刺史，获允赴任，在湖州兴修水利、抚恤流民，多有惠政','《旧唐书·杜牧传》：牧以弟顗病废，家贫俸薄，求为湖州刺史，因拜是官，政声甚著。','唐大中四年',8,'2026-04-09 11:18:52.819459','2026-04-09 11:18:52.819459'),(420,56,'约556年','1','为北周隋国公杨坚与嫡妻独孤伽罗的长子，小名睍地伐','《隋书·卷四十五·列传第十》：房陵王勇，字睍地伐，高祖长子也。','西魏恭帝三年',0,'2026-04-09 11:28:51.714319','2026-04-09 11:28:51.714319'),(421,56,'580','25','父亲杨坚执掌北周朝政，杨勇被册为世子，拜大将军、左司卫，封长宁郡公，出镇洛阳，统领原北齐境内军政事务','《隋书·卷四十五·列传第十》：及高祖辅政，立为世子，拜大将军、左司卫，封长宁郡公。出为洛州总管、东京小冢宰，总统旧齐之地。','北周大象二年',1,'2026-04-09 11:28:51.714574','2026-04-09 11:28:51.714574'),(422,56,'581','26','杨坚受禅代周建立隋朝，杨勇被册立为皇太子，获许参与决断军国政事及死罪以下的刑罚裁定','《隋书·卷四十五·列传第十》：高祖受禅，立为皇太子，军国政事及尚书奏死罪已下，皆令勇参决之。','隋开皇元年',2,'2026-04-09 11:28:51.714923','2026-04-09 11:28:51.714923'),(423,56,'583','28','上书谏止隋文帝迁徙山东流民充实北方边境的政策，被隋文帝采纳，其理政能力得到朝野认可','《隋书·卷四十五·列传第十》：上以山东民多流冗，遣使按检，又欲徙民北实边塞。勇上书切谏，上览而嘉之，遂寝其事。是后时政不便，多所损益，高祖每纳之。','隋开皇三年',3,'2026-04-09 11:28:51.715135','2026-04-09 11:28:51.715135'),(424,56,'598','43','冬至日在东宫张乐接受百官朝贺，行事逾越礼制，引发隋文帝猜忌，父子间嫌隙渐生，帝后对其恩宠开始衰减','《隋书·卷四十五·列传第十》：其后经冬至，百官朝勇，勇张乐受贺。高祖知之，问朝臣曰：「近闻至节，内外百官相率朝东宫，是何礼也？」自此恩宠始衰，渐生疑阻。','隋开皇十八年',4,'2026-04-09 11:28:51.715368','2026-04-09 11:28:51.715368'),(425,56,'604','49','隋文帝驾崩后，杨广继位为隋炀帝，假传文帝遗诏赐死杨勇，追封其为房陵王，不设立嗣君，其诸子多被流放岭南后遇害','《隋书·卷四十五·列传第十》：高祖崩，杨广秘不发丧，伪为高祖敕书，赐庶人勇死。追封房陵王，不为立嗣。','隋仁寿四年',6,'2026-04-09 11:28:51.715570','2026-04-09 11:28:51.715570'),(426,56,'600','45','在晋王杨广、独孤皇后、宰相杨素的联合构陷下，隋文帝下诏废杨勇为庶人，其子女爵位一并褫夺，交由新太子杨广看管','《隋书·卷四十五·列传第十》：开皇二十年，高祖御武德殿，集百官立于东面，诸亲立于西面，引勇及诸子列于殿庭，命内史侍郎薛道衡宣诏，废勇及其男女为王、公主者，并为庶人。','隋开皇二十年',5,'2026-04-09 11:28:51.715712','2026-04-09 11:28:51.715712'),(427,57,'571','1','出生于北周贵族杨氏府邸，为隋文帝杨坚第三子，母亲是文献皇后独孤伽罗','《隋书·卷四十五·列传第十·文四子》：秦孝王俊，字阿祗，高祖第三子也。','北周天和六年',0,'2026-04-09 11:30:39.378524','2026-04-09 11:30:39.378524'),(428,57,'581','11','杨坚代周建立隋朝，杨俊受封秦王爵位','《隋书·卷四十五·列传第十·文四子》：开皇元年，立为秦王。','隋开皇元年',1,'2026-04-09 11:30:39.378609','2026-04-09 11:30:39.378609'),(429,57,'586','16','调任山南道行台尚书令、襄州刺史，总领三十二州军政事务','《隋书·卷四十五·列传第十·文四子》：六年，转山南道行台尚书令。','隋开皇六年',3,'2026-04-09 11:30:39.379038','2026-04-09 11:30:39.379038'),(430,57,'582','12','授上柱国、河南道行台尚书令、洛州刺史，加右武卫大将军，统领关东兵马，隋文帝为其选配良臣辅佐','《隋书·卷四十五·列传第十·文四子》：开皇二年，拜上柱国、河南道行台尚书令、洛州刺史，时年十二。加右武卫大将军，领关东兵。','隋开皇二年',2,'2026-04-09 11:30:39.379127','2026-04-09 11:30:39.379127'),(431,57,'588','18','隋灭陈战役爆发，杨俊任山南道行军元帅，督管三十总管、水陆大军十余万屯驻汉口，节制长江上游隋军行动','《隋书·卷四十五·列传第十·文四子》：伐陈之役，以为山南道行军元帅，督三十总管，水陆十余万，屯汉口，为上流节度。','隋开皇八年',4,'2026-04-09 11:30:39.379236','2026-04-09 11:30:39.379236'),(432,57,'589','19','陈朝灭亡后，平定据城抗隋的陈湘州刺史陈叔慎，因功授扬州总管，掌管四十四州军政，镇守广陵','《隋书·卷四十五·列传第十·文四子》：陈平，拜扬州总管四十四州诸军事，镇广陵。','隋开皇九年',5,'2026-04-09 11:30:39.379386','2026-04-09 11:30:39.379386'),(433,57,'590','20','转任并州总管，掌管二十四州军政事务','《隋书·卷四十五·列传第十·文四子》：岁余，转并州总管二十四州诸军事。','隋开皇十年',6,'2026-04-09 11:30:39.379416','2026-04-09 11:30:39.379416'),(434,57,'隋开皇中期','20余岁','杨俊仁恕慈爱，崇信佛道，主动向隋文帝请求出家为僧，未获准许','《隋书·卷四十五·列传第十·文四子》：俊仁恕慈爱，崇敬佛道，请为沙门，上不许。','隋开皇年间',7,'2026-04-09 11:30:39.379495','2026-04-09 11:30:39.379495'),(435,57,'597','27','任职并州期间骄奢放纵，违反制度放债取息、营建奢华宫室，侵扰百姓，被隋文帝征召回京，免去所有官职，仅保留秦王爵位归家反省，朝臣求情被文帝以“不可别制天子儿律”为由拒绝','《隋书·卷四十五·列传第十·文四子》：十七年，上以俊奢纵，免官，以王就第。武卫将军刘升谏曰：“秦王非有他过，但费官物营廨舍而已。臣谓可容。”上曰：“法不可违。”……又曰：“我是五儿之父，若如公意，何不别制天子儿律？以周公之为人，尚诛管、蔡，我诚不及周公远矣，安能亏法乎？”','隋开皇十七年',8,'2026-04-09 11:30:39.379571','2026-04-09 11:30:39.379571'),(436,57,'598','28','杨俊广纳姬妾，王妃崔氏性情善妒，心怀不满，在瓜中投毒，杨俊因此染病，身体日渐衰弱','《隋书·卷四十五·列传第十·文四子》：俊颇好内，妃崔氏性妒，甚不平之，遂于瓜中进毒，俊由是遇疾。','隋开皇十八年',9,'2026-04-09 11:30:39.379643','2026-04-09 11:30:39.379643'),(437,57,'600','30','杨俊病重无法起身，遣使向隋文帝奉表谢罪，遭到文帝严厉斥责，内心惊惧之下病情进一步加重','《隋书·卷四十五·列传第十·文四子》：二十年，俊疾笃，不能起，遣使奉表陈谢。上谓其使曰：“我戮力关塞，创兹大业，作训垂范，庶臣下守之而不失。汝为吾子，而欲败之，不知何以责汝！”俊惭怖，疾甚。','隋开皇二十年',10,'2026-04-09 11:30:39.383330','2026-04-09 11:30:39.383330'),(438,57,'601','31','杨俊在秦王府邸去世，谥号为孝；隋文帝下令焚毁其生前所有奢侈违制的物品，葬礼从简以为后世法度','《隋书·卷四十五·列传第十·文四子》：仁寿元年六月，薨于秦邸，时年三十。上哭之，数声而止……命送终之具，务从俭约，为后法也。俊所为侈丽之物，悉命焚之。谥曰孝王。','隋仁寿元年',11,'2026-04-09 11:30:39.385384','2026-04-09 11:30:39.385384'),(439,58,'592','20','入朝任内史令、右领军大将军，不久后再次出镇蜀地；因勇武有胆气遭隋文帝忌惮，被认为日后必反，杨秀在蜀地日渐骄奢，车马服饰僭越天子规制','《隋书·卷四十五·列传第十》：十二年，又为内史令、右领军大将军。寻复出镇于蜀。秀有胆气，容貌瑰伟，美须髯，多武艺，甚为朝臣所惮。高祖每谓献皇后曰：‘秀必以恶终。我在当无虑，至兄弟必反。’……秀既贵，渐奢侈，违犯制度，车马被服，拟于天子。','隋开皇十二年',3,'2026-04-09 11:32:15.272748','2026-04-09 11:32:15.272748'),(440,58,'581','9','受封越王，不久后改封蜀王，授柱国、益州刺史，总管二十四州诸军事','《隋书·卷四十五·列传第十》：开皇元年，立为越王。未几，徙封于蜀，拜柱国、益州刺史、总管，二十四州诸军事。','隋开皇元年',1,'2026-04-09 11:32:15.274809','2026-04-09 11:32:15.274809'),(441,58,'582','10','进位上柱国、西南道行台尚书令，原有职权保留，一年后西南道行台被撤销','《隋书·卷四十五·列传第十》：二年，进位上柱国、西南道行台尚书令，本官如故。岁余，道行台废。','隋开皇二年',2,'2026-04-09 11:32:15.275137','2026-04-09 11:32:15.275137'),(442,58,'600','28','太子杨勇被废，晋王杨广被立为皇太子，杨秀对此心存不满，杨广担心杨秀日后生变，暗中指使杨素搜罗其罪证进行构陷','《隋书·卷四十五·列传第十》：及太子勇以谗毁废，晋王广为皇太子，秀意甚不平。皇太子恐秀终为后变，阴令杨素求其罪而谮之。','隋开皇二十年',4,'2026-04-09 11:32:15.275348','2026-04-09 11:32:15.275348'),(443,58,'602','30','被征召返回京师，隋文帝对其切责问罪，随后被废为庶人，软禁于内侍省，仅派两名獠婢供其驱使，连坐获罪者达百余人','《隋书·卷四十五·列传第十》：仁寿二年，征还京师。上见之，不与语。明日，使使切让之。……于是废为庶人，幽之内侍省，不得与妻子相见，令给獠婢二人驱使。与相连坐者百余人。','隋仁寿二年',5,'2026-04-09 11:32:15.275766','2026-04-09 11:32:15.275766'),(444,58,'618','46','宇文化及发动江都宫变弑杀隋炀帝，原本打算拥立杨秀为帝，遭到群臣反对，杨秀和他的七个儿子一同被杀害','《隋书·卷四十五·列传第十》：化及之弑逆也，欲立秀为帝，群议不许。于是害之，并其诸子。','隋大业十四年',7,'2026-04-09 11:32:15.275964','2026-04-09 11:32:15.275964'),(445,58,'573','1','出生，为隋文帝杨坚第四子，母亲是文献皇后独孤伽罗','《隋书·卷四十五·列传第十》：庶人秀，高祖第四子也。母曰文献独孤皇后。','北周建德二年',0,'2026-04-09 11:32:15.276148','2026-04-09 11:32:15.276148'),(446,58,'604','32','隋炀帝杨广即位后，依旧对杨秀严加禁锢，每次出巡都将杨秀带在身边随行，防止其在外生变','《隋书·卷四十五·列传第十》：炀帝即位，禁锢如初。每巡幸，辄恒带自随。','隋仁寿四年',6,'2026-04-09 11:32:15.276273','2026-04-09 11:32:15.276273'),(447,59,'602','28','文献皇后独孤伽罗驾崩，加之此前太子杨勇被废、蜀王杨秀获罪，杨谅内心不安，以防备突厥为名修缮军备、招纳亡命，暗中积蓄力量图谋自保','《隋书·卷四十五·列传第十》：谅自以所居天下精兵处，以太子谗废，居常怏怏，阴有异图。遂讽高祖云：‘突厥方强，太原即为重镇，宜修武备。’高祖从之。于是大发工役，缮治器械，贮纳于并州。招雇亡命，左右私人，殆将数万。','隋仁寿二年',4,'2026-04-09 11:33:53.543458','2026-04-09 11:33:53.543458'),(448,59,'581','7','隋朝建立后，被隋文帝册封为汉王','《隋书·卷四十五·列传第十》：开皇元年，立为汉王。','隋开皇元年',1,'2026-04-09 11:33:53.544692','2026-04-09 11:33:53.544692'),(449,59,'575','1','为隋文帝杨坚与文献皇后独孤伽罗幼子，是杨坚第五子','《隋书·卷四十五·列传第十》：汉王谅，字德章，一名杰，高祖第五子也。','北周建德四年',0,'2026-04-09 11:33:53.544937','2026-04-09 11:33:53.544937'),(450,59,'598','24','担任行军元帅，统领水陆三十万大军征讨高句丽，途中军中爆发疫病，无功而返','《隋书·卷四十五·列传第十》：十八年，起辽东之役，以谅为行军元帅，率众至辽水，遇疾疫，不利而还。','隋开皇十八年',3,'2026-04-09 11:33:53.545147','2026-04-09 11:33:53.545147'),(451,59,'597','23','出任并州总管，管辖太行山以东、沧海以西、黄河以北共五十二州军政事务，获隋文帝特许可便宜行事，不受律令约束','《隋书·卷四十五·列传第十》：十七年，出为并州总管，上幸温汤而送之。自山以东，至于沧海，南拒黄河，五十二州尽隶焉。特许以便宜，不拘律令。','隋开皇十七年',2,'2026-04-09 11:33:53.545356','2026-04-09 11:33:53.545356'),(452,59,'隋大业初年','30余岁','在幽禁中去世，其子杨颢一同被禁锢，至宇文化及发动江都之变弑杀隋炀帝时，杨颢遇害','《隋书·卷四十五·列传第十》：竟以幽死。子颢，因而禁锢，宇文化及弑逆之际，遇害。','隋朝晚期',7,'2026-04-09 11:33:53.545520','2026-04-09 11:33:53.545520'),(453,59,'604','30','隋文帝驾崩，隋炀帝杨广派使者持玺书征召杨谅入朝，杨谅发现玺书不符合与父亲事先约定的暗号，知道朝中有变，遂起兵反叛','《隋书·卷四十五·列传第十》：及高祖崩，炀帝遣车骑将军屈突通以高祖玺书征之。先是，高祖与谅密约：‘若玺书召汝，敕字傍别加一点，又与玉麟符合者，当就征。’及发书无验，谅知有变。诘通，通占对不屈，乃遣归长安。谅遂发兵反。','隋仁寿四年',5,'2026-04-09 11:33:53.545708','2026-04-09 11:33:53.545708'),(454,59,'604','30','杨素奉隋炀帝诏令率军讨伐，接连击败杨谅所部，围困并州，杨谅穷蹙投降，百官奏请将其处死，隋炀帝特赦其死罪，除名为民，开除出宗室属籍，予以幽禁','《隋书·卷四十五·列传第十》：杨素进击谅，大破之，擒于清源。谅遂退保并州，素进兵围之，谅穷蹙，降于素。百僚奏谅罪当死，帝曰：‘终鲜兄弟，情不忍言，欲屈法恕谅一死。’于是除名为民，绝其属籍。','隋仁寿四年',6,'2026-04-09 11:33:53.545910','2026-04-09 11:33:53.545910'),(455,60,'584','1','生于大兴城，为晋王杨广与萧皇后嫡长子，出生后即被隋文帝杨坚接入宫中抚养','《隋书·卷五十九·列传第二十四》：元德太子昭，炀帝长子也，母曰萧皇后。生而高祖命养宫中。','隋开皇四年',0,'2026-04-09 11:35:06.900083','2026-04-09 11:35:06.900083'),(456,60,'597','14','纳内史令崔弘升之女为河南王妃','《隋书·卷五十九·列传第二十四》：开皇十七年，纳内史令崔弘升女为妃。','隋开皇十七年',2,'2026-04-09 11:35:06.900434','2026-04-09 11:35:06.900434'),(457,60,'590','7','受封为河南王，食邑一千户','《隋书·卷五十九·列传第二十四》：开皇十年，立为河南王。','隋开皇十年',1,'2026-04-09 11:35:06.900659','2026-04-09 11:35:06.900659'),(458,60,'600','17','父亲杨广被册立为皇太子，杨昭转封晋王，授内史令、兼左卫大将军','《隋书·卷五十九·列传第二十四》：及炀帝为皇太子，转封晋王，拜内史令，兼左卫大将军。','隋开皇二十年',3,'2026-04-09 11:35:06.900866','2026-04-09 11:35:06.900866'),(459,60,'604','21','杨广即位为隋炀帝，巡幸洛阳宫，杨昭奉命留守京师长安','《隋书·卷五十九·列传第二十四》：炀帝即位，便幸洛阳宫，昭留守京师。','隋仁寿四年',4,'2026-04-09 11:35:06.901055','2026-04-09 11:35:06.901055'),(460,60,'605','22','被正式册立为皇太子','《隋书·卷五十九·列传第二十四》：大业元年，帝遣使者立为皇太子。','隋大业元年',5,'2026-04-09 11:35:06.901299','2026-04-09 11:35:06.901299'),(461,60,'606','23','赴洛阳朝见隋炀帝，因多次跪拜请求留居洛阳，加之本身肥胖致劳疾发作，不久去世，谥号元德太子，葬于庄陵','《隋书·卷五十九·列传第二十四》：大业二年，朝于洛阳。后数月，将还京师，愿得少留，帝不许。拜请无数，体素肥，因致劳疾。帝令巫者视之，云：‘房陵王为祟。’未几而薨，时年二十三。谥曰元德。','隋大业二年',6,'2026-04-09 11:35:06.901808','2026-04-09 11:35:06.901808'),(462,60,'617','已故','李渊立其第三子代王杨侑为隋恭帝，追尊杨昭为孝成皇帝，庙号世宗','《隋书·卷五十九·列传第二十四》：义宁元年，恭帝追崇为世宗孝成皇帝。','隋义宁元年',7,'2026-04-09 11:35:06.902288','2026-04-09 11:35:06.902288'),(463,61,'605','21','隋炀帝即位后，进封齐王，增食邑至四千户，不久转任雍州牧、河南尹、开府仪同三司，恩宠冠于当时','《隋书·卷五十九·列传第二十四》：炀帝即位，进封齐王，增邑四千户。俄拜雍州牧，寻转河南尹、开府仪同三司。','隋大业元年',3,'2026-04-09 11:36:41.722055','2026-04-09 11:36:41.722055'),(464,61,'601','17','受任扬州总管，统领沿淮以南诸军事','《隋书·卷五十九·列传第二十四》：仁寿中，拜扬州总管沿淮以南诸军事。','隋仁寿元年',2,'2026-04-09 11:36:41.722880','2026-04-09 11:36:41.722880'),(465,61,'585','1','为晋王杨广与萧皇后所生次子，相貌俊美眉目疏朗，自幼深得祖父隋文帝杨坚喜爱','《隋书·卷五十九·列传第二十四》：齐王暕，字世朏，小字阿孩。美容仪，疏眉目，少为高祖所爱。','隋开皇五年',0,'2026-04-09 11:36:41.723032','2026-04-09 11:36:41.723032'),(466,61,'606','22','元德太子杨昭薨逝，朝野上下都认为杨暕应当被立为储君，隋炀帝也对其颇为重视，将东宫原属官属尽数划归杨暕麾下','《隋书·卷五十九·列传第二十四》：及元德太子薨，朝野注望，咸以暕当嗣。帝又敕吏部尚书牛弘妙选官属，公卿由是多进子弟。','隋大业二年',4,'2026-04-09 11:36:41.723161','2026-04-09 11:36:41.723161'),(467,61,'593','9','受封豫章王，食邑千户，不久后拜任内史令','《隋书·卷五十九·列传第二十四》：开皇中，立为豫章王，邑千户。初拜内史令。','隋开皇十三年',1,'2026-04-09 11:36:41.723304','2026-04-09 11:36:41.723304'),(468,61,'隋大业年间','壮年','杨暕日渐骄纵，亲近小人，多行不法，又因私纳柳述之女、行厌胜之术诅咒元德太子诸子等事触怒隋炀帝，被隋炀帝下令长期禁锢，随行护卫皆用老弱之人，不再允许他参与时政','《隋书·卷五十九·列传第二十四》：暕颇骄恣，昵近小人，所行多不法……帝闻之大怒，穷治其事……于是恩宠日衰，虽为京尹，不复关预时政。帝恒令武贲郎将一人监其府事，暕有微失，武贲辄奏之。帝亦常虑暕生变，所给左右，皆以老弱，备员而已。','隋朝晚期',5,'2026-04-09 11:36:41.723480','2026-04-09 11:36:41.723480'),(469,61,'618','34','江都之变爆发，宇文化及率军弑杀隋炀帝，杨暕被乱兵抓获时误以为是隋炀帝要处死自己，最终与两个儿子一同遇害，至死都不知道杀他的是宇文化及叛军','《隋书·卷五十九·列传第二十四》：宇文化及之逆也，俄而兵至，暕尚卧未起，乱兵已入，暕惊曰：‘是何人？’莫有报者，暕犹谓帝令捕之，因曰：‘诏使且缓，儿不负国家。’贼于是曳至街而斩之，及其二子亦遇害。暕竟不知杀者为谁。时年三十四。','隋大业十四年',6,'2026-04-09 11:36:41.723844','2026-04-09 11:36:41.723844'),(470,62,'615','9','随隋炀帝巡幸雁门，遭突厥始毕可汗率军围困，箭矢射至御前，战况危急，隋炀帝抱着他痛哭，双目都哭至肿胀','《隋书·卷五十九·列传第二十四》：从帝幸雁门，为突厥所围，矢及御前，帝抱杲而泣，目为之肿。','隋大业十一年',2,'2026-04-09 11:37:46.768727','2026-04-09 11:37:46.768727'),(471,62,'613','7','受封赵王，不久后授光禄大夫，拜河南尹','《隋书·卷五十九·列传第二十四》：年七岁，封赵王。寻授光禄大夫，拜河南尹。','隋大业九年',1,'2026-04-09 11:37:46.769327','2026-04-09 11:37:46.769327'),(472,62,'武德年间','殁后','唐朝平定江南后，追赠杨杲为光禄大夫，赐谥号为悼','《隋书·卷五十九·列传第二十四》：大唐平江南，赠光禄大夫，谥曰悼。','唐初',4,'2026-04-09 11:37:46.769655','2026-04-09 11:37:46.769655'),(473,62,'618','12','江都之变爆发，宇文化及率叛军弑杀隋炀帝，杨杲在炀帝身旁痛哭不止，被叛将裴虔通斩杀于炀帝身前，鲜血溅到炀帝的御服之上','《隋书·卷五十九·列传第二十四》：宇文化及弑逆之际，杲在帝侧，号恸不已，裴虔通使贼斩之于帝前，血湔御服，时年十二。','隋大业十四年',3,'2026-04-09 11:37:46.769801','2026-04-09 11:37:46.769801'),(474,62,'607','1','杨杲出生，为隋炀帝杨广第三子，生母为萧嫔，其自幼容貌俊美、天性聪慧，极受隋炀帝宠爱','《隋书·卷五十九·列传第二十四》：赵王杲，字季子，小字季子。父隋炀帝，母萧嫔。美容仪，性聪敏，帝甚钟爱之。','隋大业三年',0,'2026-04-09 11:37:46.769915','2026-04-09 11:37:46.769915'),(475,63,'577','青年','北齐被北周攻灭后入关与堂兄杨坚相认，杨坚怜悯其早年流离的身世，为他购置田宅','《隋书·卷四十三·列传第八》：\"齐为周所并，弘始入关，与高祖相得。高祖哀之，为买田宅。\"','北周建德六年',0,'2026-04-09 11:39:53.243557','2026-04-09 11:39:53.243557'),(476,63,'580','壮年','杨坚担任北周丞相后将他视为心腹，常侍左右护卫，后以行军总管身份跟随韦孝宽平定尉迟迥叛乱，进位柱国，封河间郡公','《隋书·卷四十三·列传第八》：\"及为丞相，常置左右，委以心腹。高祖诣周赵王宅，将及于难，弘时立于门外，以卫高祖。……及尉迥作乱，以弘为行军总管，从韦孝宽击之。关东平，进位柱国，封河间郡公。\"','北周大象二年',1,'2026-04-09 11:39:53.243734','2026-04-09 11:39:53.243734'),(477,63,'581','壮年','杨坚称帝建立隋朝，杨弘受封河间王，食邑万户，授右卫大将军职','《隋书·卷四十三·列传第八》：\"开皇元年，拜右卫大将军，进爵为王，邑万户。\"','隋开皇元年',2,'2026-04-09 11:39:53.243896','2026-04-09 11:39:53.243896'),(478,63,'开皇中后期','壮年','数年后被征召回京，不久后转任蒲州刺史，获准可便宜行事；整治境内盗贼，奏请将百余名为盗者发配边境，州境安定，期间每当晋王杨广入朝，他便暂代扬州总管事务，待杨广归藩后再返回蒲州，在任十余年教化大行，被称为良吏','《隋书·卷四十三·列传第八》：\"后数载，征还京师。未几，拜蒲州刺史，得以便宜从事。时河东多盗贼，民不得安，弘奏为盗者百余人，投之边裔，州境帖然，号为良吏。每晋王广入朝，弘辄领扬州总管，及晋王归藩，弘复还蒲州。在官十余年，风教大洽。\"','隋开皇年间',4,'2026-04-09 11:39:53.244068','2026-04-09 11:39:53.244068'),(479,63,'606','晚年','在太子太保任上去世，朝廷赐予丰厚丧礼','《隋书·卷四十三·列传第八》：\"岁余，薨。\"','隋大业二年',6,'2026-04-09 11:39:53.244169','2026-04-09 11:39:53.244169'),(480,63,'610','已故','朝廷追封杨弘为郇王','《隋书·卷四十三·列传第八》：\"大业六年，追封郇王。\"','隋大业六年',7,'2026-04-09 11:39:53.244255','2026-04-09 11:39:53.244255'),(481,63,'583','壮年','出任行军元帅，率数万部众从灵州道出击突厥，与突厥军遭遇后大破敌军，斩首数千级，战后升任宁州总管，进位上柱国，在任治政宽简，深得吏民拥戴','《隋书·卷四十三·列传第八》：\"其年，以行军元帅，率众数万出灵州道，与虏遇，战，大破之，斩数千级。赐物二千段，出为宁州总管，进位上柱国。弘在州，治尚清静，甚有恩惠。\"','隋开皇三年',3,'2026-04-09 11:39:53.244337','2026-04-09 11:39:53.244337'),(482,63,'605','晚年','隋炀帝杨广即位后，杨弘被征召回京，授太子太保之职','《隋书·卷四十三·列传第八》：\"炀帝即位，征还，拜太子太保。\"','隋大业元年',5,'2026-04-09 11:39:53.244403','2026-04-09 11:39:53.244403'),(483,64,'550','1','出生于北周将门杨氏，为隋太祖杨忠第三子，隋文帝杨坚同母弟，本名杨慧，字恒生，自幼俊美好学，在当世有很好的名声，时人称呼其为“杨三郎”','《隋书·卷四十四·列传第九》：滕穆王瓒，字恒生，一名慧，高祖母弟也。美姿仪，好书爱士，甚有令名于当世，时人号曰杨三郎。','西魏大统十六年',0,'2026-04-09 11:41:45.401257','2026-04-09 11:41:45.401257'),(484,64,'564','15','迎娶北周武帝宇文邕之妹顺阳公主，官职从右中侍上士升任御伯中大夫，同年北周改御伯为纳言，杨瓒因此担任纳言一职，授仪同三司','《隋书·卷四十四·列传第九》：周世，尚武帝妹顺阳公主，自右中侍上士迁御伯中大夫。保定四年，改为纳言，授仪同。','北周保定四年',1,'2026-04-09 11:41:45.401440','2026-04-09 11:41:45.401440'),(485,64,'579','30','升任大宗伯，晋爵邵国公，食邑三千户，在北周朝堂声望颇高','《隋书·卷四十四·列传第九》：大象初，迁大宗伯，进爵邵国公，邑三千户。','北周大象元年',2,'2026-04-09 11:41:45.401598','2026-04-09 11:41:45.401598'),(486,64,'580','31','杨坚即将辅政把持北周朝政，遣使召杨瓒支持，杨瓒担心杨坚起事失败会株连宗族，多次拒绝，甚至暗中谋划推翻杨坚，杨坚得知后仍对其宽容优待','《隋书·卷四十四·列传第九》：及高祖作相，迁大将军，寻拜大宗伯。瓒素与高祖不协，又恐高祖倾覆宗社，阴有图高祖之计，高祖每优容之。','北周大象二年',3,'2026-04-09 11:41:45.401770','2026-04-09 11:41:45.401770'),(487,64,'581','32','杨坚受禅代周建立隋朝，杨瓒被册封为滕王，后拜雍州牧，隋文帝多次和他同坐交谈，以乳名“阿三”称呼他','《隋书·卷四十四·列传第九》：开皇元年，立为滕王，后拜雍州牧。上数与同坐，呼为阿三。','隋开皇元年',4,'2026-04-09 11:41:45.401980','2026-04-09 11:41:45.401980'),(488,64,'约589','40','妻子顺阳公主因与独孤皇后素来不和，行巫蛊之事被揭发，隋文帝命杨瓒与公主离婚，杨瓒不忍离绝多次上奏恳请收回成命，隋文帝最终同意他不离婚，但下旨将宇文氏从宗室属籍中除名，杨瓒也因此忤旨，受到的恩宠礼遇日益淡薄','《隋书·卷四十四·列传第九》：其妻宇文氏，先时与独孤皇后不平，及有咒诅，上命瓒出之，瓒不忍离绝，固请。上不得已，从之，宇文氏竟除属籍。瓒由是忤旨，恩礼更薄。','隋开皇九年左右',5,'2026-04-09 11:41:45.402142','2026-04-09 11:41:45.402142'),(489,64,'591','42','跟随隋文帝前往栗园游幸，途中突然离世，时人大多传言他是被隋文帝赐毒酒鸩杀，朝廷追赠其谥号为“穆”，故后世称其为滕穆王','《隋书·卷四十四·列传第九》：十一年，从幸栗园，暴薨，时年四十二。人皆言其遇鸩以毙。子纶嗣。','隋开皇十一年',6,'2026-04-09 11:41:45.402269','2026-04-09 11:41:45.402269'),(490,65,'550年左右','孩童','幼年攀爬树木跌落受伤，因此成为阉人，性情沉静机敏，好学强记，深受异母兄杨素的友爱看重，杨素凡事都会先与他商议再推行','《隋书·卷四十八·杨约传》：约字惠伯，素异母弟也。在童儿时，尝登树堕地，为查所伤，由是竟为宦者。性好沉静，内多谲诈，好学强记。素友爱之，凡有所为，必先筹于约而后行之。','西魏大统年间',0,'2026-04-09 11:43:24.108272','2026-04-09 11:43:24.108272'),(491,65,'604','50余岁','隋文帝驾崩后，受杨广指派入朝替换京中留守，矫诏赐死废太子杨勇，稳定局势，杨广继位后数日即升任内史令','《隋书·卷四十八·杨约传》：遇高祖崩，遣约入朝，易留守者，缢杀庶人勇，然后陈兵集众，发高祖凶问。炀帝闻之曰：‘令兄之弟，果堪大任。’即位数日，拜内史令。','隋仁寿四年',4,'2026-04-09 11:43:24.108383','2026-04-09 11:43:24.108383'),(492,65,'580年左右','青年','凭借兄长杨素的军功，获赐安成县公爵位，授上仪同三司','《隋书·卷四十八·杨约传》：周末，以素军功，赐爵安成县公，拜上仪同三司。','北周大象年间',1,'2026-04-09 11:43:24.108494','2026-04-09 11:43:24.108494'),(493,65,'581','30余岁','隋朝建立后，被隋文帝授为内史侍郎，进位开府，改封临贞县公，后历任大理少卿，备受朝廷信任','《隋书·卷四十八·杨约传》：高祖受禅，授内史侍郎，进位开府，封临贞县公，历官大理少卿。','隋开皇元年',2,'2026-04-09 11:43:24.108582','2026-04-09 11:43:24.108582'),(494,65,'600','50余岁','受晋王杨广笼络，劝说杨素配合独孤皇后，策划构陷太子杨勇，推动隋文帝废黜杨勇，改立杨广为太子','《隋书·卷四十八·杨约传》：晋王广之在藩也，阴有夺宗之计，以约为素所信，深布腹心。约知其计，因说素曰：‘今皇后之言，上无不用，宜因机会，早自结托’，素遂行其策，废太子，黜蜀王秀。','隋开皇二十年',3,'2026-04-09 11:43:24.108660','2026-04-09 11:43:24.108660'),(495,65,'607年左右','晚年','奉命赴京师祭祀宗庙时，顺路拜谒杨素墓与杨氏祖墓，被御史弹劾免官，不久后复任淅阳太守，岁余被召回京，未及授新职便病逝，时年六十余岁','《隋书·卷四十八·杨约传》：后帝在东都，令约诣京师享庙，行至华阴，见其兄墓，遂枉道拜哭，为宪司所劾，坐是免官。未几，拜淅阳太守。岁余，卒官，时年六十余。','隋大业三年左右',5,'2026-04-09 11:43:24.108741','2026-04-09 11:43:24.108741'),(496,66,'605','68','隋炀帝即位，征召杨文思入朝任民部尚书，不久改任纳言，授右光禄大夫','《隋书·杨文思传》：炀帝嗣位，征为民部尚书。转纳言，改授右光禄大夫。','隋大业元年',7,'2026-04-09 11:45:01.026632','2026-04-09 11:45:01.026632'),(497,66,'538','1','生于弘农杨氏望族，为北周小冢宰杨宽之子，自幼习文练武，才干过人','《隋书·杨文思传》：杨文思字温才，弘农华阴人也。父宽，魏左仆射，周小冢宰。','西魏大统四年',0,'2026-04-09 11:45:01.027212','2026-04-09 11:45:01.027212'),(498,66,'566','29','任武都太守，先后平定十姓獠、党项羌叛乱，因功升任大将军、司会中大夫','《隋书·杨文思传》：天和初，治武都太守。十姓獠反，文思讨平之，复治翼州事。党项羌叛，文思率州兵讨平之。进授大将军，迁司会中大夫。','北周天和元年',2,'2026-04-09 11:45:01.027384','2026-04-09 11:45:01.027384'),(499,66,'577','40','随周武帝平定北齐，以军功升开府仪同三司，改封永宁县公，食邑累计一千七百户','《隋书·杨文思传》：武帝平齐，以功进授开府，改封永宁县公，增邑通前千七百户。','北周建德六年',3,'2026-04-09 11:45:01.027530','2026-04-09 11:45:01.027530'),(500,66,'548','11','因父亲杨宽功勋卓著，被授车骑大将军、仪同三司、散骑常侍，不久封新丰县子，食邑五百户','《隋书·杨文思传》：在周，年十一，拜车骑大将军、仪同三司、散骑常侍。寻以父功，封新丰县子，邑五百户。','西魏大统十四年',1,'2026-04-09 11:45:01.027644','2026-04-09 11:45:01.027644'),(501,66,'580','43','尉迟迥叛乱时据守辖区抵御叛军，因功授上大将军，改封洛川县公','《隋书·杨文思传》：大象中，行绛州事。及尉迟迥作乱，文思守境东御，以功授上大将军。寻改封洛川县公。','北周大象二年',4,'2026-04-09 11:45:01.027755','2026-04-09 11:45:01.027755'),(502,66,'581','44','杨坚代周建隋，杨文思进爵正平郡公','《隋书·杨文思传》：开皇元年，进爵正平郡公。','隋开皇元年',5,'2026-04-09 11:45:01.027875','2026-04-09 11:45:01.027875'),(503,66,'隋开皇年间','壮年','转任魏州刺史，任内颇有惠政，安抚百姓、整顿吏治，离职后当地吏民为其立碑颂德','《隋书·杨文思传》：后数岁，转魏州刺史，甚有惠政，及去职，吏民思之，为立碑颂德。','隋开皇年间',6,'2026-04-09 11:45:01.027983','2026-04-09 11:45:01.027983'),(504,66,'607','70','因脚疾不便上朝，复授民部尚书、加左光禄大夫，后出为冀州刺史，在任上去世，谥号为定','《隋书·杨文思传》：以足疾不堪趋奏，复授民部尚书，加位左光禄大夫。卒官，时年七十，谥曰定。','隋大业三年',8,'2026-04-09 11:45:01.028318','2026-04-09 11:45:01.028318'),(505,67,'578','34','出任安州总管长史，任内施政宽惠，境内汉族与夷獠百姓都心悦归附，治理成效显著','《隋书·杨文纪传》：又为安州总管长史，甚有惠政，民夷悦附。','北周宣政元年',3,'2026-04-09 11:47:07.579396','2026-04-09 11:47:07.579396'),(506,67,'563','19','入仕北周，初任右侍上士，之后承袭父亲爵位为华山郡公，食邑二千户','《隋书·杨文纪传》：在周，释褐右侍上士，袭爵华山郡公，邑二千户。','北周保定三年',1,'2026-04-09 11:47:07.579948','2026-04-09 11:47:07.579948'),(507,67,'545','1','生于弘农华阴杨氏望族，为北周大冢宰杨宽幼子，年少时性情刚正，有器量格局，涉猎经史典籍','《隋书·杨文纪传》：杨文纪，字温范，少刚正，有器局，颇涉书史。','西魏大统十一年',0,'2026-04-09 11:47:07.580018','2026-04-09 11:47:07.580018'),(508,67,'577','33','跟随周武帝征讨北齐，凭借军功授任车骑大将军、仪同三司','《隋书·杨文纪传》：后从武帝平齐，以功授车骑大将军、仪同三司。','北周建德六年',2,'2026-04-09 11:47:07.580186','2026-04-09 11:47:07.580186'),(509,67,'579','35','升任虞部下大夫，不久后外放为资州刺史，持节掌辖境内诸军事，以才干出众闻名','《隋书·杨文纪传》：宣政元年，为虞部下大夫。大象初，出为资州刺史、持节、诸军事，有能名。','北周大象元年',4,'2026-04-09 11:47:07.580214','2026-04-09 11:47:07.580214'),(510,67,'581','37','隋朝建立后被征召回朝，历任宗正少卿、尚书右丞，处事公允，得朝廷称许','《隋书·杨文纪传》：开皇初，征为宗正少卿，迁尚书右丞。','隋开皇元年',5,'2026-04-09 11:47:07.580322','2026-04-09 11:47:07.580322'),(511,67,'590','46','调任益州总管司马，辅佐蜀王杨秀治理蜀地，政绩突出，加授上仪同三司','《隋书·杨文纪传》：历益州总管司马，加上仪同三司。','隋开皇十年',7,'2026-04-09 11:47:07.580465','2026-04-09 11:47:07.580465'),(512,67,'583','39','转任黄门侍郎，后受亲属牵连被免官，不久后复起为荆州总管长史','《隋书·杨文纪传》：俄转黄门侍郎，坐事免。后拜荆州总管长史。','隋开皇三年',6,'2026-04-09 11:47:07.580495','2026-04-09 11:47:07.580495'),(513,67,'602','58','蜀王杨秀被隋文帝废黜，益州属官多被牵连获罪，唯有杨文纪因忠正未被追责，不久后拜任蒲州刺史','《隋书·杨文纪传》：及秀废，吏属多坐之，唯文纪以忠获免，寻拜蒲州刺史。','隋仁寿二年',8,'2026-04-09 11:47:07.580754','2026-04-09 11:47:07.580754'),(514,67,'605','61','隋炀帝即位后，杨文纪升任殿内尚书，后拜为荆州总管，进位上大将军','《隋书·杨文纪传》：炀帝嗣位，迁殿内尚书，拜荆州总管，进位上大将军。','隋大业元年',9,'2026-04-09 11:47:07.580838','2026-04-09 11:47:07.580838'),(515,67,'607','63','在荆州总管任上病逝，朝廷追赠其为吏部尚书，谥号为恭','《隋书·杨文纪传》：大业三年卒官，时年六十三，谥曰恭。','隋大业三年',10,'2026-04-09 11:47:07.585977','2026-04-09 11:47:07.585977'),(516,68,'545','1','出生于安定鹑觚官宦世家，本姓寮氏，父亲寮允为西魏侍中，后获赐姓牛氏。牛弘自幼宽厚好学，博闻强识','《隋书·牛弘传》：牛弘，字里仁，安定鹑觚人也，本姓寮氏。祖炽，郡中正。父允，魏侍中、工部尚书、临泾公，赐姓为牛氏。及长，须貌甚伟，性宽裕，好学博闻。','西魏大统十一年',0,'2026-04-09 11:49:39.814737','2026-04-09 11:49:39.814737'),(517,68,'581','37','隋朝建立后，升任散骑常侍、秘书监，鉴于前朝典籍散佚严重，上奏《请开献书之路》，系统梳理历代藏书损毁的五厄，请求朝廷下诏征集民间藏书','《隋书·牛弘传》：开皇初，迁授散骑常侍、秘书监。弘以典籍遗逸，上表请开献书之路。','隋开皇元年',3,'2026-04-09 11:49:39.815731','2026-04-09 11:49:39.815731'),(518,68,'578','34','转任内史下大夫，进位使持节、大将军、仪同三司，袭封父亲的临泾公爵位','《隋书·牛弘传》：宣政元年，转内史下大夫，进位使持节、大将军、仪同三司。','北周宣政元年',2,'2026-04-09 11:49:39.815901','2026-04-09 11:49:39.815901'),(519,68,'557','13','初入仕途，起家任中外府记室、内史上士，不久转任纳言上士，专掌文书起草事务，以才干出众获得朝野美称','《隋书·牛弘传》：周闵帝时，起家中外府记室、内史上士。俄转纳言上士，专掌文翰，甚有美称。','北周孝闵帝元年',1,'2026-04-09 11:49:39.816406','2026-04-09 11:49:39.816406'),(520,68,'583','39','升任礼部尚书，奉敕修撰《五礼》；其提出的献书之策正式落地，朝廷规定献书一卷赐缣一匹，校写完毕后原书归还主人，民间大量珍稀典籍得以现世，隋廷最终整理得藏书三万余卷','《隋书·经籍志》：隋开皇三年，秘书监牛弘，表请分遣使人，搜访异本。每书一卷，赏绢一匹，校写既定，本即归主。于是民间异书，往往间出。','隋开皇三年',4,'2026-04-09 11:49:39.816569','2026-04-09 11:49:39.816569'),(521,68,'592','48','改任吏部尚书，主持官员选拔时坚持先考察德行、再看文才的标准，用人审慎公允，所提拔的官员大多称职，获朝野信服','《隋书·牛弘传》：弘在吏部，其选举先德行而后文才，务在审慎。虽致停缓，所有进用，并多称职。','隋开皇十二年',6,'2026-04-09 11:49:39.816732','2026-04-09 11:49:39.816732'),(522,68,'589','45','隋灭陈统一全国后，奉诏主持改定雅乐，剔除前朝靡靡之音，修撰乐府歌词、圆丘五帝凯乐，建成隋朝官方雅乐体系','《隋书·牛弘传》：九年，诏改定雅乐，又作乐府歌词，撰定圆丘五帝凯乐，并议乐事。','隋开皇九年',5,'2026-04-09 11:49:39.817135','2026-04-09 11:49:39.817135'),(523,68,'602','58','文献皇后独孤氏去世，朝中三公以下无人能拟定葬礼仪制，牛弘片刻之间便参照古制拟定完备的礼仪流程，获杨素等重臣叹服','《隋书·牛弘传》：仁寿二年，献皇后崩，三公已下不能定其仪注。杨素谓弘曰：‘公旧学，时贤所仰，今日之事，决在于公。’弘了不辞让，斯须之间，仪注悉备，皆有故实。','隋仁寿二年',7,'2026-04-09 11:49:39.817350','2026-04-09 11:49:39.817350'),(524,68,'605','61','隋炀帝即位后，牛弘进位大将军，后改授上大将军，封奇章郡公，食邑一千五百户，复任礼部尚书','《隋书·牛弘传》：大业元年，进位大将军，拜礼部尚书，改授上大将军，封奇章郡公。','隋大业元年',8,'2026-04-09 11:49:39.817577','2026-04-09 11:49:39.817577'),(525,68,'607','63','随隋炀帝拜祭恒岳，祭祀的坛场规制、珪币牲牢等礼仪全部由牛弘拟定，后获炀帝恩宠，被引入内帐与皇后同席饮宴，礼遇甚重','《隋书·牛弘传》：三年，从拜恒岳，坛场珪币，牲牢礼度，皆弘所定。还下太行，炀帝尝引入内帐，对皇后赐以同席饮食。其礼遇亲重如此。','隋大业三年',9,'2026-04-09 11:49:39.817851','2026-04-09 11:49:39.817851'),(526,68,'610','66','随隋炀帝巡幸江都，途中患病去世，炀帝为之伤惜，追赠开府仪同三司、光禄大夫、文安侯，谥号为宪','《隋书·牛弘传》：六年，从幸江都，其年十一月，卒于江都郡，时年六十六。炀帝伤惜之，赠甚厚。归葬安定，赠开府仪同三司、光禄大夫、文安侯，谥曰宪。','隋大业六年',10,'2026-04-09 11:49:39.821534','2026-04-09 11:49:39.821534'),(527,69,'531','1','出生于博陵安平官宦世家，幼有夙慧，数岁即可日诵《左氏春秋》千余言','《隋书·李德林传》：\"李德林，字公辅，博陵安平人也。年数岁，诵左氏春秋，日通千余言。\"','北魏普泰元年',0,'2026-04-09 11:52:07.187449','2026-04-09 11:52:07.187449'),(528,69,'591','61','在怀州刺史任上遭遇旱灾，组织百姓掘井灌田被考司贬责，不久病逝，朝廷追赠大将军、廉州刺史，谥号为文','《隋书·李德林传》：\"在州逢旱，课人掘井溉田，为考司所贬。岁余，卒官，时年六十一。赠大将军、廉州刺史，谥曰文。\"','隋开皇十一年',10,'2026-04-09 11:52:07.187594','2026-04-09 11:52:07.187594'),(529,69,'556','26','受北齐尚书令杨遵彦赏识，受命起草文书一挥而就，被举荐授员外散骑侍郎，掌理朝廷机密文诰','《隋书·李德林传》：\"齐尚书令杨遵彦，重德林才学，遵彦即命德林制《让尚书令表》，援笔立成，不加治点。由是除员外散骑侍郎，仍典机密。\"','北齐天保七年',2,'2026-04-09 11:52:07.187786','2026-04-09 11:52:07.187786'),(530,69,'590','60','因反对隋文帝废止乡正的政令，多次忤逆圣意，又被弹劾虚报田产等罪，被贬为湖州刺史，不久转任怀州刺史','《隋书·李德林传》：\"十年，虞庆则等奏五百家乡正专理辞讼、公行货贿，上令废之。德林复奏称政令不宜朝成暮毁，高祖发怒，大诟云：‘尔欲将我作王莽邪？’由是出为湖州刺史，在州岁余，转怀州刺史。\"','隋开皇十年',9,'2026-04-09 11:52:07.187955','2026-04-09 11:52:07.187955'),(531,69,'580','50','北周宣帝驾崩，杨坚辅政，召李德林入相府为僚属，他力主杨坚代周自立，禅代期间所有诏策文书皆出自其手','《隋书·李德林传》：\"高祖初受顾命，遣邗国公杨惠谓德林曰：‘朝廷赐令总文武事，经国重任，非群才辅佐，无以克成大业，今欲与公共事，必不得辞。’德林答云：‘若曲相提奖，必望以死奉公。’受禅之际，其相国总百揆、九锡殊礼诏策笺表玺书，皆德林之辞也。\"','北周大象二年',5,'2026-04-09 11:52:07.188151','2026-04-09 11:52:07.188151'),(532,69,'581','51','隋文帝杨坚受禅称帝，授李德林内史令，封安平郡公，与高颎等人共同修订《开皇律》，奠定隋朝法制基础','《隋书·李德林传》：\"高祖登阼之日，授内史令，封安平郡公，邑九百户。开皇元年，敕令与太尉任国公于翼、高颎等同修律令，事讫奏闻，别赐九环金带一腰，骏马一匹，赏损益之多也。\"','隋开皇元年',6,'2026-04-09 11:52:07.188284','2026-04-09 11:52:07.188284'),(533,69,'589','59','陈朝平定后，文帝本拟授李德林柱国、实封八百户，因高颎进谗称军功归于诸将，最终搁置封赏，仅加授上仪同三司','《隋书·李德林传》：\"及陈平，授柱国、郡公，实封八百户，赏物三千段。晋王广宣敕讫，有人说高颎曰：‘天子画策，晋王及诸将戮力之所致也。今乃归功于李德林，诸将必当愤惋。’颎入言之，高祖乃止，仅加上仪同，进爵为子。\"','隋开皇九年',8,'2026-04-09 11:52:07.188388','2026-04-09 11:52:07.188388'),(534,69,'546','16','父亲李敬族去世，丁忧返乡，寒冬单跣徒步扶灵归葬，以孝闻名州里，服阕后博通经史、阴阳纬候之学','《隋书·李德林传》：\"年十六，遭父艰，自驾灵舆，反葬乡里。时方严冬，单跣徒步，州里人物由是敬慕之。既终丧，博坟典，阴阳纬候，无不通涉。\"','东魏武定四年',1,'2026-04-09 11:52:07.188487','2026-04-09 11:52:07.188487'),(535,69,'587','57','隋文帝赴同州商议平陈之策，特召患病的李德林随行，命高颎亲自到其家中取平陈方略，交付晋王杨广统筹','《隋书·李德林传》：\"开皇七年，高祖幸同州，德林以疾不从。敕书追之，书后御笔注云：‘伐陈事意，宜自随也。’时高颎入京，上语颎曰：‘德林若患未堪行，宜自至宅，取其方略。’高祖以之付晋王广。\"','隋开皇七年',7,'2026-04-09 11:52:07.188583','2026-04-09 11:52:07.188583'),(536,69,'573','43','出任中书侍郎，主持文林馆事务，与颜之推等文士共同修撰《齐史》，后授仪同三司','《隋书·李德林传》：\"武平初，加通直散骑侍郎，又与中书侍郎宋士素、黄门侍郎颜之推同判文林馆事，寻除中书侍郎，仍诏修国史。\"','北齐武平四年',3,'2026-04-09 11:52:07.188679','2026-04-09 11:52:07.188679'),(537,69,'577','47','北周武帝平北齐，遣使专程征召李德林，称平齐最大的收获就是得到他，授内史上士，掌北周诏诰格式及关东人士选任事宜','《隋书·李德林传》：\"周武帝平齐，遣使就宅宣旨云：‘平齐之利，唯在于尔。’入京，授内史上士，自此以后，诏诰格式，及用山东人物，一以委之。\"','北周建德六年',4,'2026-04-09 11:52:07.193539','2026-04-09 11:52:07.193539'),(538,70,'592','51','被御史弹劾与卢恺等人结党，被隋文帝免官仅保留爵位，不久后恢复官爵参与朝政','《隋书·苏威传》：十二年，国子博士何妥奏威与礼部尚书卢恺等共为朋党，上令杂治之，事皆验。上于是免威官，以开府就第。未几，上曰：‘苏威德行者，但为人所误耳。’命之通籍。','隋开皇十二年',9,'2026-04-09 11:54:28.638480','2026-04-09 11:54:28.638480'),(539,70,'589','48','隋灭陈统一全国后，持节巡抚江南，安抚地方吏民，推行隋朝典制，稳定江南局势','《隋书·苏威传》：寻令持节巡抚江南，得以便宜从事。过会稽，逾五岭而还。','隋开皇九年',8,'2026-04-09 11:54:28.638653','2026-04-09 11:54:28.638653'),(540,70,'557','16','袭爵美阳县公，受权臣宇文护赏识，娶其女新兴公主，授车骑大将军、仪同三司，改封怀道县公','《隋书·苏威传》：周太祖时，袭爵美阳县公，仕郡功曹。大冢宰宇文护见而礼之，以其女新兴主妻焉。授使持节、车骑大将军、仪同三司，改封怀道县公。','北周孝闵帝元年',2,'2026-04-09 11:54:28.638780','2026-04-09 11:54:28.638780'),(541,70,'546','5','父亲苏绰去世，苏威守孝时哀伤举止如同成人，得时人赞许','《隋书·苏威传》：威少有至性，五岁丧父，哀毁有若成人。','西魏大统十二年',1,'2026-04-09 11:54:28.638875','2026-04-09 11:54:28.638875'),(542,70,'542','1','出生于京兆武功苏氏，为西魏度支尚书苏绰之子，自幼品行淳厚','《隋书·苏威传》：苏威，字无畏，京兆武功人也。父绰，魏度支尚书。','西魏大统八年',0,'2026-04-09 11:54:28.638968','2026-04-09 11:54:28.638968'),(543,70,'581','40','隋文帝杨坚代周建隋，征召苏威入朝，授太子少保，袭爵邳国公，不久兼任纳言、民部尚书，成为隋朝核心重臣','《隋书·苏威传》：及受禅，征拜太子少保。追赠其父为邳国公，邑三千户，以威袭焉。俄兼纳言、民部尚书。','隋开皇元年',6,'2026-04-09 11:54:28.639077','2026-04-09 11:54:28.639077'),(544,70,'北周保定年间','20','见宇文护专权恐祸及自身，避居山寺苦读典籍，屡次推辞朝廷征召','《隋书·苏威传》：威见护专权，恐祸及己，逃入山中，为叔父所逼，卒不获免。然威每屏居山寺，以讽读为娱。','北周武帝前期',3,'2026-04-09 11:54:28.639174','2026-04-09 11:54:28.639174'),(545,70,'580','39','丞相杨坚征召苏威，交谈后对其十分赏识，苏威得知杨坚有代周称帝的打算，遁归乡里回避','《隋书·苏威传》：高祖为丞相，高颎屡言其贤，高祖亦素重其名，召之。及至，引入卧内，与语大悦。居月余，威闻禅代之议，遁归田里。','北周大定元年',5,'2026-04-09 11:54:28.639261','2026-04-09 11:54:28.639261'),(546,70,'577','36','北周灭北齐后，朝廷追赠苏绰为邳国公，令苏威袭爵，苏威上表辞让未获准许','《隋书·苏威传》：武帝平齐，追赠其父为邳国公，邑三千户，以威袭焉。威表让，不许。','北周建德六年',4,'2026-04-09 11:54:28.639359','2026-04-09 11:54:28.639359'),(547,70,'583','42','牵头修订《开皇律》，确立隋代律法体系，同时奏请减轻赋役，推行轻典，获文帝准许','《隋书·苏威传》：威闻其（父苏绰）言，每以为己任。至是，奏减赋役，务从轻典，上悉从之。','隋开皇三年',7,'2026-04-09 11:54:28.639444','2026-04-09 11:54:28.639444'),(548,70,'601','60','升任尚书右仆射，与杨素共同执掌朝政，后因职事处理不力被文帝诘责','《隋书·苏威传》：仁寿初，复拜尚书右仆射。高祖幸仁寿宫，以威总留后事。及上还，御史奏威职事多不理，请推之。上怒，诘责威，威拜谢，上亦止。','隋仁寿元年',10,'2026-04-09 11:54:28.644602','2026-04-09 11:54:28.644602'),(549,70,'618','77','宇文化及发动江都之变弑杀隋炀帝，立杨浩为帝，任命苏威为光禄大夫、开府仪同三司','《隋书·苏威传》：宇文化及之弑逆也，以威为光禄大夫、开府仪同三司。','隋大业十四年',15,'2026-04-09 11:54:28.646523','2026-04-09 11:54:28.646523'),(550,70,'607','66','因高颎、贺若弼被杀事件牵连被免官，次年被起用为鲁郡太守，召回朝参与朝政','《隋书·苏威传》：高颎、贺若弼等之诛也，威坐与相连，免官。岁余，拜鲁郡太守。俄召还，参预朝政。','隋大业三年',11,'2026-04-09 11:54:28.646771','2026-04-09 11:54:28.646771'),(551,70,'隋大业年间','壮年','复任纳言，与宇文述、裴矩、裴蕴、虞世基参掌朝政，时人称为“五贵”','《隋书·苏威传》：复为纳言。与左翊卫大将军宇文述、黄门侍郎裴矩、御史大夫裴蕴、内史侍郎虞世基参掌朝政，时人称为“五贵”。','隋大业中期',12,'2026-04-09 11:54:28.646880','2026-04-09 11:54:28.646880'),(552,70,'613','72','杨玄感叛乱时，向隋炀帝进言称杨玄感粗疏不足为虑，提醒炀帝警惕各地民变苗头','《隋书·苏威传》：及杨玄感反，帝问威曰：‘此小儿聪明，得不为患乎？’威曰：‘夫识是非，审成败者，乃所谓聪明。玄感粗疏，非聪明者，必无所虑。但恐浸成乱阶耳。’','隋大业九年',13,'2026-04-09 11:54:28.646972','2026-04-09 11:54:28.646972'),(553,70,'616','75','劝谏隋炀帝返回京师、停止穷兵黩武，遭裴蕴诬陷，被削除官爵贬为庶民','《隋书·苏威传》：裴蕴希旨，令白衣张行本奏威昔在高阳典选，滥授人官，畏怯突厥，请还京师。帝令案其事。及狱成，下诏除名为民。','隋大业十二年',14,'2026-04-09 11:54:28.647058','2026-04-09 11:54:28.647058'),(554,70,'619','78','宇文化及兵败后，苏威先后归附李密、王世充，王世充称帝后署其为太师','《隋书·苏威传》：化及败，归于李密。未几密败，归东都，越王侗以为上柱国、邳公。王世充僭号，署太师。','唐武德二年',16,'2026-04-09 11:54:28.647149','2026-04-09 11:54:28.647149'),(555,70,'621','80','唐军平定王世充后，苏威请求谒见秦王李世民被斥，赴长安谒见唐高祖李渊亦未获授官职','《隋书·苏威传》：及太宗平王世充，威请谒见，称老病不能拜起。太宗遣人数之曰：‘公隋朝宰辅，政乱不能匡救，遂令品物涂炭，君弑国亡。见李密、王充，皆拜伏舞蹈。今既老病，无劳相见也。’寻归长安，至朝堂请见，又不许。','唐武德四年',17,'2026-04-09 11:54:28.647232','2026-04-09 11:54:28.647232'),(556,70,'623','82','于长安家中去世，享年八十二岁','《隋书·苏威传》：卒于家，时年八十二。','唐武德六年',18,'2026-04-09 11:54:28.647313','2026-04-09 11:54:28.647313'),(557,71,'557','27','北周代魏后，历任典祠下大夫、沔州刺史、硖州刺史，任职有惠政','《隋书·韦世康传》：后仕周，历典祠下大夫，沔、硖二州刺史。','北周孝闵帝元年',3,'2026-04-09 11:56:08.918321','2026-04-09 11:56:08.918321'),(558,71,'531','1','生于京兆韦氏关陇望族，自幼沉静敏悟，有器度','《隋书·韦世康传》：世康幼而沉敏，有器度。','北魏普泰元年',0,'2026-04-09 11:56:08.918704','2026-04-09 11:56:08.918704'),(559,71,'550','20','被宇文泰赏识任直寝，封汉安县公，娶宇文泰之女襄乐公主，授仪同三司','《隋书·韦世康传》：在魏，弱冠为直寝，封汉安县公，尚周文帝女襄乐公主，授仪同三司。','西魏大统十六年',2,'2026-04-09 11:56:08.918868','2026-04-09 11:56:08.918868'),(560,71,'580','50','杨坚辅政时授绛州刺史，素有威望，清廉自守，全境秩序安定','《隋书·韦世康传》：宣帝崩，高祖辅政，授绛州刺史，雅有威望，清节自守，合境清肃。','北周大象二年',6,'2026-04-09 11:56:08.919035','2026-04-09 11:56:08.919035'),(561,71,'577','47','跟随北周武帝平定北齐，授司州总管长史，安抚北齐旧地，士民安居乐业','《隋书·韦世康传》：从武帝平齐，授司州总管长史。于时东夏初定，百姓未安，世康绥抚之，士民胥悦。','北周建德六年',4,'2026-04-09 11:56:08.919181','2026-04-09 11:56:08.919181'),(562,71,'540','10','被州府征召为主簿，少年有才名','《隋书·韦世康传》：年十岁，州辟主簿。','西魏大统六年',1,'2026-04-09 11:56:08.919296','2026-04-09 11:56:08.919296'),(563,71,'579','49','入朝任民部中大夫，进位上开府，转任司会中大夫','《隋书·韦世康传》：岁余，入为民部中大夫，进位上开府，转司会中大夫。','北周大象元年',5,'2026-04-09 11:56:08.919398','2026-04-09 11:56:08.919398'),(564,71,'581','51','隋代北周后征召入朝任礼部尚书，进爵上庸郡公，不久转任吏部尚书，选拔官员公平允当，拒绝请托','《隋书·韦世康传》：开皇初，入为礼部尚书，进爵上庸郡公，转吏部尚书。选用平允，请托不行。','隋开皇元年',7,'2026-04-09 11:56:08.919554','2026-04-09 11:56:08.919554'),(565,71,'584','54','外任襄州刺史，后历任安州总管、信州总管，所任之处治理有方，百姓感念','《隋书·韦世康传》：开皇四年，拜襄州刺史，坐事免。后寻授安州总管，迁信州总管。','隋开皇四年',8,'2026-04-09 11:56:08.919698','2026-04-09 11:56:08.919698'),(566,71,'593','63','返回京师再次担任吏部尚书，前后掌选官事务十余年，举荐提拔大量人才，所任官员皆称职，朝廷称其廉明公平','《隋书·韦世康传》：十三年，入朝，复拜吏部尚书。前后十余年间，多所进拔，朝廷称为廉平。','隋开皇十三年',9,'2026-04-09 11:56:08.919854','2026-04-09 11:56:08.919854'),(567,71,'594','64','侍宴时向隋文帝请求辞官归隐，文帝不许，劝勉其继续为国效力','《隋书·韦世康传》：世康尝因侍宴，再拜陈让曰：‘臣无尺寸之功，位亚台铉。今犬马齿濆，不益明时，恐先朝露，无以塞责。愿乞骸骨，退避贤能。’上曰：‘朕夙夜庶几，求贤若渴，冀与公共理天下，以致太平。今之所请，深乖本望，纵令筋骨衰谢，犹屈公卧治一隅。’','隋开皇十四年',10,'2026-04-09 11:56:08.924116','2026-04-09 11:56:08.924116'),(568,71,'595','65','被隋文帝任命为荆州总管，管辖荆、襄等四州事务，镇守东南重地，待遇优厚','《隋书·韦世康传》：开皇十五年，上谓世康曰：‘东南之美，尽属于公。’于是拜荆州总管，领荆、襄等四州刺史。','隋开皇十五年',11,'2026-04-09 11:56:08.926154','2026-04-09 11:56:08.926154'),(569,71,'597','67','在荆州总管任上去世，朝廷追赠大将军、豫州刺史，谥号为「文」','《隋书·韦世康传》：开皇十七年，卒官，时年六十七。赠大将军、豫州刺史，谥曰文。','隋开皇十七年',12,'2026-04-09 11:56:08.926287','2026-04-09 11:56:08.926287'),(570,72,'北周初年','青年','入仕北周任直寝上士，多次随军出征，累积军功升任开府，获赐卫国县公爵位，食邑一千二百户','《隋书·卷四十七·列传第十二》：仕周，释褐直寝上士。数从征伐，累迁开府，赐爵卫国县公，邑千二百户。','北周早期',0,'2026-04-09 11:57:45.993277','2026-04-09 11:57:45.993277'),(571,72,'580','壮年','跟随叔父韦孝宽出兵相州讨伐叛臣尉迟迥，平叛后因军功升任柱国，晋封襄阳郡公，食邑二千户','《隋书·卷四十七·列传第十二》：高祖为丞相，从季父孝宽击尉迟迥于相州，以功拜柱国，进封襄阳郡公，邑二千户。','北周大象二年',1,'2026-04-09 11:57:45.993439','2026-04-09 11:57:45.993439'),(572,72,'581','壮年','隋文帝受禅建隋后，被任命为江陵总管，不久调任卫州刺史兼司农卿，后以行军总管身份率军击败进犯的突厥部众','《隋书·卷四十七·列传第十二》：开皇元年，拜江陵总管。寻转卫州刺史，兼司农卿。突厥尝寇边，洸以行军总管击破之。','隋开皇元年',2,'2026-04-09 11:57:45.993549','2026-04-09 11:57:45.993549'),(573,72,'589','壮年','隋灭陈之战中出任江州总管，率部平定九江等地，斩杀拒降的陈朝豫章太守徐璒，之后奉诏持节巡抚岭南，得到冼夫人率众迎接，所到之处陈朝旧部纷纷归降，岭南全境平定','《隋书·卷四十七·列传第十二》：陈平，拜江州总管，率步骑二万，略定九江。陈豫章太守徐璒据郡持两端，洸遣开府吕昂、长史冯世基以兵相继而进。既至城下，璒伪降，其夜率所部二千人袭击昂。昂与世基合击，大破之，擒璒于阵。高梁女子洗氏率众迎洸，遂进图岭南。所至皆降，岭南悉定。','隋开皇九年',3,'2026-04-09 11:57:45.993672','2026-04-09 11:57:45.993672'),(574,72,'590','壮年','出任广州总管治理岭南期间，番禺豪强王仲宣举兵叛乱围困广州，韦洸率兵出城拒战，中流矢阵亡，朝廷追赠上柱国，赐谥号为敬','《隋书·卷四十七·列传第十二》：洸所绥集二十四州，拜广州总管。岁余，番禺夷王仲宣聚众为乱，以兵围洸，洸勒兵拒之，中流矢而卒。赠上柱国，赐绵绢万段，谥曰敬。','隋开皇十年',4,'2026-04-09 11:57:45.993779','2026-04-09 11:57:45.993779'),(575,73,'538','1','生于京兆韦氏望族，为北周名士韦夐之子，年少时入国子学修习，略通经史','《隋书·卷四十七·列传第十二》：韦艺，字世文，京兆杜陵人也。父夐，隐居不仕，魏周二代，十征不出，号为逍遥公。艺少受业国子，略涉经史。','西魏大统四年',0,'2026-04-09 11:59:32.380665','2026-04-09 11:59:32.380665'),(576,73,'北周武帝年间','壮年','入仕北周，初任左侍上士，后逐步升迁至仪同三司，获赐修武县侯爵位，食邑八百户','《隋书·卷四十七·列传第十二》：周武帝时，为左侍上士。后秩上大夫，累迁仪同三司，赐爵修武县侯，邑八百户。','北周武成至建德年间',1,'2026-04-09 11:59:32.380809','2026-04-09 11:59:32.380809'),(577,73,'581','44','隋朝建立后进爵魏兴郡公，食邑二千户，不久后被任命为齐州刺史，在任期间为政清简，深受官吏百姓感念','《隋书·卷四十七·列传第十二》：开皇初，进爵魏兴郡公，食邑二千户。岁余，拜齐州刺史。为政清简，士庶怀惠。','隋开皇元年',3,'2026-04-09 11:59:32.380933','2026-04-09 11:59:32.380933'),(578,73,'580','43','时任魏郡太守，最初依附叛乱的相州总管尉迟迥，被叔父韦孝宽俘获后归顺，跟随韦孝宽平定尉迟迥叛乱，因军功进位上大将军，改封武威县公，食邑千户','《隋书·卷四十七·列传第十二》：宣帝时，授齐州刺史。及高祖为丞相，尉迥作乱，艺与迥姻亲，或言艺私怀两端。高祖令韦孝宽驰往代迥，孝宽将至邺，因诈病止传舍，从迥求药，以察其变。艺时为魏郡太守，谒孝宽。孝宽问迥所为，艺党于迥，不以实答。孝宽怒，将斩之，艺惧，乃言迥反状。及破迥，以功进位上大将军，改封武威县公，邑千户。','北周大象二年',2,'2026-04-09 11:59:32.381037','2026-04-09 11:59:32.381037'),(579,73,'隋开皇中期','壮年','调任营州总管治理北部边境，对突厥、契丹、靺鞨等少数民族采取怀柔政策，威震北境，维持了边境安定，但也因与少数民族贸易牟利，被舆论非议','《隋书·卷四十七·列传第十二》：在职数年，迁营州总管。艺容貌瑰伟，每夷狄参谒，必整仪卫，盛服以见之，独坐满一榻。番人畏惧，莫敢仰视。而大治产业，与北夷贸易，家资巨万，颇为清论所讥。','隋朝开皇年间',4,'2026-04-09 11:59:32.381132','2026-04-09 11:59:32.381132'),(580,73,'597','60','在任上去世，朝廷追赠其谥号为“怀”','《隋书·卷四十七·列传第十二》：开皇十七年，卒官，时年六十。谥曰怀。','隋开皇十七年',5,'2026-04-09 11:59:32.381214','2026-04-09 11:59:32.381214'),(581,74,'577','38','跟随北周武帝攻灭北齐，以军功进位上仪同，赐爵安固县侯，拜少御伯下大夫','《隋书·卷四十七·列传第十二》：及武帝平齐，以功进位上仪同，仍赐爵安固县侯，拜少御伯下大夫。','北周建德六年',2,'2026-04-09 12:01:34.432087','2026-04-09 12:01:34.432087'),(582,74,'540','1','生于京兆韦氏望族，为北周逍遥公韦夐幼子，自幼明敏仁厚，有理事才干','《隋书·卷四十七·列传第十二》：韦冲，字世冲，雍州万年人也。父夐，隐居不仕，魏周二代，十征不出，号为逍遥公。','西魏大统六年',0,'2026-04-09 12:01:34.432214','2026-04-09 12:01:34.432214'),(583,74,'567','28','跟随大将军元定渡江南征陈朝，战败被俘，后北周武帝遣使以黄金布帛将其赎回','《隋书·卷四十七·列传第十二》：后从大将军元定渡江伐陈，为陈人所虏，周武帝以币赎而还之。','北周天和二年',1,'2026-04-09 12:01:34.432312','2026-04-09 12:01:34.432312'),(584,74,'580','41','丞相杨坚主政时，升任汾州刺史，到任后安抚境内胡人，稳定北齐旧境局势','《隋书·卷四十七·列传第十二》：高祖为丞相，迁汾州刺史。','北周大象二年',3,'2026-04-09 12:01:34.432395','2026-04-09 12:01:34.432395'),(585,74,'581','42','隋朝建立后进爵安固县公，不久升任南石州刺史，治境安民颇有政绩','《隋书·卷四十七·列传第十二》：开皇初，进爵安固县公，俄迁南石州刺史。','隋开皇元年',4,'2026-04-09 12:01:34.432886','2026-04-09 12:01:34.432886'),(586,74,'597','58','出任南宁州总管，持节安抚西南地区，当地爨氏等少数民族酋帅纷纷归附，隋朝顺利在当地置州设县管控边疆','《隋书·卷四十七·列传第十二》：高祖以冲为南宁州总管，持节抚慰。冲既至南宁，渠帅爨震及西爨首领皆诣府参谒。上大悦，下诏褒扬之。','隋开皇十七年',5,'2026-04-09 12:01:34.433139','2026-04-09 12:01:34.433139'),(587,74,'598','59','因侄子韦伯仁劫掠少数族民女、麾下士卒放纵扰民，被御史弹劾免官，后因女为豫章王杨暕妃，系皇室姻亲，不久获赦','《隋书·卷四十七·列传第十二》：其兄子伯仁，随冲在府，掠人之妻，士卒纵暴，边人失望。上闻而大怒，令蜀王秀按其事，冲竟坐免。','隋开皇十八年',6,'2026-04-09 12:01:34.433515','2026-04-09 12:01:34.433515'),(588,74,'606','67','卒于营州总管任上，朝廷追赠谥号为\"庄\"','《隋书·卷四十七·列传第十二》：岁余，卒官，时年六十七，谥曰庄。','隋大业二年',9,'2026-04-09 12:01:34.433607','2026-04-09 12:01:34.433607'),(589,74,'605','66','隋炀帝即位后，征为散骑常侍，进位左光禄大夫，拜营州总管，安抚东北靺鞨、契丹、奚、霫等部族，诸部纷纷遣使朝贡，边境安宁','《隋书·卷四十七·列传第十二》：炀帝即位，征为散骑常侍，进位左光禄大夫，拜营州总管。冲容貌都雅，宽厚得众心。怀抚靺鞨、契丹，皆能致其死力。奚、霫畏惧，朝贡相续。','隋大业元年',8,'2026-04-09 12:01:34.434188','2026-04-09 12:01:34.434188'),(590,74,'600','61','复起为检校括州事，率兵平定东阳陶子定、吴郡罗慧方叛乱，改封义丰县侯，转检校泉州事','《隋书·卷四十七·列传第十二》：后数载，令冲检校括州事。时东阳贼帅陶子定、吴郡贼帅罗慧方并聚众为乱，围攻婺州永康、乌程诸县，冲率兵击破之。改封义丰县侯，检校泉州事。','隋开皇二十年',7,'2026-04-09 12:01:34.434458','2026-04-09 12:01:34.434458'),(591,75,'549','1','生于京兆杜陵韦氏望族，为北周郧国公韦孝宽第四子，自幼聪慧，早有美名','《隋书·卷四十七·列传第十二》：\"韦寿，字世龄，京兆杜陵人也。父孝宽，周太傅、郧国公。寿少以贵公子，早有令誉。\"','西魏大统十五年',0,'2026-04-09 12:03:12.673314','2026-04-09 12:03:12.673314'),(592,75,'580','32','杨坚任北周丞相时，因父亲韦孝宽率军平定相州尉迟迥叛乱有功，受拜开府仪同三司，进封滑国公，食邑五千户','《隋书·卷四十七·列传第十二》：\"高祖为丞相，以其父平尉迟迥，拜寿为开府仪同三司，进封滑国公，邑五千户。\"','北周大象二年',2,'2026-04-09 12:03:12.673840','2026-04-09 12:03:12.673840'),(593,75,'北周保定年间','青年','以功臣子弟身份入仕北周，起家任右侍上士，后升任仪同三司，受封永安县侯，食邑五百户','《隋书·卷四十七·列传第十二》：\"迁右侍上士，迁仪同三司，封永安县侯，邑五百户。\"','北周中期',1,'2026-04-09 12:03:12.674172','2026-04-09 12:03:12.674172'),(594,75,'581','33','隋朝建立后，先后升任恒州、毛州刺史，在任期间施政得当，素有能干之名','《隋书·卷四十七·列传第十二》：\"开皇初，迁恒、毛二州刺史，俱有能名。\"','隋开皇元年',3,'2026-04-09 12:03:12.674423','2026-04-09 12:03:12.674423'),(595,75,'590','42','在寿州总管任上去世，朝廷追赠其为雍州刺史，谥号为\"定\"','《隋书·卷四十七·列传第十二》：\"十年，卒官，时年四十二，赠雍州刺史，谥曰定。\"','隋开皇十年',5,'2026-04-09 12:03:12.674627','2026-04-09 12:03:12.674627'),(596,75,'隋开皇年间','壮年','因母亲去世丁忧去职，守制未满便被朝廷起复处理政务，不久升任寿州总管，获赐帛千匹','《隋书·卷四十七·列传第十二》：\"后以母忧去职，未几，起令视事，寻迁寿州总管，赐帛千匹。\"','隋开皇年间',4,'2026-04-09 12:03:12.674785','2026-04-09 12:03:12.674785'),(597,76,'556','19','因仪表出众、涉猎经史有才名，被北周太祖宇文泰征召为记室参军，正式入仕','《隋书·卷四十七·列传第十二》：机伟仪容，有器局，颇涉经史。年十九，周太祖引为记室。','西魏恭帝三年',1,'2026-04-09 12:04:56.326763','2026-04-09 12:04:56.326763'),(598,76,'538','1','出生于河东解县柳氏望族，父亲柳庆为西魏尚书左仆射，家世显赫','《隋书·卷四十七·列传第十二》：柳机，字匡时，河东解人也。父庆，魏尚书左仆射。','西魏大统四年',0,'2026-04-09 12:04:56.327020','2026-04-09 12:04:56.327020'),(599,76,'北周保定年间','青年','历任少纳言、少府中大夫等职，爵位由平齐县男累升至伯爵','《隋书·卷四十七·列传第十二》：累迁少纳言，封平齐县男，转少府中大夫，进爵为伯。','北周初期',2,'2026-04-09 12:04:56.327257','2026-04-09 12:04:56.327257'),(600,76,'隋开皇年间','壮年','升任纳言居宰相之职，生性宽厚不务细务，后外任华州、冀州刺史，治政宽简，受吏民爱戴','《隋书·卷四十七·列传第十二》：俄迁纳言，机性宽简，有雅望，然当近侍，无所损益，又好饮酒，不亲细务。居职数年，复出为华州刺史，奉诏宽简，吏民悦之。寻迁冀州刺史，甚有惠政。','隋初',5,'2026-04-09 12:04:56.327409','2026-04-09 12:04:56.327409'),(601,76,'581','44','隋文帝杨坚受禅建隋，柳机被征召入朝任卫尉卿，进爵建安郡公，食邑二千四百户','《隋书·卷四十七·列传第十二》：高祖受禅，征为卫尉卿，进爵建安郡公，邑二千四百户。','隋开皇元年',4,'2026-04-09 12:04:56.327558','2026-04-09 12:04:56.327558'),(602,76,'578','41','北周宣帝宇文赟即位，念及柳机旧恩将其召回京师，因多次劝谏宣帝失德被疏远，外任华州刺史','《隋书·卷四十七·列传第十二》：及宣帝嗣位，以机有旧恩，征还京师。时帝失德，机屡陈谏，帝不纳。由是疏忌，出为华州刺史。','北周宣政元年',3,'2026-04-09 12:04:56.327694','2026-04-09 12:04:56.327694'),(603,76,'593','56','其子柳述迎娶隋文帝爱女兰陵公主，柳氏一族恩遇更隆','《隋书·卷四十七·列传第十二》：后其子述尚兰陵公主，由是恩遇益隆。','隋开皇十三年',6,'2026-04-09 12:04:56.328206','2026-04-09 12:04:56.328206'),(604,76,'594','57','在冀州刺史任上病逝，朝廷追赠大将军、青州刺史，谥号为简','《隋书·卷四十七·列传第十二》：开皇十四年卒官，时年五十六，赠大将军、青州刺史，谥曰简。','隋开皇十四年',7,'2026-04-09 12:04:56.328336','2026-04-09 12:04:56.328336'),(605,77,'581年','15','凭借父荫入仕，担任太子杨勇的亲卫，正式步入仕途','《隋书·卷四十七·列传第十二》：少以父荫，为太子亲卫。','隋开皇元年',1,'2026-04-09 12:06:30.696601','2026-04-09 12:06:30.696601'),(606,77,'约567年','1','出身河东柳氏望族，为北周华州刺史柳机之子，自幼明敏有干略，略通文艺','《隋书·卷四十七·列传第十二》：柳述，字业隆，性明敏，有干略，颇涉文艺。','北周天和二年',0,'2026-04-09 12:06:30.697601','2026-04-09 12:06:30.697601'),(607,77,'596年','30','迎娶隋文帝第五女兰陵公主杨阿五，以帝婿身份获文帝亲近信任，进位开府仪同三司，历任内史侍郎、兵部尚书，任职颇有称职之名','《隋书·卷四十七·列传第十二》：后尚高祖女兰陵公主，由是渐见亲待，历兵部、尚书二曹，颇称职。','隋开皇十六年',2,'2026-04-09 12:06:30.697813','2026-04-09 12:06:30.697813'),(608,77,'601年','35','接替权臣杨素担任吏部尚书，参掌朝廷中枢机密，因性格刚直骄豪，多次当众折辱杨素，同时得罪太子杨广，为二人所忌恨','《隋书·卷四十七·列传第十二》：仁寿中，判吏部尚书事，虽无学业，而为吏所称。然怙宠骄豪，无所降屈，杨素时方贵重，朝臣莫不詟惮，述每陵侮之，数于上前面折素短。','隋仁寿元年',3,'2026-04-09 12:06:30.697976','2026-04-09 12:06:30.697976'),(609,77,'604年','38','隋文帝病重于仁寿宫，柳述与杨素、元岩等入宫侍疾，文帝得知太子杨广无礼于宣华夫人后大怒，命柳述拟敕召回废太子杨勇，事泄后被杨广矫诏逮捕下狱','《隋书·卷四十七·列传第十二》：及上寝疾于仁寿宫也，述与杨素、元岩等侍疾宫中。时皇太子无礼于陈贵人，上知而大怒，因令述召房陵王。述与元岩出外作敕书，杨素闻之，与皇太子协谋，便矫诏执述、岩，持以属吏。','隋仁寿四年',4,'2026-04-09 12:06:30.698401','2026-04-09 12:06:30.698401'),(610,77,'605年','39','隋炀帝杨广即位后，柳述被除名免官，与兰陵公主被迫离异，流放龙川郡，后又被改流宁越，途中感染瘴疠病逝，时年三十九岁','《隋书·卷四十七·列传第十二》：炀帝即位，述竟坐除名，与公主离绝，徙于龙川郡。公主请与述同徙，帝不听，事在《列女传》。述在龙川数年，复徙宁越，遇瘴疠而死，时年三十九。','隋大业元年',5,'2026-04-09 12:06:30.698558','2026-04-09 12:06:30.698558'),(611,78,'548','1','出生于河东柳氏名门，为北周名臣柳庆幼子，自幼学习骑射，涉猎经史典籍','《隋书·卷四十七·列传第十二》：\"机弟旦，字匡德，工骑射，颇涉书籍。\"','西魏大统十四年',0,'2026-04-09 12:07:53.021600','2026-04-09 12:07:53.021600'),(612,78,'北周建德年间','青年','出仕北周，起家任左侍上士，因履职得当逐步升迁至兵部下大夫','《隋书·卷四十七·列传第十二》：\"仕周，起家左侍上士，累迁兵部下大夫。\"','北周中期',1,'2026-04-09 12:07:53.021784','2026-04-09 12:07:53.021784'),(613,78,'581','34','隋文帝杨坚受禅代周建立隋朝，柳旦加授开府仪同三司，受封新城县男，食邑四百户，后升任掌设骠骑','《隋书·卷四十七·列传第十二》：\"高祖受禅，加开府，封新城县男，迁授掌设骠骑。\"','隋开皇元年',2,'2026-04-09 12:07:53.021908','2026-04-09 12:07:53.021908'),(614,78,'隋开皇年间','壮年','先后出任罗州、淅州、鲁州三州刺史，在任期间施政得当，皆有贤能的名声','《隋书·卷四十七·列传第十二》：\"历罗、淅、鲁三州刺史，并有能名。\"','隋开皇年间',3,'2026-04-09 12:07:53.022019','2026-04-09 12:07:53.022019'),(615,78,'605','58','隋炀帝即位后，柳旦被任命为龙川太守，当地民众多居山洞，民风剽悍好斗殴，柳旦到任后开设学校推行教化，大幅改善当地风俗，得到隋炀帝下诏褒奖','《隋书·卷四十七·列传第十二》：\"大业初，拜龙川太守。民居山洞，好相攻击，旦为开设学校，大变其风。帝闻而善之，下诏褒美。\"','隋大业元年',4,'2026-04-09 12:07:53.022127','2026-04-09 12:07:53.022127'),(616,78,'608','61','被朝廷征召入朝担任太常少卿，兼管黄门侍郎事务，不久后在任上去世，谥号为敬','《隋书·卷四十七·列传第十二》：\"四年，征为太常少卿，摄判黄门侍郎事。卒官，时年六十一。谥曰敬。\"','隋大业四年',5,'2026-04-09 12:07:53.022264','2026-04-09 12:07:53.022264'),(617,79,'554','1','生于河东柳氏官宦世家，自幼聪敏，熟习应对之道','《隋书